fn cached_dashboard_assistant_scope_sources(
    repo_root: &Path,
    target_context_pack_ids: &BTreeSet<String>,
    working_state_summary: &[postgres::ObservabilitySnapshotKindSummary],
    direct_turn_summary: &[postgres::ObservabilitySnapshotKindSummary],
    token_budget_summary: &[postgres::ObservabilitySnapshotKindSummary],
) -> Result<
    Option<(
        Vec<AssistantGenerationTurnObservedSnapshot>,
        BTreeMap<String, WorkingStateContextPackMeta>,
        BTreeMap<String, BTreeSet<String>>,
        BTreeMap<String, Vec<codex_threads::RolloutAssistantGenerationTurnObservation>>,
    )>,
> {
    let cache = DASHBOARD_ASSISTANT_SCOPE_SOURCE_CACHE.get_or_init(|| Mutex::new(None));
    let mut guard = cache
        .lock()
        .map_err(|_| anyhow!("dashboard assistant scope source cache poisoned"))?;
    let repo_root = canonical_repo_root(repo_root);
    let candidate = guard
        .as_ref()
        .filter(|entry| repo_root == entry.repo_root)
        .cloned()
        .or_else(|| load_shared_dashboard_assistant_scope_sources(&repo_root));
    let Some(entry) = candidate else {
        return Ok(None);
    };
    if target_context_pack_ids != &entry.target_context_pack_ids {
        return Ok(None);
    }
    let thread_ids = entry
        .metadata
        .values()
        .map(|item| item.thread_id.clone())
        .collect::<BTreeSet<_>>();
    let thread_signatures = dashboard_assistant_scope_thread_signatures(&thread_ids)?;
    let signature = dashboard_assistant_scope_source_signature(
        target_context_pack_ids,
        working_state_summary,
        direct_turn_summary,
        token_budget_summary,
        &thread_signatures,
    );
    if entry.signature != signature {
        return Ok(None);
    }
    *guard = Some(entry.clone());
    Ok(Some((
        entry.direct_turns,
        entry.metadata,
        entry.helper_only_context_pack_ids_by_thread,
        entry.turns_by_thread,
    )))
}

fn store_dashboard_assistant_scope_sources(
    repo_root: &Path,
    signature: &str,
    target_context_pack_ids: &BTreeSet<String>,
    direct_turns: &[AssistantGenerationTurnObservedSnapshot],
    metadata: &BTreeMap<String, WorkingStateContextPackMeta>,
    helper_only_context_pack_ids_by_thread: &BTreeMap<String, BTreeSet<String>>,
    turns_by_thread: &BTreeMap<
        String,
        Vec<codex_threads::RolloutAssistantGenerationTurnObservation>,
    >,
) {
    let cache = DASHBOARD_ASSISTANT_SCOPE_SOURCE_CACHE.get_or_init(|| Mutex::new(None));
    let Some(mut guard) = cache.lock().ok() else {
        return;
    };
    let entry = DashboardAssistantScopeSourceCache {
        repo_root: canonical_repo_root(repo_root),
        signature: signature.to_string(),
        target_context_pack_ids: target_context_pack_ids.clone(),
        direct_turns: direct_turns.to_vec(),
        metadata: metadata.clone(),
        helper_only_context_pack_ids_by_thread: helper_only_context_pack_ids_by_thread.clone(),
        turns_by_thread: turns_by_thread.clone(),
    };
    let _ = write_shared_dashboard_assistant_scope_sources(repo_root, &entry);
    *guard = Some(entry);
}

fn cached_dashboard_assistant_generation_scopes(
    repo_root: &Path,
    signature: &str,
) -> Option<Vec<AssistantGenerationScopeObservation>> {
    let cache = DASHBOARD_ASSISTANT_SCOPE_CACHE.get_or_init(|| Mutex::new(None));
    let mut guard = cache.lock().ok()?;
    let repo_root = canonical_repo_root(repo_root);
    let entry = guard
        .as_ref()
        .filter(|entry| repo_root == entry.repo_root)
        .cloned()
        .or_else(|| load_shared_dashboard_assistant_generation_scopes(&repo_root))?;
    if entry.signature != signature {
        return None;
    }
    *guard = Some(entry.clone());
    Some(entry.scopes)
}

fn store_dashboard_assistant_generation_scopes(
    repo_root: &Path,
    signature: &str,
    scopes: &[AssistantGenerationScopeObservation],
) {
    let cache = DASHBOARD_ASSISTANT_SCOPE_CACHE.get_or_init(|| Mutex::new(None));
    let Some(mut guard) = cache.lock().ok() else {
        return;
    };
    let entry = DashboardAssistantScopeCache {
        repo_root: canonical_repo_root(repo_root),
        signature: signature.to_string(),
        scopes: scopes.to_vec(),
    };
    let _ = write_shared_dashboard_assistant_generation_scopes(repo_root, &entry);
    *guard = Some(entry);
}

fn dashboard_report_signature_components(
    current_session_events: &[TokenBudgetEvent],
    rolling_window_events: &[TokenBudgetEvent],
    lifetime_events: &[TokenBudgetEvent],
    current_session_assistant_scope: &AssistantGenerationScopeObservation,
    rolling_window_assistant_scope: Option<&AssistantGenerationScopeObservation>,
    lifetime_assistant_scope: &AssistantGenerationScopeObservation,
    client_live_meter_observation: Option<&codex_threads::RolloutClientMeterObservation>,
    client_live_meter_binding_hint: Option<&str>,
    exact_client_limits_observation: Option<&CodexAppServerRateLimitsObservation>,
    client_budget_target_percent: u64,
) -> DashboardReportSignatureComponents {
    DashboardReportSignatureComponents {
        current_session_events: dashboard_report_events_signature(current_session_events),
        rolling_window_events: dashboard_report_events_signature(rolling_window_events),
        lifetime_events: dashboard_report_events_signature(lifetime_events),
        current_session_assistant_scope: dashboard_report_assistant_scope_signature(
            current_session_assistant_scope,
        ),
        rolling_window_assistant_scope: rolling_window_assistant_scope
            .map(dashboard_report_assistant_scope_signature)
            .unwrap_or_else(|| hex_sha256(b"dashboard_rolling_window_scope:null")),
        lifetime_assistant_scope: dashboard_report_assistant_scope_signature(
            lifetime_assistant_scope,
        ),
        client_live_meter: dashboard_client_live_meter_signature(
            client_live_meter_observation,
            client_live_meter_binding_hint,
        ),
        exact_client_limits: dashboard_exact_client_limits_signature(
            exact_client_limits_observation,
        ),
        client_budget_target_percent,
    }
}

fn dashboard_report_signature(components: &DashboardReportSignatureComponents) -> String {
    let payload = json!({
        "current_session_events": components.current_session_events,
        "rolling_window_events": components.rolling_window_events,
        "lifetime_events": components.lifetime_events,
        "current_session_assistant_scope": components.current_session_assistant_scope,
        "rolling_window_assistant_scope": components.rolling_window_assistant_scope,
        "lifetime_assistant_scope": components.lifetime_assistant_scope,
        "client_live_meter": components.client_live_meter,
        "exact_client_limits": components.exact_client_limits,
        "client_budget_target_percent": components.client_budget_target_percent,
    });
    hex_sha256(&serde_json::to_vec(&payload).unwrap_or_else(|_| payload.to_string().into_bytes()))
}

fn refresh_dashboard_report_live_ages(
    mut report: Value,
    now_epoch_ms: i64,
    current_session_events: &[TokenBudgetEvent],
    rolling_window_events: &[TokenBudgetEvent],
    lifetime_events: &[TokenBudgetEvent],
    pre_cache_timings: &DashboardReportPreCacheTimings,
    assistant_scope_debug: &DashboardAssistantScopeDebug,
) -> Value {
    if let Some(node) = report["token_budget_report"]["cache_debug"].as_object_mut() {
        node.insert("status".to_string(), Value::from("hit"));
        node.insert(
            "pre_cache_total_ms".to_string(),
            Value::from(pre_cache_timings.total_ms),
        );
        node.insert(
            "pre_cache_stage_ms".to_string(),
            dashboard_precache_stage_ms_value(pre_cache_timings),
        );
        node.insert(
            "assistant_scope_debug".to_string(),
            dashboard_assistant_scope_debug_value(assistant_scope_debug),
        );
    }
    refresh_dashboard_report_scope_age(
        &mut report,
        "current_session",
        now_epoch_ms,
        current_session_events,
    );
    refresh_dashboard_report_scope_age(
        &mut report,
        "rolling_window",
        now_epoch_ms,
        rolling_window_events,
    );
    refresh_dashboard_report_scope_age(&mut report, "lifetime", now_epoch_ms, lifetime_events);
    report
}

fn refresh_dashboard_report_scope_age(
    report: &mut Value,
    scope_key: &str,
    now_epoch_ms: i64,
    events: &[TokenBudgetEvent],
) {
    let Some(scope) = report["token_budget_report"][scope_key].as_object_mut() else {
        return;
    };
    if events.is_empty() {
        scope.insert("age_ms_since_latest".to_string(), Value::Null);
        return;
    }
    let latest_epoch_ms = events
        .last()
        .map(|event| event.created_at_epoch_ms)
        .unwrap_or_default();
    scope.insert(
        "age_ms_since_latest".to_string(),
        Value::from(now_epoch_ms.saturating_sub(latest_epoch_ms)),
    );
}

fn dashboard_report_events_signature(events: &[TokenBudgetEvent]) -> String {
    let mut buffer = String::new();
    for event in events {
        let parts = [
            event.created_at_epoch_ms.to_string(),
            event.event_id.clone(),
            event.correlation_id.clone(),
            event.session_id.clone(),
            event.source_kind.clone(),
            event.traffic_class.clone(),
            event.measurement_scope.clone(),
            event.query.clone(),
            event.query_type.clone(),
            event.target_kind.clone(),
            event.tokenizer.clone(),
            event.latency_ms.to_string(),
            event.saved_tokens.to_string(),
            event.naive_tokens.to_string(),
            event.context_tokens.to_string(),
            event.recovery_tokens.to_string(),
            event.effective_saved_tokens.to_string(),
            event.quality_ok.to_string(),
            event.quality_method.clone(),
            event.quality_tier.clone(),
            event.head_hit_target.to_string(),
            event.needed_followup.to_string(),
            event.resolved_by_event_id.clone().unwrap_or_default(),
            event.fallback_triggered.to_string(),
            event.document_hits.to_string(),
            event.symbol_hits_count.to_string(),
            event.file_hits.to_string(),
            event.sources_count.to_string(),
            event.chunks_count.to_string(),
            event
                .client_prompt_tokens
                .map(|value| value.to_string())
                .unwrap_or_default(),
            event
                .assistant_generation_tokens
                .map(|value| value.to_string())
                .unwrap_or_default(),
            event
                .tool_overhead_tokens
                .map(|value| value.to_string())
                .unwrap_or_default(),
            event
                .continuity_restore_tokens
                .map(|value| value.to_string())
                .unwrap_or_default(),
        ];
        buffer.push_str(&parts.join("\\u{1f}"));
        buffer.push('\u{1e}');
    }
    hex_sha256(buffer.as_bytes())
}

fn dashboard_report_assistant_scope_signature(
    scope: &AssistantGenerationScopeObservation,
) -> String {
    let mut buffer = String::new();
    let header = [
        scope.target_group_count.to_string(),
        scope.observed_group_count.to_string(),
        scope.observed_tokens.to_string(),
        scope.available_turns.to_string(),
        scope.available_direct_turns.to_string(),
        scope.available_rollout_turns.to_string(),
        scope.helper_only_context_pack_ids.len().to_string(),
        scope
            .helper_only_non_model_visible_context_pack_ids
            .len()
            .to_string(),
        scope.target_context_pack_ids.len().to_string(),
    ];
    buffer.push_str(&header.join("\\u{1f}"));
    buffer.push('\u{1f}');
    append_sorted_signature_items(&mut buffer, &scope.target_context_pack_ids);
    append_sorted_signature_items(&mut buffer, &scope.helper_only_context_pack_ids);
    append_sorted_signature_items(
        &mut buffer,
        &scope.helper_only_non_model_visible_context_pack_ids,
    );
    append_sorted_signature_items(&mut buffer, &scope.matched_context_pack_ids);
    append_sorted_signature_items(&mut buffer, &scope.unmatched_context_pack_ids);
    append_sorted_signature_items(&mut buffer, &scope.matched_turn_ids);
    append_sorted_signature_items(&mut buffer, &scope.matched_direct_turn_ids);
    append_sorted_signature_items(&mut buffer, &scope.matched_rollout_turn_ids);
    hex_sha256(buffer.as_bytes())
}

fn append_sorted_signature_items(buffer: &mut String, values: &BTreeSet<String>) {
    for value in values {
        let _ = write!(buffer, "{}\u{1f}", value);
    }
    buffer.push('\u{1e}');
}

fn dashboard_report_cache_debug(
    previous_entry: Option<&DashboardReportCache>,
    report_signature: &str,
    components: &DashboardReportSignatureComponents,
    pre_cache_timings: &DashboardReportPreCacheTimings,
    assistant_scope_debug: &DashboardAssistantScopeDebug,
) -> Value {
    let mut reasons = Vec::new();
    let mut previous_signature = Value::Null;
    if let Some(previous) = previous_entry {
        previous_signature = Value::from(previous.signature.clone());
        if previous.components.current_session_events != components.current_session_events {
            reasons.push("current_session_events");
        }
        if previous.components.rolling_window_events != components.rolling_window_events {
            reasons.push("rolling_window_events");
        }
        if previous.components.lifetime_events != components.lifetime_events {
            reasons.push("lifetime_events");
        }
        if previous.components.current_session_assistant_scope
            != components.current_session_assistant_scope
        {
            reasons.push("current_session_assistant_scope");
        }
        if previous.components.rolling_window_assistant_scope
            != components.rolling_window_assistant_scope
        {
            reasons.push("rolling_window_assistant_scope");
        }
        if previous.components.lifetime_assistant_scope != components.lifetime_assistant_scope {
            reasons.push("lifetime_assistant_scope");
        }
        if previous.components.client_live_meter != components.client_live_meter {
            reasons.push("client_live_meter");
        }
        if previous.components.exact_client_limits != components.exact_client_limits {
            reasons.push("exact_client_limits");
        }
    } else {
        reasons.push("cold_start");
    }
    json!({
        "status": "miss",
        "signature": report_signature,
        "previous_signature": previous_signature,
        "changed_components": reasons,
        "pre_cache_total_ms": pre_cache_timings.total_ms,
        "pre_cache_stage_ms": dashboard_precache_stage_ms_value(pre_cache_timings),
        "assistant_scope_debug": dashboard_assistant_scope_debug_value(assistant_scope_debug),
    })
}

fn record_dashboard_precache_stage_ms(
    timings: &mut DashboardReportPreCacheTimings,
    stage_key: &str,
    started_at: Instant,
) {
    record_dashboard_stage_ms(&mut timings.stage_ms, stage_key, started_at);
}

fn dashboard_precache_stage_ms_value(timings: &DashboardReportPreCacheTimings) -> Value {
    Value::Object(
        timings
            .stage_ms
            .iter()
            .map(|(stage_key, elapsed_ms)| (stage_key.clone(), Value::from(*elapsed_ms)))
            .collect(),
    )
}

fn record_dashboard_stage_ms(
    stage_ms: &mut BTreeMap<String, u64>,
    stage_key: &str,
    started_at: Instant,
) {
    stage_ms.insert(
        stage_key.to_string(),
        started_at.elapsed().as_millis() as u64,
    );
}

fn dashboard_assistant_scope_debug_value(debug: &DashboardAssistantScopeDebug) -> Value {
    json!({
        "source_cache_status": debug.source_cache_status,
        "source_stage_ms": debug.source_stage_ms,
        "source_total_ms": debug.source_total_ms,
        "scope_cache_status": debug.scope_cache_status,
        "scope_stage_ms": debug.scope_stage_ms,
        "scope_total_ms": debug.scope_total_ms,
    })
}

fn cached_dashboard_report_entry(repo_root: &Path) -> Option<DashboardReportCache> {
    let cache = DASHBOARD_REPORT_CACHE.get_or_init(|| Mutex::new(None));
    let guard = cache.lock().ok()?;
    let entry = guard.as_ref()?;
    if canonical_repo_root(repo_root) == entry.repo_root {
        Some(entry.clone())
    } else {
        None
    }
}

fn store_dashboard_report(
    repo_root: &Path,
    signature: &str,
    components: &DashboardReportSignatureComponents,
    report: &Value,
) {
    let cache = DASHBOARD_REPORT_CACHE.get_or_init(|| Mutex::new(None));
    let Some(mut guard) = cache.lock().ok() else {
        return;
    };
    *guard = Some(DashboardReportCache {
        repo_root: canonical_repo_root(repo_root),
        signature: signature.to_string(),
        components: components.clone(),
        report: report.clone(),
    });
}

fn canonical_repo_root(path: &Path) -> PathBuf {
    path.canonicalize().unwrap_or_else(|_| path.to_path_buf())
}

fn derive_rollout_assistant_generation_scope_from_sources(
    target_context_pack_ids: &BTreeSet<String>,
    direct_turns: &[AssistantGenerationTurnObservedSnapshot],
    metadata: &BTreeMap<String, WorkingStateContextPackMeta>,
    turns_by_thread: &BTreeMap<
        String,
        Vec<codex_threads::RolloutAssistantGenerationTurnObservation>,
    >,
    helper_only_context_pack_ids: &BTreeSet<String>,
    helper_only_non_model_visible_context_pack_ids: &BTreeSet<String>,
) -> AssistantGenerationScopeObservation {
    let target_context_pack_ids = target_context_pack_ids
        .difference(helper_only_context_pack_ids)
        .cloned()
        .collect::<BTreeSet<_>>();
    let metadata_lineage_context_pack_ids = target_context_pack_ids
        .iter()
        .filter(|context_pack_id| {
            metadata
                .get(*context_pack_id)
                .map(|meta| meta.captured_at_epoch_ms > 0 || !meta.turn_id.trim().is_empty())
                .unwrap_or(false)
        })
        .cloned()
        .collect::<BTreeSet<_>>();
    let direct_turn_lineage_context_pack_ids = direct_turns
        .iter()
        .flat_map(|turn| turn.context_pack_ids.iter())
        .filter(|context_pack_id| target_context_pack_ids.contains(*context_pack_id))
        .cloned()
        .collect::<BTreeSet<_>>();
    let target_context_pack_ids = target_context_pack_ids
        .into_iter()
        .filter(|context_pack_id| {
            metadata_lineage_context_pack_ids.contains(context_pack_id)
                || direct_turn_lineage_context_pack_ids.contains(context_pack_id)
        })
        .collect::<BTreeSet<_>>();
    if target_context_pack_ids.is_empty() {
        return AssistantGenerationScopeObservation {
            helper_only_context_pack_ids: helper_only_context_pack_ids.clone(),
            helper_only_non_model_visible_context_pack_ids:
                helper_only_non_model_visible_context_pack_ids.clone(),
            ..AssistantGenerationScopeObservation::default()
        };
    }

    let mut matched_context_pack_ids = BTreeSet::new();
    let mut matched_turn_ids = BTreeSet::new();
    let mut matched_direct_turn_ids = BTreeSet::new();
    let mut matched_rollout_turn_ids = BTreeSet::new();
    let mut observed_tokens = 0_u64;
    let mut observed_group_count = 0_u64;
    let mut target_group_keys = BTreeSet::new();
    let mut grouped_context_pack_ids = BTreeMap::<(String, String), BTreeSet<String>>::new();
    let mut direct_turns_by_key =
        BTreeMap::<String, AssistantGenerationTurnObservedSnapshot>::new();

    for turn in direct_turns {
        let matched_ids = turn
            .context_pack_ids
            .intersection(&target_context_pack_ids)
            .cloned()
            .collect::<BTreeSet<_>>();
        if matched_ids.is_empty() {
            continue;
        }
        let turn_key = format!("{}:{}", turn.thread_id, turn.turn_id);
        target_group_keys.insert(turn_key.clone());
        matched_turn_ids.insert(turn_key.clone());
        matched_direct_turn_ids.insert(turn_key.clone());
        direct_turns_by_key.insert(turn_key, turn.clone());
        matched_context_pack_ids.extend(matched_ids);
        observed_group_count = observed_group_count.saturating_add(1);
        observed_tokens = observed_tokens.saturating_add(turn.assistant_generation_tokens);
    }

    let mut by_thread = BTreeMap::<String, Vec<(String, WorkingStateContextPackMeta)>>::new();
    for context_pack_id in &target_context_pack_ids {
        if matched_context_pack_ids.contains(context_pack_id) {
            continue;
        }
        if let Some(meta) = metadata.get(context_pack_id.as_str()) {
            by_thread
                .entry(meta.thread_id.clone())
                .or_default()
                .push((context_pack_id.clone(), meta.clone()));
        }
    }

    for (thread_id, entries) in by_thread {
        let Some(turns) = turns_by_thread.get(&thread_id) else {
            continue;
        };
        if turns.is_empty() {
            continue;
        }
        for (context_pack_id, meta) in entries {
            let matched_turn = turns
                .iter()
                .find(|turn| !meta.turn_id.is_empty() && turn.turn_id == meta.turn_id)
                .or_else(|| {
                    (meta.captured_at_epoch_ms > 0).then(|| {
                        turns.iter().find(|turn| {
                            turn.started_at_epoch_ms
                                .saturating_sub(ASSISTANT_GENERATION_TURN_MATCH_GRACE_MS)
                                <= meta.captured_at_epoch_ms
                                && meta.captured_at_epoch_ms
                                    <= turn
                                        .ended_at_epoch_ms
                                        .saturating_add(ASSISTANT_GENERATION_TURN_MATCH_GRACE_MS)
                        })
                    })?
                });
            let Some(turn) = matched_turn else {
                continue;
            };
            let turn_key = format!("{thread_id}:{}", turn.turn_id);
            if direct_turns_by_key.contains_key(&turn_key) {
                matched_context_pack_ids.insert(context_pack_id);
                continue;
            }
            grouped_context_pack_ids
                .entry((thread_id.clone(), turn.turn_id.clone()))
                .or_default()
                .insert(context_pack_id);
        }
    }

    let available_turns: u64 = turns_by_thread
        .values()
        .map(|turns| turns.len() as u64)
        .sum();

    for ((thread_id, turn_id), context_pack_ids) in &grouped_context_pack_ids {
        let Some(turns) = turns_by_thread.get(thread_id) else {
            continue;
        };
        let Some(turn) = turns.iter().find(|candidate| candidate.turn_id == *turn_id) else {
            continue;
        };
        if context_pack_ids.is_empty() {
            continue;
        }
        let turn_key = format!("{thread_id}:{turn_id}");
        target_group_keys.insert(turn_key.clone());
        matched_turn_ids.insert(turn_key.clone());
        matched_rollout_turn_ids.insert(turn_key);
        matched_context_pack_ids.extend(context_pack_ids.iter().cloned());
        observed_group_count = observed_group_count.saturating_add(1);
        observed_tokens = observed_tokens.saturating_add(turn.assistant_generation_tokens);
    }

    let unmatched_context_pack_ids = target_context_pack_ids
        .difference(&matched_context_pack_ids)
        .cloned()
        .collect::<BTreeSet<_>>();
    for context_pack_id in &unmatched_context_pack_ids {
        target_group_keys.insert(format!("context_pack:{context_pack_id}"));
    }

    AssistantGenerationScopeObservation {
        target_group_count: target_group_keys.len() as u64,
        observed_group_count,
        observed_tokens,
        helper_only_context_pack_ids: helper_only_context_pack_ids.clone(),
        helper_only_non_model_visible_context_pack_ids:
            helper_only_non_model_visible_context_pack_ids.clone(),
        target_context_pack_ids,
        matched_context_pack_ids,
        unmatched_context_pack_ids,
        matched_turn_ids,
        available_turns: available_turns.saturating_add(direct_turns.len() as u64),
        available_direct_turns: direct_turns.len() as u64,
        available_rollout_turns: available_turns,
        matched_direct_turn_ids,
        matched_rollout_turn_ids,
    }
}

fn helper_only_context_pack_ids_for_scope(
    metadata: &BTreeMap<String, WorkingStateContextPackMeta>,
    helper_only_context_pack_ids_by_thread: &BTreeMap<String, BTreeSet<String>>,
) -> BTreeSet<String> {
    metadata
        .iter()
        .filter_map(|(context_pack_id, meta)| {
            let helper_ids = helper_only_context_pack_ids_by_thread.get(meta.thread_id.as_str())?;
            helper_ids
                .contains(context_pack_id)
                .then(|| context_pack_id.clone())
        })
        .collect()
}

fn event_has_model_visible_with_amai_tokens(event: &TokenBudgetEvent) -> bool {
    event.context_tokens > 0
        || event.recovery_tokens > 0
        || event.client_prompt_tokens.unwrap_or(0) > 0
        || event.assistant_generation_tokens.unwrap_or(0) > 0
        || event.tool_overhead_tokens.unwrap_or(0) > 0
        || event.continuity_restore_tokens.unwrap_or(0) > 0
}

fn is_legacy_continuity_bootstrap_context_pack(event: &TokenBudgetEvent) -> bool {
    event.namespace == "continuity"
        && event.source_kind == "live_context_pack"
        && event.query_type == "code_lookup"
        && event.target_kind == "file"
        && event.query == CONTINUITY_SNAPSHOT_QUERY_LABEL
}

fn helper_only_non_model_visible_context_pack_ids(
    events: &[TokenBudgetEvent],
    metadata: &BTreeMap<String, WorkingStateContextPackMeta>,
    helper_only_context_pack_ids_by_thread: &BTreeMap<String, BTreeSet<String>>,
) -> BTreeSet<String> {
    events
        .iter()
        .filter_map(|event| {
            let context_pack_id = event_context_pack_id(event)?;
            let thread_id = metadata.get(context_pack_id.as_str())?.thread_id.as_str();
            let helper_ids = helper_only_context_pack_ids_by_thread.get(thread_id)?;
            if helper_ids.contains(&context_pack_id)
                && !event_has_model_visible_with_amai_tokens(event)
            {
                Some(context_pack_id)
            } else {
                None
            }
        })
        .collect()
}

fn current_live_turn_assistant_scope_from_client_meter(
    events: &[TokenBudgetEvent],
    matched_context_pack_ids: &BTreeSet<String>,
    observation: &codex_threads::RolloutClientMeterObservation,
) -> Option<AssistantGenerationScopeObservation> {
    let target_context_pack_ids = assistant_generation_missing_scope_context_pack_ids(Some(events))
        .into_iter()
        .filter(|context_pack_id| matched_context_pack_ids.contains(context_pack_id))
        .collect::<BTreeSet<_>>();
    if target_context_pack_ids.is_empty() {
        return None;
    }

    let thread_id = observation.thread_id.trim();
    let turn_id = observation.turn_id.trim();
    let turn_key = if !thread_id.is_empty()
        && !turn_id.is_empty()
        && observation.started_at_epoch_ms > 0
        && observation.ended_at_epoch_ms > 0
    {
        Some(format!("{thread_id}:{turn_id}"))
    } else {
        None
    };
    let observed = turn_key.is_some() && observation.client_turn_output_tokens > 0;
    let matched_turn_ids = turn_key
        .clone()
        .into_iter()
        .filter(|_| observed)
        .collect::<BTreeSet<_>>();
    let matched_context_pack_ids = if observed {
        target_context_pack_ids.clone()
    } else {
        BTreeSet::new()
    };
    let unmatched_context_pack_ids = target_context_pack_ids
        .difference(&matched_context_pack_ids)
        .cloned()
        .collect::<BTreeSet<_>>();

    Some(AssistantGenerationScopeObservation {
        target_group_count: 1,
        observed_group_count: if observed { 1 } else { 0 },
        observed_tokens: if observed {
            observation.client_turn_output_tokens
        } else {
            0
        },
        helper_only_context_pack_ids: BTreeSet::new(),
        helper_only_non_model_visible_context_pack_ids: BTreeSet::new(),
        target_context_pack_ids,
        matched_context_pack_ids,
        unmatched_context_pack_ids,
        matched_turn_ids: matched_turn_ids.clone(),
        available_turns: turn_key.iter().count() as u64,
        available_direct_turns: 0,
        available_rollout_turns: turn_key.iter().count() as u64,
        matched_direct_turn_ids: BTreeSet::new(),
        matched_rollout_turn_ids: matched_turn_ids,
    })
}

fn current_live_turn_meter_summary(summary: &Value) -> Value {
    let mut adjusted = summary.clone();
    let live_events_count = adjusted["live_events_count"].as_u64().unwrap_or(0);
    if live_events_count > 0 {
        adjusted["meter_counted_events"] = Value::from(live_events_count);
    }
    adjusted
}

fn assistant_scope_is_materialized(scope: &AssistantGenerationScopeObservation) -> bool {
    scope.target_group_count > 0
        || scope.observed_group_count > 0
        || scope.observed_tokens > 0
        || scope.available_turns > 0
        || !scope.target_context_pack_ids.is_empty()
        || !scope.matched_context_pack_ids.is_empty()
        || !scope.unmatched_context_pack_ids.is_empty()
        || !scope.helper_only_context_pack_ids.is_empty()
        || !scope
            .helper_only_non_model_visible_context_pack_ids
            .is_empty()
}

fn materialized_assistant_scope<'a>(
    scope: &'a AssistantGenerationScopeObservation,
) -> Option<&'a AssistantGenerationScopeObservation> {
    assistant_scope_is_materialized(scope).then_some(scope)
}

pub async fn record_continuity_restore_observed_event(
    db: &Client,
    project_code: &str,
    namespace_code: &str,
    prompt_text: &str,
    source_kind: &str,
) -> Result<()> {
    let prompt_text = prompt_text.trim();
    if prompt_text.is_empty() {
        return Ok(());
    }

    let repo_root = config::discover_repo_root(None)?;
    let config = load_config(&repo_root)?;
    let tokenizer = build_tokenizer(&config.measurement.tokenizer)?;
    let continuity_restore_tokens = tokenizer.encode_with_special_tokens(prompt_text).len() as u64;
    let traffic_class = derive_traffic_class(source_kind);
    let mut event = build_continuity_restore_observed_event(
        project_code,
        namespace_code,
        source_kind,
        &config.measurement,
        &config.contract,
        prompt_text,
        continuity_restore_tokens,
    )?;
    let continuity_snapshots = postgres::list_scoped_observability_snapshots_by_kinds(
        db,
        &["continuity_import", "continuity_handoff"],
        project_code,
        namespace_code,
        None,
    )
    .await?;
    let occurred_at_epoch_ms = event["token_budget_event"]["occurred_at_epoch_ms"]
        .as_i64()
        .unwrap_or_else(|| current_epoch_ms().unwrap_or_default());
    if let Some(materialization) = continuity_pre_amai_baseline_materialization(
        &tokenizer,
        project_code,
        namespace_code,
        latest_scoped_continuity_snapshot_before(
            &continuity_snapshots,
            "continuity_import",
            project_code,
            namespace_code,
            occurred_at_epoch_ms,
        ),
        latest_scoped_continuity_snapshot_before(
            &continuity_snapshots,
            "continuity_handoff",
            project_code,
            namespace_code,
            occurred_at_epoch_ms,
        ),
    ) {
        let _ = apply_continuity_pre_amai_baseline(&mut event, &materialization)?;
    }
    if traffic_class == "live" {
        let profile = resolve_profile(&config, None, &repo_root)?;
        enrich_live_event_payload(db, &mut event, &profile, &repo_root).await?;
    }
    let _ = postgres::insert_observability_snapshot(db, "token_budget_event", &event).await?;
    Ok(())
}

pub async fn record_verify_context_pack_event(db: &Client, payload: &Value) -> Result<()> {
    record_context_pack_event(db, payload, "verify_context_pack").await
}

