fn dashboard_token_events_delta_limit(
    previous: &[postgres::ObservabilitySnapshotKindSummary],
    current: &[postgres::ObservabilitySnapshotKindSummary],
    max_delta: i64,
) -> Option<i64> {
    let previous = previous
        .iter()
        .map(|item| (item.snapshot_kind.clone(), item))
        .collect::<BTreeMap<_, _>>();
    let current = current
        .iter()
        .map(|item| (item.snapshot_kind.clone(), item))
        .collect::<BTreeMap<_, _>>();
    let kinds = previous
        .keys()
        .chain(current.keys())
        .cloned()
        .collect::<BTreeSet<_>>();
    let mut delta_total = 0_i64;
    for kind in kinds {
        let previous_item = previous.get(&kind);
        let current_item = current.get(&kind);
        let previous_count = previous_item.map(|item| item.snapshots_count).unwrap_or(0);
        let current_count = current_item.map(|item| item.snapshots_count).unwrap_or(0);
        if current_count < previous_count {
            return None;
        }
        let previous_latest = previous_item.and_then(|item| item.latest_created_at_epoch_ms);
        let current_latest = current_item.and_then(|item| item.latest_created_at_epoch_ms);
        if current_latest < previous_latest {
            return None;
        }
        delta_total = delta_total.saturating_add(current_count.saturating_sub(previous_count));
    }
    if delta_total == 0 || delta_total > max_delta {
        None
    } else {
        Some(delta_total)
    }
}

fn event_shadow_version_key(event: &TokenBudgetEvent) -> (i64, i64, String) {
    (
        event.created_at_epoch_ms,
        event.ingested_at_epoch_ms,
        event
            .snapshot_id
            .as_ref()
            .map(ToString::to_string)
            .unwrap_or_else(|| event.event_id.clone()),
    )
}

fn live_usage_identity_shadow_key(event: &TokenBudgetEvent) -> Option<String> {
    if event.traffic_class != "live" {
        return None;
    }
    let correlation_id = event_context_pack_id(event)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| event.event_id.clone());
    if correlation_id.is_empty() {
        return None;
    }
    Some(format!(
        "{}:{}:{}:{}:{}",
        event.project, event.namespace, event.measurement_scope, event.source_kind, correlation_id
    ))
}

fn dashboard_token_event_merge_key(event: &TokenBudgetEvent) -> String {
    live_usage_identity_shadow_key(event).unwrap_or_else(|| {
        format!(
            "{}:{}:{}:{}:{}:{}",
            event.project,
            event.namespace,
            event.measurement_scope,
            event.traffic_class,
            event.source_kind,
            event.event_id
        )
    })
}

fn merge_dashboard_token_events(
    previous_events: Vec<TokenBudgetEvent>,
    delta_events: Vec<TokenBudgetEvent>,
) -> Vec<TokenBudgetEvent> {
    let mut merged = BTreeMap::<String, TokenBudgetEvent>::new();
    for event in previous_events.into_iter().chain(delta_events) {
        let key = dashboard_token_event_merge_key(&event);
        let version = event_shadow_version_key(&event);
        match merged.get(&key) {
            Some(existing) if event_shadow_version_key(existing) >= version => {}
            _ => {
                merged.insert(key, event);
            }
        }
    }
    merged.into_values().collect()
}

fn can_shadow_live_report_event(event: &TokenBudgetEvent) -> bool {
    if event.traffic_class == "live" {
        return false;
    }
    event.source_kind.starts_with("proof_")
        || event.source_kind.starts_with("verify_")
        || event.source_kind.starts_with("benchmark_")
        || event.payload_origin == "operator_source_kind_rewrite"
}

fn live_event_is_engineering_runtime_contamination(event: &TokenBudgetEvent) -> bool {
    if event.traffic_class != "live" {
        return false;
    }
    if event.source_kind.starts_with("live_proof_") {
        return true;
    }
    let thread_id = event.thread_id.as_deref().unwrap_or_default().trim();
    if thread_id.starts_with("proof-") || thread_id.starts_with("proof_") {
        return true;
    }
    let turn_id = event.turn_id.as_deref().unwrap_or_default().trim();
    turn_id.starts_with("turn-proof-") || turn_id.starts_with("turn_proof_")
}

fn shadowed_live_event_key(event: &TokenBudgetEvent) -> Option<String> {
    let correlation_id = event.correlation_id.trim();
    if correlation_id.is_empty() {
        return None;
    }
    Some(format!(
        "{}:{}:{}:{}",
        event.project, event.namespace, event.measurement_scope, correlation_id
    ))
}

fn suppress_shadowed_live_events(events: Vec<TokenBudgetEvent>) -> Vec<TokenBudgetEvent> {
    let mut newest_shadow_by_key = BTreeMap::<String, (i64, i64, String)>::new();
    let mut newest_live_by_usage_identity = BTreeMap::<String, (i64, i64, String)>::new();
    for event in &events {
        if let Some(key) = live_usage_identity_shadow_key(event) {
            let version = event_shadow_version_key(event);
            newest_live_by_usage_identity
                .entry(key)
                .and_modify(|current| {
                    if *current < version {
                        *current = version.clone();
                    }
                })
                .or_insert(version);
        }
        if !can_shadow_live_report_event(event) {
            continue;
        }
        let Some(key) = shadowed_live_event_key(event) else {
            continue;
        };
        let version = event_shadow_version_key(event);
        newest_shadow_by_key
            .entry(key)
            .and_modify(|current| {
                if *current < version {
                    *current = version.clone();
                }
            })
            .or_insert(version);
    }
    events
        .into_iter()
        .filter(|event| {
            if let Some(key) = live_usage_identity_shadow_key(event) {
                let current_version = event_shadow_version_key(event);
                if newest_live_by_usage_identity
                    .get(&key)
                    .is_some_and(|latest_version| *latest_version > current_version)
                {
                    return false;
                }
            }
            if event.traffic_class != "live" {
                return true;
            }
            let Some(key) = shadowed_live_event_key(event) else {
                return true;
            };
            let Some(shadow_version) = newest_shadow_by_key.get(&key) else {
                return true;
            };
            *shadow_version < event_shadow_version_key(event)
        })
        .collect()
}

fn parse_snapshot_event(row: &ObservabilitySnapshotRecord) -> Result<Option<TokenBudgetEvent>> {
    let (node, fallback_source_kind) = match row.snapshot_kind.as_str() {
        "token_budget_event" => (&row.payload["token_budget_event"], None),
        "token_benchmark" => (
            &row.payload["token_benchmark"],
            Some("verify_token_benchmark_legacy"),
        ),
        _ => return Ok(None),
    };
    if !node.is_object() {
        return Ok(None);
    }
    let source_kind = node["source_kind"]
        .as_str()
        .or(fallback_source_kind)
        .unwrap_or("unknown")
        .to_string();
    let traffic_class = node["traffic_class"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_traffic_class(&source_kind));
    let project = node["project"]
        .as_str()
        .or_else(|| node["project_code"].as_str())
        .unwrap_or_default()
        .to_string();
    let namespace = node["namespace"]
        .as_str()
        .or_else(|| node["namespace_code"].as_str())
        .unwrap_or_default()
        .to_string();
    let query = node["query"].as_str().unwrap_or_default().to_string();
    let query_hash = node["query_hash"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| hex_sha256(query.as_bytes()));
    let query_type = node["query_type"]
        .as_str()
        .filter(|value| !value.is_empty() && *value != "unknown")
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_query_type(&query).to_string());
    let target_kind = node["target_kind"]
        .as_str()
        .filter(|value| !value.is_empty())
        .unwrap_or("unknown")
        .to_string();
    let baseline_hit_target = node["baseline_hit_target"].as_bool().unwrap_or(false);
    let amai_hit_target = node["amai_hit_target"].as_bool().unwrap_or(false);
    let cold_warm_state = node["cold_warm_state"]
        .as_str()
        .unwrap_or("unknown")
        .to_string();
    let baseline_strategy = node["baseline_strategy"]
        .as_str()
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_baseline_strategy(&query_type).to_string());
    let retrieval_mode = node["retrieval_mode"].as_str().map(ToOwned::to_owned);
    let tokenizer = node["tokenizer"].as_str().unwrap_or_default().to_string();
    let latency_ms = node["latency_ms"].as_f64().unwrap_or(0.0);
    let event_id = node["event_id"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("{}-{}", row.snapshot_kind, row.created_at_epoch_ms));
    let correlation_id = node["correlation_id"]
        .as_str()
        .map(ToOwned::to_owned)
        .or_else(|| node["context_pack_id"].as_str().map(ToOwned::to_owned))
        .unwrap_or_else(|| event_id.clone());
    let context_pack_id = node["context_pack_id"].as_str().map(ToOwned::to_owned);
    let thread_id = node["thread_id"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let turn_id = node["turn_id"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let payload_origin = node["payload_origin"]
        .as_str()
        .unwrap_or("unknown")
        .to_string();
    let session_id = node["session_id"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_default();
    let rolling_window_profile = node["rolling_window_profile"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_default();
    let timestamp_utc = node["timestamp_utc"]
        .as_i64()
        .unwrap_or(row.created_at_epoch_ms);
    let occurred_at_epoch_ms = node["occurred_at_epoch_ms"]
        .as_i64()
        .unwrap_or(timestamp_utc);
    let ingested_at_epoch_ms = node["ingested_at_epoch_ms"]
        .as_i64()
        .unwrap_or(row.created_at_epoch_ms);
    let measurement_scope = node["measurement_scope"]
        .as_str()
        .unwrap_or("retrieval_lower_bound")
        .to_string();
    let usage_event_schema_version = node["contract"]["usage_event_schema_version"]
        .as_str()
        .unwrap_or("billing-usage-event-v0")
        .to_string();
    let settlement_statement_version = node["contract"]["settlement_statement_version"]
        .as_str()
        .unwrap_or("settlement-preview-v0")
        .to_string();
    let metering_event_schema_version = node["contract"]["metering_event_schema_version"]
        .as_str()
        .unwrap_or("token-budget-event-v1")
        .to_string();
    let usage_lifecycle_model_version = node["contract"]["usage_lifecycle_model_version"]
        .as_str()
        .unwrap_or("usage-lifecycle-v0")
        .to_string();
    let baseline_method_version = node["contract"]["baseline_method_version"]
        .as_str()
        .unwrap_or("retrieval-baseline-v0")
        .to_string();
    let quality_method_version = node["contract"]["quality_method_version"]
        .as_str()
        .unwrap_or("quality-gate-v0")
        .to_string();
    let coverage_model_version = node["contract"]["coverage_model_version"]
        .as_str()
        .unwrap_or("token-coverage-v0")
        .to_string();
    let metering_freshness_model_version = node["contract"]["metering_freshness_model_version"]
        .as_str()
        .unwrap_or("metering-freshness-v0")
        .to_string();
    let excluded_taxonomy_version = node["contract"]["excluded_taxonomy_version"]
        .as_str()
        .unwrap_or("token-excluded-usage-v0")
        .to_string();
    let dedup_contract_version = node["contract"]["dedup_contract_version"]
        .as_str()
        .unwrap_or("event-id-source-kind-v0")
        .to_string();
    let backfill_policy_version = node["contract"]["backfill_policy_version"]
        .as_str()
        .unwrap_or("report-only-backfill-v0")
        .to_string();
    let correction_policy_version = node["contract"]["correction_policy_version"]
        .as_str()
        .unwrap_or("report-only-correction-v0")
        .to_string();
    let freeze_close_policy_version = node["contract"]["freeze_close_policy_version"]
        .as_str()
        .unwrap_or("freeze-close-v0")
        .to_string();
    let late_arrival_policy_version = node["contract"]["late_arrival_policy_version"]
        .as_str()
        .unwrap_or("late-arrival-v0")
        .to_string();
    let dispute_policy_version = node["contract"]["dispute_policy_version"]
        .as_str()
        .unwrap_or("report-only-dispute-v0")
        .to_string();
    let settlement_lifecycle_model_version = node["contract"]["settlement_lifecycle_model_version"]
        .as_str()
        .unwrap_or("settlement-lifecycle-v0")
        .to_string();
    let statement_period_governance_version =
        node["contract"]["statement_period_governance_version"]
            .as_str()
            .unwrap_or("statement-period-governance-v0")
            .to_string();
    let adjustment_preview_model_version = node["contract"]["adjustment_preview_model_version"]
        .as_str()
        .unwrap_or("adjustment-preview-v0")
        .to_string();
    let adjustment_request_schema_version = node["contract"]["adjustment_request_schema_version"]
        .as_str()
        .unwrap_or("adjustment-request-v0")
        .to_string();
    let adjustment_registry_version = node["contract"]["adjustment_registry_version"]
        .as_str()
        .unwrap_or("adjustment-registry-v0")
        .to_string();
    let rate_card_binding_model_version = node["contract"]["rate_card_binding_model_version"]
        .as_str()
        .unwrap_or("rate-card-binding-v0")
        .to_string();
    let telemetry_surface_split_version = node["contract"]["telemetry_surface_split_version"]
        .as_str()
        .unwrap_or("tokenonomics-surface-split-v0")
        .to_string();
    let event_time_policy_version = node["contract"]["event_time_policy_version"]
        .as_str()
        .unwrap_or("client-visible-ingest-v0")
        .to_string();
    let billing_policy_version = node["contract"]["billing_policy_version"]
        .as_str()
        .unwrap_or("report-only-v0")
        .to_string();
    let suitability_model_version = node["contract"]["suitability_model_version"]
        .as_str()
        .unwrap_or("token-suitability-v0")
        .to_string();
    let billing_mode = node["contract"]["billing_mode"]
        .as_str()
        .unwrap_or("report_only")
        .to_string();
    let reconciliation_contract_version = node["contract"]["reconciliation_contract_version"]
        .as_str()
        .unwrap_or("provider-reconciliation-v0")
        .to_string();
    let margin_model_version = node["contract"]["margin_model_version"]
        .as_str()
        .unwrap_or("margin-view-v0")
        .to_string();
    let infra_cost_profile_version = node["contract"]["infra_cost_profile_version"]
        .as_str()
        .unwrap_or("unpriced-infra-v0")
        .to_string();
    let contractual_evidence_pack_version = node["contract"]["contractual_evidence_pack_version"]
        .as_str()
        .unwrap_or("contractual-evidence-pack-v0")
        .to_string();
    let rate_card_version = node["contract"]["rate_card_version"]
        .as_str()
        .unwrap_or("unpriced-v0")
        .to_string();
    let currency_profile = node["contract"]["currency_profile"]
        .as_str()
        .unwrap_or("unpriced")
        .to_string();
    let settlement_status = node["contract"]["settlement_status"]
        .as_str()
        .unwrap_or("unsettled_report_only")
        .to_string();
    let saved_tokens = node["savings"]["saved_tokens"].as_u64().unwrap_or(0);
    let naive_tokens = node["naive_scope"]["tokens"]
        .as_u64()
        .or_else(|| node["baseline_tokens"].as_u64())
        .unwrap_or(0);
    let context_tokens = node["context_pack_render"]["tokens"]
        .as_u64()
        .or_else(|| node["delivered_tokens"].as_u64())
        .unwrap_or(0);
    let recovery_tokens = node["recovery"]["recovery_tokens"].as_u64().unwrap_or(0);
    let effective_saved_tokens = node["savings"]["effective_saved_tokens"]
        .as_i64()
        .unwrap_or_else(|| naive_tokens as i64 - (context_tokens as i64 + recovery_tokens as i64));
    let savings_factor = node["savings"]["savings_factor"].as_f64().unwrap_or(0.0);
    let savings_percent = node["savings"]["savings_percent"]
        .as_f64()
        .or_else(|| node["gross_savings_pct"].as_f64())
        .unwrap_or(0.0);
    let effective_savings_percent = node["savings"]["effective_savings_percent"]
        .as_f64()
        .unwrap_or_else(|| percent_from_signed(effective_saved_tokens, naive_tokens));
    let quality_ok = node["quality"]["quality_ok"].as_bool().unwrap_or(false);
    let quality_score = node["quality"]["quality_score"]
        .as_f64()
        .unwrap_or(if quality_ok { 1.0 } else { 0.0 });
    let quality_method = node["quality"]["quality_method"]
        .as_str()
        .unwrap_or(if node["quality"].is_object() {
            "unknown"
        } else {
            "legacy_unverified"
        })
        .to_string();
    let quality_tier = node["quality"]["quality_tier"]
        .as_str()
        .unwrap_or("unknown")
        .to_string();
    let head_hit_target = node["quality"]["head_hit_target"]
        .as_bool()
        .unwrap_or(false);
    let needed_followup = node["followup"]["needed_followup"]
        .as_bool()
        .unwrap_or(!quality_ok);
    let followup_count = node["followup"]["followup_count"].as_u64().unwrap_or(0);
    let followup_of_event_id = node["followup"]["followup_of_event_id"]
        .as_str()
        .map(ToOwned::to_owned);
    let resolved_by_event_id = node["followup"]["resolved_by_event_id"]
        .as_str()
        .map(ToOwned::to_owned);
    let fallback_triggered = node["recovery"]["fallback_triggered"]
        .as_bool()
        .unwrap_or(false);
    let fallback_count = node["recovery"]["fallback_count"].as_u64().unwrap_or(0);
    let document_hits = node["shape"]["document_hits"].as_u64().unwrap_or(0);
    let symbol_hits_count = node["shape"]["symbol_hits"].as_u64().unwrap_or(0);
    let file_hits = node["shape"]["file_hits"].as_u64().unwrap_or(0);
    let sources_count = node["shape"]["sources_count"].as_u64().unwrap_or(0);
    let chunks_count = node["shape"]["chunks_count"].as_u64().unwrap_or(0);
    let pack_token_count = node["shape"]["pack_token_count"]
        .as_u64()
        .unwrap_or(context_tokens);
    let deduped_token_count = node["shape"]["deduped_token_count"]
        .as_u64()
        .unwrap_or(context_tokens);
    let client_prompt_tokens = node["whole_cycle_observed"]["client_prompt_tokens"].as_u64();
    let assistant_generation_tokens =
        node["whole_cycle_observed"]["assistant_generation_tokens"].as_u64();
    let tool_overhead_tokens = node["whole_cycle_observed"]["tool_overhead_tokens"].as_u64();
    let continuity_restore_tokens =
        node["whole_cycle_observed"]["continuity_restore_tokens"].as_u64();
    let tool_overhead_source = node["whole_cycle_observed_source"]["tool_overhead"]
        .as_object()
        .map(|_| node["whole_cycle_observed_source"]["tool_overhead"].clone());
    let pre_amai_baseline_source = node["pre_amai_baseline_source"]
        .as_object()
        .map(|_| node["pre_amai_baseline_source"].clone());

    Ok(Some(TokenBudgetEvent {
        snapshot_id: Some(row.snapshot_id),
        created_at_epoch_ms: row.created_at_epoch_ms,
        event_id,
        correlation_id,
        context_pack_id,
        thread_id,
        turn_id,
        payload_origin,
        session_id,
        rolling_window_profile,
        timestamp_utc,
        occurred_at_epoch_ms,
        ingested_at_epoch_ms,
        snapshot_kind: row.snapshot_kind.clone(),
        source_kind,
        traffic_class,
        measurement_scope,
        usage_event_schema_version,
        settlement_statement_version,
        metering_event_schema_version,
        usage_lifecycle_model_version,
        baseline_method_version,
        quality_method_version,
        coverage_model_version,
        metering_freshness_model_version,
        excluded_taxonomy_version,
        dedup_contract_version,
        backfill_policy_version,
        correction_policy_version,
        freeze_close_policy_version,
        late_arrival_policy_version,
        dispute_policy_version,
        settlement_lifecycle_model_version,
        statement_period_governance_version,
        adjustment_preview_model_version,
        adjustment_request_schema_version,
        adjustment_registry_version,
        rate_card_binding_model_version,
        telemetry_surface_split_version,
        event_time_policy_version,
        billing_policy_version,
        suitability_model_version,
        billing_mode,
        reconciliation_contract_version,
        margin_model_version,
        infra_cost_profile_version,
        contractual_evidence_pack_version,
        rate_card_version,
        currency_profile,
        settlement_status,
        project,
        namespace,
        query,
        query_hash,
        query_type,
        target_kind,
        baseline_hit_target,
        amai_hit_target,
        cold_warm_state,
        baseline_strategy,
        retrieval_mode,
        tokenizer,
        latency_ms,
        saved_tokens,
        naive_tokens,
        context_tokens,
        recovery_tokens,
        effective_saved_tokens,
        savings_factor,
        savings_percent,
        effective_savings_percent,
        quality_ok,
        quality_score,
        quality_method,
        quality_tier,
        head_hit_target,
        needed_followup,
        followup_count,
        followup_of_event_id,
        resolved_by_event_id,
        fallback_triggered,
        fallback_count,
        document_hits,
        symbol_hits_count,
        file_hits,
        sources_count,
        chunks_count,
        pack_token_count,
        deduped_token_count,
        client_prompt_tokens,
        assistant_generation_tokens,
        tool_overhead_tokens,
        continuity_restore_tokens,
        tool_overhead_source,
        pre_amai_baseline_source,
    }))
}

fn needs_live_reverification(payload: &Value) -> bool {
    let node = &payload["token_budget_event"];
    if !node.is_object() {
        return false;
    }
    let source_kind = node["source_kind"].as_str().unwrap_or_default();
    let traffic_class = node["traffic_class"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_traffic_class(source_kind));
    if traffic_class != "live" {
        return false;
    }
    let quality_method = node["quality"]["quality_method"]
        .as_str()
        .unwrap_or_default();
    let quality_ok = node["quality"]["quality_ok"].as_bool().unwrap_or(false);
    let needs_shape_upgrade = node["target_kind"]
        .as_str()
        .map(|value| value.is_empty() || value == "unknown")
        .unwrap_or(true)
        || node.get("latency_ms").is_none()
        || node["quality"].get("quality_tier").is_none()
        || node["quality"].get("head_hit_target").is_none()
        || node["shape"].get("pack_token_count").is_none()
        || node["shape"].get("deduped_token_count").is_none()
        || node["followup"].is_null()
        || node["shape"].get("file_hits").is_none();
    quality_method == "legacy_unverified"
        || (quality_method.is_empty() && !quality_ok)
        || needs_shape_upgrade
}

fn matches_token_ledger_repair_selector(
    event: &TokenBudgetEvent,
    request: &TokenLedgerRepairRequest,
) -> bool {
    if request
        .project
        .as_deref()
        .is_some_and(|expected| event.project != expected)
    {
        return false;
    }
    if request
        .project_prefix
        .as_deref()
        .is_some_and(|prefix| !event.project.starts_with(prefix))
    {
        return false;
    }
    if request
        .namespace
        .as_deref()
        .is_some_and(|expected| event.namespace != expected)
    {
        return false;
    }
    if request
        .source_kind
        .as_deref()
        .is_some_and(|expected| event.source_kind != expected)
    {
        return false;
    }
    if request
        .correlation_id
        .as_deref()
        .is_some_and(|expected| event.correlation_id != expected)
    {
        return false;
    }
    true
}

fn rewrite_token_ledger_source_kind_payload(
    row: &ObservabilitySnapshotRecord,
    rewrite_source_kind: &str,
    repair_reason: &str,
) -> Result<Option<Value>> {
    let mut updated = row.payload.clone();
    let root = updated
        .as_object_mut()
        .ok_or_else(|| anyhow!("token budget payload root is not an object"))?;
    let node = root
        .get_mut("token_budget_event")
        .and_then(Value::as_object_mut)
        .ok_or_else(|| anyhow!("token budget payload missing token_budget_event"))?;
    let previous_source_kind = node
        .get("source_kind")
        .and_then(Value::as_str)
        .unwrap_or("unknown")
        .to_string();
    let previous_traffic_class = node
        .get("traffic_class")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_traffic_class(&previous_source_kind));
    let rewritten_traffic_class = derive_traffic_class(rewrite_source_kind);
    if previous_source_kind == rewrite_source_kind
        && previous_traffic_class == rewritten_traffic_class
    {
        return Ok(None);
    }

    let event_id = node
        .get("event_id")
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_string();
    let correlation_id = node
        .get("correlation_id")
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
        .or_else(|| {
            node.get("context_pack_id")
                .and_then(Value::as_str)
                .map(ToOwned::to_owned)
        })
        .unwrap_or_else(|| event_id.clone());
    let payload_origin = if rewritten_traffic_class == "live" {
        "context_pack_token_budget".to_string()
    } else {
        rewrite_source_kind.to_string()
    };
    node.insert(
        "source_kind".to_string(),
        Value::String(rewrite_source_kind.to_string()),
    );
    node.insert(
        "traffic_class".to_string(),
        Value::String(rewritten_traffic_class.clone()),
    );
    node.insert(
        "payload_origin".to_string(),
        Value::String(payload_origin.clone()),
    );
    node.insert(
        "usage_identity".to_string(),
        json!({
            "dedup_key": usage_dedup_key(rewrite_source_kind, &event_id),
            "idempotency_scope": "source_kind + event_id",
            "canonical_window_time_field": "occurred_at_epoch_ms",
            "event_id": event_id,
            "correlation_id": correlation_id,
        }),
    );
    let repair = ensure_nested_object(node, "repair")?;
    repair.insert(
        "operator_source_kind_rewrite".to_string(),
        json!({
            "repaired_at_utc": current_epoch_ms()?,
            "repair_reason": repair_reason,
            "previous_source_kind": previous_source_kind,
            "previous_traffic_class": previous_traffic_class,
            "rewritten_source_kind": rewrite_source_kind,
            "rewritten_traffic_class": rewritten_traffic_class,
            "rewritten_payload_origin": payload_origin,
        }),
    );
    let observability = ensure_nested_object(root, "_observability")?;
    observability.insert(
        "source_kind".to_string(),
        Value::String(rewrite_source_kind.to_string()),
    );

    let rebuilt = parse_snapshot_event(&ObservabilitySnapshotRecord {
        snapshot_id: row.snapshot_id,
        snapshot_kind: row.snapshot_kind.clone(),
        payload: updated.clone(),
        created_at_epoch_ms: row.created_at_epoch_ms,
    })?
    .ok_or_else(|| anyhow!("failed to rebuild token budget event after source kind rewrite"))?;
    let node = updated["token_budget_event"]
        .as_object_mut()
        .ok_or_else(|| anyhow!("token budget payload missing token_budget_event after rebuild"))?;
    node.insert(
        "usage_state".to_string(),
        json!({
            "lifecycle_status": usage_lifecycle_status(&rebuilt),
            "reporting_layer": usage_reporting_layer(&rebuilt),
            "included_in_verified_rollup": usage_excluded_reason_code(&rebuilt).is_none(),
            "excluded_reason_code": usage_excluded_reason_code(&rebuilt),
            "backfill_status": usage_backfill_status(&rebuilt),
            "settlement_status": rebuilt.settlement_status,
        }),
    );
    Ok(Some(updated))
}

fn usage_dedup_key(source_kind: &str, event_id: &str) -> String {
    format!("{source_kind}:{event_id}")
}

fn usage_excluded_reason_code(event: &TokenBudgetEvent) -> Option<&'static str> {
    if event.traffic_class != "live" {
        return Some("non_live_other");
    }
    if event.quality_ok {
        return None;
    }
    Some(excluded_event_code(event))
}

fn usage_lifecycle_status(event: &TokenBudgetEvent) -> &'static str {
    match usage_excluded_reason_code(event) {
        None => "verified_included",
        Some("quality_gate_failed") => "excluded_quality_gate_failed",
        Some("awaiting_followup_reconciliation") => "excluded_awaiting_followup_reconciliation",
        Some("legacy_unverified") => "excluded_legacy_unverified",
        Some(_) => "excluded_non_live",
    }
}

fn usage_reporting_layer(event: &TokenBudgetEvent) -> &'static str {
    if usage_excluded_reason_code(event).is_none() {
        "measured_non_billable"
    } else {
        "excluded"
    }
}

fn usage_backfill_status(event: &TokenBudgetEvent) -> &'static str {
    if event.traffic_class != "live" {
        "synthetic_ingest"
    } else if event.payload_origin == "reverified_live_context_pack" {
        "reverified_backfill"
    } else if event.metering_event_schema_version != default_metering_event_schema_version() {
        "legacy_ingest"
    } else {
        "live_ingest"
    }
}

async fn reverify_live_event_payload(
    cfg: &AppConfig,
    db: &mut Client,
    measurement: &MeasurementConfig,
    contract: &TokenBudgetContractConfig,
    row: &ObservabilitySnapshotRecord,
) -> Result<Option<Value>> {
    let node = &row.payload["token_budget_event"];
    if !node.is_object() {
        return Ok(None);
    }

    let project = node["project"]
        .as_str()
        .filter(|value| !value.is_empty())
        .ok_or_else(|| anyhow!("token event missing project"))?;
    let namespace = node["namespace"]
        .as_str()
        .filter(|value| !value.is_empty())
        .ok_or_else(|| anyhow!("token event missing namespace"))?;
    let query = node["query"]
        .as_str()
        .filter(|value| !value.is_empty())
        .ok_or_else(|| anyhow!("token event missing query"))?;

    let args = ContextPackArgs {
        project: project.to_string(),
        namespace: namespace.to_string(),
        query: query.to_string(),
        retrieval_mode: node["retrieval_mode"].as_str().map(ToOwned::to_owned),
        disable_cache: false,
        limit_documents: 5,
        limit_symbols: 8,
        limit_chunks: 8,
        limit_semantic_chunks: 8,
        token_source_kind: "proof_reverify_context_pack".to_string(),
        client_prompt_tokens: None,
        assistant_generation_tokens: None,
        tool_overhead_tokens: None,
        continuity_restore_tokens: None,
    };

    let result =
        retrieval::execute_context_pack_capture_with_options(cfg, db, &args, false, false).await?;
    let source_kind = node["source_kind"]
        .as_str()
        .filter(|value| !value.is_empty())
        .unwrap_or("live_context_pack");
    let mut rebuilt = build_event_payload(
        &result.payload,
        measurement,
        contract,
        source_kind,
        "reverified_live_context_pack",
    )?;
    apply_reverification_metadata(&mut rebuilt, node, row.created_at_epoch_ms)?;
    Ok(Some(rebuilt))
}

fn apply_reverification_metadata(
    rebuilt_payload: &mut Value,
    original_node: &Value,
    fallback_timestamp_utc: i64,
) -> Result<()> {
    let target_kind_owned = rebuilt_payload["token_budget_event"]["target_kind"]
        .as_str()
        .unwrap_or("file")
        .to_string();
    let exact_hits = rebuilt_payload["retrieval"]["exact_documents"]
        .as_array()
        .map_or(0, Vec::len);
    let symbol_hits = rebuilt_payload["retrieval"]["symbol_hits"]
        .as_array()
        .map_or(0, Vec::len);
    let lexical_hits = rebuilt_payload["retrieval"]["lexical_chunks"]
        .as_array()
        .map_or(0, Vec::len);
    let semantic_hits = rebuilt_payload["retrieval"]["semantic_chunks"]
        .as_array()
        .map_or(0, Vec::len);
    let rebuilt_node = rebuilt_payload["token_budget_event"]
        .as_object_mut()
        .ok_or_else(|| anyhow!("rebuilt token event payload missing token_budget_event object"))?;

    let event_id = original_node["event_id"]
        .as_str()
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| Uuid::new_v4().to_string());
    let timestamp_utc = original_node["timestamp_utc"]
        .as_i64()
        .unwrap_or(fallback_timestamp_utc);
    let source_kind = original_node["source_kind"]
        .as_str()
        .filter(|value| !value.is_empty())
        .unwrap_or("live_context_pack");
    let quality_ok = rebuilt_node
        .get("quality")
        .and_then(|value| value.get("quality_ok"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let reverified_at_utc = current_epoch_ms()?;

    rebuilt_node.insert("event_id".to_string(), Value::String(event_id));
    rebuilt_node.insert("timestamp_utc".to_string(), Value::from(timestamp_utc));
    rebuilt_node.insert(
        "source_kind".to_string(),
        Value::String(source_kind.to_string()),
    );
    rebuilt_node.insert(
        "traffic_class".to_string(),
        Value::String(derive_traffic_class(source_kind)),
    );
    rebuilt_node.insert(
        "payload_origin".to_string(),
        Value::String("reverified_live_context_pack".to_string()),
    );
    if let Some(quality) = rebuilt_node
        .get_mut("quality")
        .and_then(Value::as_object_mut)
    {
        let head_hit_target = quality
            .get("head_hit_target")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let answer_like_proxy = answer_like_from_counts(
            &target_kind_owned,
            head_hit_target,
            exact_hits,
            symbol_hits,
            lexical_hits,
            semantic_hits,
        );
        quality.insert(
            "quality_method".to_string(),
            Value::String(if quality_ok {
                if answer_like_proxy {
                    "reverified_answer_proxy".to_string()
                } else if head_hit_target {
                    "reverified_task_proxy".to_string()
                } else {
                    "reverified_retrieval_parity".to_string()
                }
            } else {
                "reverified_retrieval_miss".to_string()
            }),
        );
        quality.insert(
            "quality_tier".to_string(),
            Value::String(if quality_ok {
                if answer_like_proxy {
                    "answer_proxy".to_string()
                } else if head_hit_target {
                    "task_proxy".to_string()
                } else {
                    "retrieval".to_string()
                }
            } else {
                "partial".to_string()
            }),
        );
        quality.insert(
            "reverified_at_utc".to_string(),
            Value::from(reverified_at_utc),
        );
    }
    rebuilt_node.insert(
        "reverification".to_string(),
        json!({
            "reverified_at_utc": reverified_at_utc,
            "previous_quality_method": original_node["quality"]["quality_method"]
                .as_str()
                .unwrap_or("missing"),
            "previous_quality_ok": original_node["quality"]["quality_ok"]
                .as_bool()
                .unwrap_or(false),
        }),
    );
    Ok(())
}

fn repair_legacy_token_event_payload(payload: &Value) -> Option<Value> {
    let mut updated = payload.clone();
    let node = updated.get_mut("token_budget_event")?;
    let object = node.as_object_mut()?;
    let source_kind = object
        .get("source_kind")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let query = object
        .get("query")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let query_type = object
        .get("query_type")
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty() && *value != "unknown")
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| derive_query_type(query).to_string());
    let mut changed = false;

    if !object.contains_key("traffic_class") {
        object.insert(
            "traffic_class".to_string(),
            Value::String(derive_traffic_class(source_kind)),
        );
        changed = true;
    }
    if !object.contains_key("query_type") {
        object.insert("query_type".to_string(), Value::String(query_type.clone()));
        changed = true;
    }
    if !object.contains_key("baseline_strategy") {
        object.insert(
            "baseline_strategy".to_string(),
            Value::String(derive_baseline_strategy(&query_type).to_string()),
        );
        changed = true;
    }
    if !object.contains_key("recovery") {
        object.insert(
            "recovery".to_string(),
            json!({
                "recovery_tokens": 0,
                "fallback_triggered": false,
                "fallback_count": 0
            }),
        );
        changed = true;
    }
    if !object.contains_key("shape") {
        object.insert(
            "shape".to_string(),
            json!({
                "sources_count": 0,
                "chunks_count": 0
            }),
        );
        changed = true;
    }
    if !object.contains_key("quality") {
        object.insert(
            "quality".to_string(),
            json!({
                "quality_ok": false,
                "quality_score": 0.0,
                "quality_method": "legacy_unverified",
                "quality_tier": "unverified",
                "head_hit_target": false
            }),
        );
        changed = true;
    }
    let naive_tokens = object
        .get("naive_scope")
        .and_then(|value| value.get("tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let context_tokens = object
        .get("context_pack_render")
        .and_then(|value| value.get("tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let recovery_tokens = object
        .get("recovery")
        .and_then(|value| value.get("recovery_tokens"))
        .and_then(Value::as_u64)
        .unwrap_or(0);
    if let Some(savings) = object.get_mut("savings").and_then(Value::as_object_mut) {
        if !savings.contains_key("effective_saved_tokens") {
            savings.insert(
                "effective_saved_tokens".to_string(),
                Value::from(naive_tokens as i64 - (context_tokens as i64 + recovery_tokens as i64)),
            );
            changed = true;
        }
        if !savings.contains_key("effective_savings_percent") {
            let effective_saved_tokens = savings
                .get("effective_saved_tokens")
                .and_then(Value::as_i64)
                .unwrap_or(naive_tokens as i64 - (context_tokens as i64 + recovery_tokens as i64));
            savings.insert(
                "effective_savings_percent".to_string(),
                Value::from(percent_from_signed(effective_saved_tokens, naive_tokens)),
            );
            changed = true;
        }
    }

    changed.then_some(updated)
}

fn current_session_events(
    events: &[TokenBudgetEvent],
    session_gap_ms: i64,
) -> Vec<TokenBudgetEvent> {
    let Some(latest) = events.last() else {
        return Vec::new();
    };
    if !latest.session_id.trim().is_empty() {
        let session = events
            .iter()
            .filter(|event| event.session_id == latest.session_id)
            .cloned()
            .collect::<Vec<_>>();
        if !session.is_empty() {
            return session;
        }
    }
    let mut session = vec![latest.clone()];
    let mut newer_ts = latest.created_at_epoch_ms;
    for event in events.iter().rev().skip(1) {
        if newer_ts.saturating_sub(event.created_at_epoch_ms) > session_gap_ms {
            break;
        }
        session.push(event.clone());
        newer_ts = event.created_at_epoch_ms;
    }
    session.reverse();
    session
}

fn source_kind_starts_new_session(source_kind: &str) -> bool {
    source_kind.ends_with("continuity_startup")
}

fn active_same_meter_scope_events(
    session_events: &[TokenBudgetEvent],
    rolling_window_events: &[TokenBudgetEvent],
) -> Vec<TokenBudgetEvent> {
    let mut seen = BTreeSet::new();
    let mut scoped = Vec::new();
    for event in session_events.iter().chain(rolling_window_events.iter()) {
        if seen.insert(event.event_id.clone()) {
            scoped.push(event.clone());
        }
    }
    scoped
}

fn resolve_session_id(
    events: &[TokenBudgetEvent],
    current_ts: i64,
    session_gap_ms: i64,
    current_source_kind: &str,
) -> String {
    if source_kind_starts_new_session(current_source_kind) {
        return Uuid::new_v4().to_string();
    }
    events
        .iter()
        .rev()
        .find(|event| {
            event.traffic_class == "live"
                && current_ts.saturating_sub(event.created_at_epoch_ms) <= session_gap_ms
        })
        .map(|event| {
            if event.session_id.is_empty() {
                event.event_id.clone()
            } else {
                event.session_id.clone()
            }
        })
        .unwrap_or_else(|| Uuid::new_v4().to_string())
}

fn set_recovery_penalty(
    payload: &mut Value,
    recovery_tokens: u64,
    followup_count: u64,
) -> Result<()> {
    let node = payload["token_budget_event"]
        .as_object_mut()
        .ok_or_else(|| anyhow!("token budget payload missing token_budget_event object"))?;
    let recovery = ensure_nested_object(node, "recovery")?;
    recovery.insert("recovery_tokens".to_string(), Value::from(recovery_tokens));
    let followup = ensure_nested_object(node, "followup")?;
    followup.insert("followup_count".to_string(), Value::from(followup_count));

    let context_tokens = node["context_pack_render"]["tokens"].as_u64().unwrap_or(0);
    let naive_tokens = node["naive_scope"]["tokens"].as_u64().unwrap_or(0);
    let effective_saved_tokens =
        naive_tokens as i64 - (context_tokens as i64 + recovery_tokens as i64);
    let effective_savings_percent = percent_from_signed(effective_saved_tokens, naive_tokens);
    let savings = ensure_nested_object(node, "savings")?;
    savings.insert(
        "effective_saved_tokens".to_string(),
        Value::from(effective_saved_tokens),
    );
    savings.insert(
        "effective_savings_percent".to_string(),
        Value::from(effective_savings_percent),
    );
    Ok(())
}

fn ensure_nested_object<'a>(
    parent: &'a mut serde_json::Map<String, Value>,
    key: &str,
) -> Result<&'a mut serde_json::Map<String, Value>> {
    if !parent.get(key).is_some_and(Value::is_object) {
        parent.insert(key.to_string(), json!({}));
    }
    parent
        .get_mut(key)
        .and_then(Value::as_object_mut)
        .ok_or_else(|| anyhow!("payload field {key} is not an object"))
}

fn reconcile_followup_recovery(
    events: &[TokenBudgetEvent],
    session_gap_ms: i64,
) -> Vec<TokenBudgetEvent> {
    let mut reconciled = events.to_vec();
    for current_index in 1..reconciled.len() {
        if reconciled[current_index].traffic_class != "live"
            || reconciled[current_index].followup_of_event_id.is_some()
        {
            continue;
        }
        let current_ts = reconciled[current_index].created_at_epoch_ms;
        let current_project = reconciled[current_index].project.clone();
        let current_namespace = reconciled[current_index].namespace.clone();
        let current_key = followup_event_key(&reconciled[current_index]);

        for previous_index in (0..current_index).rev() {
            if reconciled[previous_index].traffic_class != "live"
                || !reconciled[previous_index].needed_followup
                || reconciled[previous_index].resolved_by_event_id.is_some()
            {
                continue;
            }
            if current_ts.saturating_sub(reconciled[previous_index].created_at_epoch_ms)
                > session_gap_ms
            {
                break;
            }
            if reconciled[previous_index].project != current_project
                || reconciled[previous_index].namespace != current_namespace
            {
                continue;
            }
            if !followup_queries_related(
                followup_event_key(&reconciled[previous_index]),
                current_key,
            ) {
                continue;
            }
            let recovery_tokens = reconciled[current_index].recovery_tokens.saturating_add(
                reconciled[previous_index]
                    .context_tokens
                    .saturating_add(reconciled[previous_index].recovery_tokens),
            );
            reconciled[current_index].recovery_tokens = recovery_tokens;
            reconciled[current_index].followup_count =
                reconciled[previous_index].followup_count.saturating_add(1);
            reconciled[current_index].followup_of_event_id =
                Some(reconciled[previous_index].event_id.clone());
            reconciled[current_index].effective_saved_tokens = reconciled[current_index]
                .naive_tokens as i64
                - (reconciled[current_index].context_tokens as i64 + recovery_tokens as i64);
            reconciled[current_index].effective_savings_percent = percent_from_signed(
                reconciled[current_index].effective_saved_tokens,
                reconciled[current_index].naive_tokens,
            );
            reconciled[previous_index].resolved_by_event_id =
                Some(reconciled[current_index].event_id.clone());
            break;
        }
    }
    reconciled
}

fn followup_event_key(event: &TokenBudgetEvent) -> FollowupEventKey<'_> {
    FollowupEventKey {
        query: &event.query,
        query_hash: &event.query_hash,
        query_type: &event.query_type,
        target_kind: &event.target_kind,
    }
}

fn followup_queries_related(current: FollowupEventKey<'_>, follower: FollowupEventKey<'_>) -> bool {
    if !current.query_hash.is_empty() && current.query_hash == follower.query_hash {
        return true;
    }
    if current.query_type != follower.query_type {
        return false;
    }
    if current.target_kind != follower.target_kind {
        return false;
    }
    if normalized_query(current.query) == normalized_query(follower.query) {
        return true;
    }
    query_terms_overlap_count(current.query, follower.query) >= 2
}

fn query_terms_overlap_count(left: &str, right: &str) -> usize {
    let left_terms = extract_query_terms(left);
    if left_terms.is_empty() {
        return 0;
    }
    let right_terms = extract_query_terms(right);
    if right_terms.is_empty() {
        return 0;
    }
    let right_set = right_terms.into_iter().collect::<HashSet<_>>();
    left_terms
        .into_iter()
        .filter(|term| right_set.contains(term))
        .count()
}

fn normalized_query(query: &str) -> String {
    extract_query_terms(query).join(" ")
}

fn derived_client_prompt_tokens(
    event: &TokenBudgetEvent,
    tokenizer_cache: &mut HashMap<String, Option<CoreBPE>>,
) -> Option<u64> {
    if let Some(tokens) = event.client_prompt_tokens {
        return Some(tokens);
    }
    if event.query.is_empty() {
        return None;
    }
    if !tokenizer_cache.contains_key(&event.tokenizer) {
        tokenizer_cache.insert(
            event.tokenizer.clone(),
            build_tokenizer(&event.tokenizer).ok(),
        );
    }
    tokenizer_cache
        .get(&event.tokenizer)
        .and_then(|tokenizer| tokenizer.as_ref())
        .map(|tokenizer| tokenizer.encode_with_special_tokens(&event.query).len() as u64)
}

fn summarize_events(
    events: &[TokenBudgetEvent],
    now_epoch_ms: i64,
    measurement: &MeasurementConfig,
    contract: &TokenBudgetContractConfig,
) -> Value {
    if events.is_empty() {
        return json!({
            "events_total": 0,
            "events_count": 0,
            "live_events_count": 0,
            "non_live_events_count": 0,
            "counted_events": 0,
            "task_success_like_counted_events": 0,
            "answer_like_counted_events": 0,
            "legacy_unverified_events": 0,
            "preliminary": true,
            "baseline_tokens": 0,
            "delivered_tokens": 0,
            "recovery_tokens": 0,
            "observed_client_prompt_tokens": 0,
            "observed_assistant_generation_tokens": 0,
            "observed_tool_overhead_tokens": 0,
            "observed_continuity_restore_tokens": 0,
            "observed_client_prompt_live_events": 0,
            "observed_assistant_generation_live_events": 0,
            "observed_tool_overhead_live_events": 0,
            "observed_continuity_restore_live_events": 0,
            "observed_whole_cycle_with_amai_tokens": 0,
            "verified_observed_whole_cycle_with_amai_tokens": 0,
            "effective_saved_tokens": 0,
            "total_saved_tokens": 0,
            "total_effective_saved_tokens": 0,
            "verified_effective_saved_tokens": 0,
            "verified_task_like_saved_tokens": 0,
            "verified_answer_like_saved_tokens": 0,
            "total_naive_tokens": 0,
            "total_context_tokens": 0,
            "total_recovery_tokens": 0,
            "gross_savings_pct": 0.0,
            "effective_savings_pct": 0.0,
            "verified_effective_savings_pct": 0.0,
            "verified_task_like_savings_pct": 0.0,
            "verified_answer_like_savings_pct": 0.0,
            "savings_percent": 0.0,
            "savings_factor": 0.0,
            "avg_saved_tokens_per_event": 0.0,
            "quality_ok_rate": 0.0,
            "task_success_like_rate": 0.0,
            "answer_like_rate": 0.0,
            "fallback_rate": 0.0,
            "median_recovery_tokens": 0.0,
            "p95_latency_ms": 0.0,
            "started_at_epoch_ms": Value::Null,
            "ended_at_epoch_ms": Value::Null,
            "age_ms_since_latest": Value::Null,
            "coverage": build_coverage_summary(contract, 0, 0, 0, 0, 0),
            "excluded_breakdown": build_excluded_breakdown(contract, &[]),
        });
    }

    let mut tokenizer_cache = HashMap::<String, Option<CoreBPE>>::new();
    let total_saved_tokens = events.iter().map(|event| event.saved_tokens).sum::<u64>();
    let total_naive_tokens = events.iter().map(|event| event.naive_tokens).sum::<u64>();
    let total_context_tokens = events.iter().map(|event| event.context_tokens).sum::<u64>();
    let total_recovery_tokens = events
        .iter()
        .map(|event| event.recovery_tokens)
        .sum::<u64>();
    let observed_client_prompt_tokens = events
        .iter()
        .filter_map(|event| derived_client_prompt_tokens(event, &mut tokenizer_cache))
        .sum::<u64>();
    let observed_assistant_generation_tokens = events
        .iter()
        .filter_map(|event| event.assistant_generation_tokens)
        .sum::<u64>();
    let observed_tool_overhead_tokens = events
        .iter()
        .filter_map(|event| event.tool_overhead_tokens)
        .sum::<u64>();
    let observed_continuity_restore_tokens = events
        .iter()
        .filter_map(|event| event.continuity_restore_tokens)
        .sum::<u64>();
    let live_events_count = events
        .iter()
        .filter(|event| event.traffic_class == "live")
        .count();
    let non_live_events_count = events.len().saturating_sub(live_events_count);
    let total_effective_saved_tokens = events
        .iter()
        .map(|event| event.effective_saved_tokens)
        .sum::<i64>();
    let verified_events = events
        .iter()
        .filter(|event| event.traffic_class == "live" && event.quality_ok)
        .collect::<Vec<_>>();
    let verified_effective_saved_tokens = verified_events
        .iter()
        .map(|event| event.effective_saved_tokens)
        .sum::<i64>();
    let verified_baseline_tokens = verified_events
        .iter()
        .map(|event| event.naive_tokens)
        .sum::<u64>();
    let verified_delivered_tokens = verified_events
        .iter()
        .map(|event| event.context_tokens)
        .sum::<u64>();
    let verified_recovery_tokens = verified_events
        .iter()
        .map(|event| event.recovery_tokens)
        .sum::<u64>();
    let verified_observed_client_prompt_tokens = verified_events
        .iter()
        .filter_map(|event| derived_client_prompt_tokens(event, &mut tokenizer_cache))
        .sum::<u64>();
    let verified_observed_assistant_generation_tokens = verified_events
        .iter()
        .filter_map(|event| event.assistant_generation_tokens)
        .sum::<u64>();
    let verified_observed_tool_overhead_tokens = verified_events
        .iter()
        .filter_map(|event| event.tool_overhead_tokens)
        .sum::<u64>();
    let verified_observed_continuity_restore_tokens = verified_events
        .iter()
        .filter_map(|event| event.continuity_restore_tokens)
        .sum::<u64>();
    let observed_client_prompt_live_events = events
        .iter()
        .filter(|event| {
            event.traffic_class == "live"
                && derived_client_prompt_tokens(event, &mut tokenizer_cache).is_some()
        })
        .count() as u64;
    let observed_assistant_generation_live_events = events
        .iter()
        .filter(|event| {
            event.traffic_class == "live" && event.assistant_generation_tokens.is_some()
        })
        .count() as u64;
    let observed_tool_overhead_live_events = events
        .iter()
        .filter(|event| event.traffic_class == "live" && event.tool_overhead_tokens.is_some())
        .count() as u64;
    let observed_continuity_restore_live_events = events
        .iter()
        .filter(|event| event.traffic_class == "live" && event.continuity_restore_tokens.is_some())
        .count() as u64;
    let observed_whole_cycle_with_amai_tokens = total_context_tokens
        .saturating_add(total_recovery_tokens)
        .saturating_add(observed_client_prompt_tokens)
        .saturating_add(observed_assistant_generation_tokens)
        .saturating_add(observed_tool_overhead_tokens)
        .saturating_add(observed_continuity_restore_tokens);
    let verified_observed_whole_cycle_with_amai_tokens = verified_delivered_tokens
        .saturating_add(verified_recovery_tokens)
        .saturating_add(verified_observed_client_prompt_tokens)
        .saturating_add(verified_observed_assistant_generation_tokens)
        .saturating_add(verified_observed_tool_overhead_tokens)
        .saturating_add(verified_observed_continuity_restore_tokens);
    let excluded_events = events
        .iter()
        .filter(|event| !(event.traffic_class == "live" && event.quality_ok))
        .collect::<Vec<_>>();
    let excluded_effective_saved_tokens = excluded_events
        .iter()
        .map(|event| event.effective_saved_tokens)
        .sum::<i64>();
    let excluded_baseline_tokens = excluded_events
        .iter()
        .map(|event| event.naive_tokens)
        .sum::<u64>();
    let excluded_delivered_tokens = excluded_events
        .iter()
        .map(|event| event.context_tokens)
        .sum::<u64>();
    let excluded_recovery_tokens = excluded_events
        .iter()
        .map(|event| event.recovery_tokens)
        .sum::<u64>();
    let task_like_events = verified_events
        .iter()
        .copied()
        .filter(|event| {
            matches!(
                event.quality_tier.as_str(),
                "task_proxy"
                    | "task_success_recovered"
                    | "answer_proxy"
                    | "answer_success_recovered"
            )
        })
        .collect::<Vec<_>>();
    let answer_like_events = verified_events
        .iter()
        .copied()
        .filter(|event| is_answer_like_event(event))
        .collect::<Vec<_>>();
    let verified_task_like_saved_tokens = task_like_events
        .iter()
        .map(|event| event.effective_saved_tokens)
        .sum::<i64>();
    let verified_task_like_baseline_tokens = task_like_events
        .iter()
        .map(|event| event.naive_tokens)
        .sum::<u64>();
    let verified_answer_like_saved_tokens = answer_like_events
        .iter()
        .map(|event| event.effective_saved_tokens)
        .sum::<i64>();
    let verified_answer_like_baseline_tokens = answer_like_events
        .iter()
        .map(|event| event.naive_tokens)
        .sum::<u64>();
    let gross_savings_pct = if total_naive_tokens == 0 {
        0.0
    } else {
        total_saved_tokens as f64 * 100.0 / total_naive_tokens as f64
    };
    let effective_savings_pct =
        percent_from_signed(total_effective_saved_tokens, total_naive_tokens);
    let verified_effective_savings_pct =
        percent_from_signed(verified_effective_saved_tokens, verified_baseline_tokens);
    let verified_task_like_savings_pct = percent_from_signed(
        verified_task_like_saved_tokens,
        verified_task_like_baseline_tokens,
    );
    let verified_answer_like_savings_pct = percent_from_signed(
        verified_answer_like_saved_tokens,
        verified_answer_like_baseline_tokens,
    );
    let savings_factor = if total_context_tokens == 0 {
        total_naive_tokens as f64
    } else {
        total_naive_tokens as f64 / total_context_tokens as f64
    };
    let avg_saved_tokens_per_event = total_saved_tokens as f64 / events.len() as f64;
    let quality_ok_events = events.iter().filter(|event| event.quality_ok).count() as f64;
    let task_success_like_events = events
        .iter()
        .filter(|event| {
            matches!(
                event.quality_tier.as_str(),
                "task_proxy"
                    | "task_success_recovered"
                    | "answer_proxy"
                    | "answer_success_recovered"
            )
        })
        .count() as f64;
    let answer_like_events_rate = events
        .iter()
        .filter(|event| is_answer_like_event(event))
        .count() as f64;
    let legacy_unverified_events = events
        .iter()
        .filter(|event| event.quality_method == "legacy_unverified")
        .count();
    let fallback_events = events
        .iter()
        .filter(|event| event.fallback_triggered)
        .count() as f64;
    let mut recovery_values = events
        .iter()
        .map(|event| event.recovery_tokens as f64)
        .collect::<Vec<_>>();
    recovery_values
        .sort_by(|left, right| left.partial_cmp(right).unwrap_or(std::cmp::Ordering::Equal));
    let median_recovery_tokens = percentile_from_sorted(&recovery_values, 0.5);
    let latency_events = events
        .iter()
        .filter(|event| event.measurement_scope == "retrieval_lower_bound")
        .collect::<Vec<_>>();
    let mut latency_values = latency_events
        .iter()
        .map(|event| event.latency_ms)
        .filter(|value| value.is_finite())
        .collect::<Vec<_>>();
    latency_values
        .sort_by(|left, right| left.partial_cmp(right).unwrap_or(std::cmp::Ordering::Equal));
    let latency_sample_count = latency_values.len();
    let current_latency_ms = latency_events
        .iter()
        .rev()
        .map(|event| event.latency_ms)
        .find(|value| value.is_finite())
        .unwrap_or_default();
    let p50_latency_ms = percentile_from_sorted(&latency_values, 0.50);
    let p95_latency_ms = percentile_from_sorted(&latency_values, 0.95);
    let p99_latency_ms = percentile_from_sorted(&latency_values, 0.99);
    let max_latency_ms = latency_values.last().copied().unwrap_or_default();
    let quality_ok_rate = quality_ok_events * 100.0 / events.len() as f64;
    let task_success_like_rate = task_success_like_events * 100.0 / events.len() as f64;
    let answer_like_rate = answer_like_events_rate * 100.0 / events.len() as f64;
    let fallback_rate = fallback_events * 100.0 / events.len() as f64;
    let started_at_epoch_ms = events
        .first()
        .map(|event| event.created_at_epoch_ms)
        .unwrap_or_default();
    let ended_at_epoch_ms = events
        .last()
        .map(|event| event.created_at_epoch_ms)
        .unwrap_or_default();

    let preliminary = events.len() < measurement.preliminary_min_events as usize
        && total_naive_tokens < measurement.preliminary_min_baseline_tokens;
    let coverage = build_coverage_summary(
        contract,
        events.len() as u64,
        verified_events.len() as u64,
        excluded_events.len() as u64,
        total_naive_tokens,
        verified_baseline_tokens,
    );
    let excluded_breakdown = build_excluded_breakdown(contract, &excluded_events);

    json!({
        "events_total": events.len(),
        "events_count": events.len(),
        "live_events_count": live_events_count,
        "non_live_events_count": non_live_events_count,
        "counted_events": verified_events.len(),
        "task_success_like_counted_events": task_like_events.len(),
        "answer_like_counted_events": answer_like_events.len(),
        "legacy_unverified_events": legacy_unverified_events,
        "preliminary": preliminary,
        "baseline_tokens": total_naive_tokens,
        "delivered_tokens": total_context_tokens,
        "recovery_tokens": total_recovery_tokens,
        "observed_client_prompt_tokens": observed_client_prompt_tokens,
        "observed_assistant_generation_tokens": observed_assistant_generation_tokens,
        "observed_tool_overhead_tokens": observed_tool_overhead_tokens,
        "observed_continuity_restore_tokens": observed_continuity_restore_tokens,
        "observed_client_prompt_live_events": observed_client_prompt_live_events,
        "observed_assistant_generation_live_events": observed_assistant_generation_live_events,
        "observed_tool_overhead_live_events": observed_tool_overhead_live_events,
        "observed_continuity_restore_live_events": observed_continuity_restore_live_events,
        "observed_whole_cycle_with_amai_tokens": observed_whole_cycle_with_amai_tokens,
        "verified_observed_whole_cycle_with_amai_tokens": verified_observed_whole_cycle_with_amai_tokens,
        "effective_saved_tokens": total_effective_saved_tokens,
        "total_saved_tokens": total_saved_tokens,
        "total_effective_saved_tokens": total_effective_saved_tokens,
        "verified_effective_saved_tokens": verified_effective_saved_tokens,
        "verified_baseline_tokens": verified_baseline_tokens,
        "verified_delivered_tokens": verified_delivered_tokens,
        "verified_recovery_tokens": verified_recovery_tokens,
        "verified_task_like_saved_tokens": verified_task_like_saved_tokens,
        "verified_answer_like_saved_tokens": verified_answer_like_saved_tokens,
        "excluded_events_count": excluded_events.len(),
        "excluded_effective_saved_tokens": excluded_effective_saved_tokens,
        "excluded_baseline_tokens": excluded_baseline_tokens,
        "excluded_delivered_tokens": excluded_delivered_tokens,
        "excluded_recovery_tokens": excluded_recovery_tokens,
        "total_naive_tokens": total_naive_tokens,
        "total_context_tokens": total_context_tokens,
        "total_recovery_tokens": total_recovery_tokens,
        "gross_savings_pct": gross_savings_pct,
        "effective_savings_pct": effective_savings_pct,
        "verified_effective_savings_pct": verified_effective_savings_pct,
        "verified_task_like_savings_pct": verified_task_like_savings_pct,
        "verified_answer_like_savings_pct": verified_answer_like_savings_pct,
        "savings_percent": gross_savings_pct,
        "savings_factor": savings_factor,
        "avg_saved_tokens_per_event": avg_saved_tokens_per_event,
        "quality_ok_rate": quality_ok_rate,
        "task_success_like_rate": task_success_like_rate,
        "answer_like_rate": answer_like_rate,
        "fallback_rate": fallback_rate,
        "median_recovery_tokens": median_recovery_tokens,
        "sample_count": latency_sample_count,
        "current_latency_ms": current_latency_ms,
        "p50_latency_ms": p50_latency_ms,
        "p95_latency_ms": p95_latency_ms,
        "p99_latency_ms": p99_latency_ms,
        "max_latency_ms": max_latency_ms,
        "latency_slices": latency_slice_breakdown(events),
        "started_at_epoch_ms": started_at_epoch_ms,
        "ended_at_epoch_ms": ended_at_epoch_ms,
        "age_ms_since_latest": now_epoch_ms.saturating_sub(ended_at_epoch_ms),
        "coverage": coverage,
        "excluded_breakdown": excluded_breakdown,
    })
}

fn build_coverage_summary(
    contract: &TokenBudgetContractConfig,
    measured_events: u64,
    included_events: u64,
    excluded_events: u64,
    measured_baseline_tokens: u64,
    included_baseline_tokens: u64,
) -> Value {
    let excluded_baseline_tokens =
        measured_baseline_tokens.saturating_sub(included_baseline_tokens);
    let event_coverage_pct = percent_share(included_events, measured_events);
    let baseline_token_coverage_pct =
        percent_share(included_baseline_tokens, measured_baseline_tokens);
    let completeness_state = if measured_events == 0 {
        "empty"
    } else if included_events == 0 {
        "no_confirmed_usage"
    } else if included_events == measured_events {
        "fully_confirmed"
    } else {
        "partially_confirmed"
    };
    json!({
        "model_version": contract.coverage_model_version.clone(),
        "completeness_state": completeness_state,
        "measured_events": measured_events,
        "included_events": included_events,
        "excluded_events": excluded_events,
        "event_coverage_pct": event_coverage_pct,
        "measured_baseline_tokens": measured_baseline_tokens,
        "included_baseline_tokens": included_baseline_tokens,
        "excluded_baseline_tokens": excluded_baseline_tokens,
        "baseline_token_coverage_pct": baseline_token_coverage_pct,
    })
}

fn build_excluded_breakdown(
    contract: &TokenBudgetContractConfig,
    excluded_events: &[&TokenBudgetEvent],
) -> Value {
    let mut grouped = BTreeMap::<String, (u64, u64, u64, u64, i64)>::new();
    for event in excluded_events {
        let code = excluded_event_code(event).to_string();
        let entry = grouped.entry(code).or_insert((0, 0, 0, 0, 0));
        entry.0 = entry.0.saturating_add(1);
        entry.1 = entry.1.saturating_add(event.naive_tokens);
        entry.2 = entry.2.saturating_add(event.context_tokens);
        entry.3 = entry.3.saturating_add(event.recovery_tokens);
        entry.4 = entry.4.saturating_add(event.effective_saved_tokens);
    }
    let items = grouped
        .into_iter()
        .map(
            |(
                code,
                (
                    events_count,
                    baseline_tokens,
                    delivered_tokens,
                    recovery_tokens,
                    effective_saved_tokens,
                ),
            )| {
                json!({
                    "code": code,
                    "label": excluded_event_label(&code),
                    "events_count": events_count,
                    "baseline_tokens": baseline_tokens,
                    "delivered_tokens": delivered_tokens,
                    "recovery_tokens": recovery_tokens,
                    "effective_saved_tokens": effective_saved_tokens,
                })
            },
        )
        .collect::<Vec<_>>();
    json!({
        "model_version": contract.excluded_taxonomy_version.clone(),
        "items": items,
    })
}

fn excluded_event_code(event: &TokenBudgetEvent) -> &'static str {
    match event.traffic_class.as_str() {
        "verify" => "synthetic_verify",
        "proof" => "synthetic_proof",
        "benchmark" => "synthetic_benchmark",
        "live" => {
            if event.quality_method == "legacy_unverified" {
                "legacy_unverified"
            } else if event.needed_followup && event.resolved_by_event_id.is_none() {
                "awaiting_followup_reconciliation"
            } else {
                "quality_gate_failed"
            }
        }
        _ => "non_live_other",
    }
}

fn excluded_event_label(code: &str) -> &'static str {
    match code {
        "synthetic_verify" => "engineering verify-событие",
        "synthetic_proof" => "engineering proof-событие",
        "synthetic_benchmark" => "benchmark-событие",
        "legacy_unverified" => "старое live-событие без quality-блока",
        "awaiting_followup_reconciliation" => "ожидает полезного follow-up или подтверждения",
        "quality_gate_failed" => "не прошло quality gate",
        _ => "другое исключённое событие",
    }
}

#[cfg(test)]
fn build_product_headline(
    summary: &Value,
    scope_label: &str,
    client_limit_boundary_semantics: Option<&Value>,
) -> Value {
    build_product_headline_with_target(
        summary,
        scope_label,
        client_limit_boundary_semantics,
        working_state::default_client_budget_target_percent(),
    )
}

fn build_product_headline_with_target(
    summary: &Value,
    scope_label: &str,
    client_limit_boundary_semantics: Option<&Value>,
    client_budget_target_percent: u64,
) -> Value {
    let events_total = summary["events_total"].as_u64().unwrap_or(0);
    let counted_events = summary["counted_events"].as_u64().unwrap_or(0);
    let legacy_unverified_events = summary["legacy_unverified_events"].as_u64().unwrap_or(0);
    let preliminary = summary["preliminary"].as_bool().unwrap_or(true);
    let verified_percent = summary["verified_effective_savings_pct"]
        .as_f64()
        .unwrap_or(0.0);
    let effective_percent = summary["effective_savings_pct"].as_f64().unwrap_or(0.0);
    let verified_saved_tokens = summary["verified_effective_saved_tokens"]
        .as_i64()
        .unwrap_or(0);
    let effective_saved_tokens = summary["total_effective_saved_tokens"]
        .as_i64()
        .unwrap_or(0);
    let quality_ok_rate = summary["quality_ok_rate"].as_f64().unwrap_or(0.0);
    let fallback_rate = summary["fallback_rate"].as_f64().unwrap_or(0.0);
    let same_meter_exact_pair = product_headline_same_meter_exact_pair(summary);
    let status_bar_correlated = same_meter_exact_pair.is_some();
    let target_percent = client_budget_target_percent as f64;
    let target_active = client_budget_target_percent > 0;
    let same_meter_value_percent = same_meter_exact_pair.map(|(_, pct)| pct);
    let same_meter_saved_tokens = same_meter_exact_pair.map(|(saved_tokens, _)| saved_tokens);
    let below_status_bar_target =
        target_active && same_meter_value_percent.is_some_and(|value| value < target_percent);
    let client_limit_boundary_semantics =
        client_limit_boundary_semantics.cloned().unwrap_or_else(|| {
            if summary["client_limit_meter_alignment"].is_object() {
                build_client_limit_boundary_review_surface(summary)
            } else {
                Value::Null
            }
        });
    let boundary_note = match client_limit_boundary_semantics["review_state"]
        .as_str()
        .unwrap_or("client_limit_boundary_review_unknown")
    {
        "strict_slice_plus_observed_amai_continuity_boundary" => Some(
            "При этом headline не равен клиентскому лимиту: measured strict slice уже materialized, а observed Amai continuity boundary вынесена отдельно.",
        ),
        "strict_slice_plus_empty_amai_continuity_boundary" => Some(
            "При этом headline не равен клиентскому лимиту: explicit Amai continuity boundary уже объявлена отдельно, но в текущем scope у неё ещё нет observed token weight.",
        ),
        "amai_continuity_boundary_present" => Some(
            "При этом headline не равен клиентскому лимиту: в scope остаётся explicit Amai continuity boundary вне strict client-meter slice.",
        ),
        "strict_slice_partial_without_explicit_boundary" => Some(
            "При этом headline не должен читаться как полный client-limit meter: strict same-meter slice пока покрывает только часть applicable components.",
        ),
        _ => None,
    };
    let frozen_gap_note = if client_limit_boundary_semantics["frozen_gap_review_surface"]["state"]
        .as_str()
        == Some("review_required")
    {
        Some(
            "Raw exact history здесь дополнительно unavailable: irrecoverable historical debt уже требует отдельного frozen-gap review.",
        )
    } else {
        None
    };
    let annotate_note = |base: &str| -> String {
        let mut note = base.to_string();
        if let Some(extra) = boundary_note {
            note.push(' ');
            note.push_str(extra);
        }
        if let Some(extra) = frozen_gap_note {
            note.push(' ');
            note.push_str(extra);
        }
        note
    };
    let below_target_note = format!(
        "Это exact same-meter метрика, коррелирующая с VS Code status bar. Текущая экономия реальных токенов модели пользователя остаётся ниже целевой планки {}%.",
        client_budget_target_percent
    );

    if counted_events > 0 {
        json!({
            "metric_code": "verified_effective_savings_pct",
            "title": "Проверенная реальная экономия",
            "scope_label": scope_label,
            "status": if preliminary || below_status_bar_target { "alert" } else { "pass" },
            "preliminary": preliminary,
            "value_percent": same_meter_value_percent.unwrap_or(verified_percent),
            "saved_tokens": same_meter_saved_tokens.unwrap_or(verified_saved_tokens),
            "events_count": events_total,
            "counted_events": counted_events,
            "quality_ok_rate": quality_ok_rate,
            "fallback_rate": fallback_rate,
            "client_meter_status_bar_correlated": status_bar_correlated,
            "client_meter_target_percent": target_percent,
            "client_meter_target_met": status_bar_correlated && !below_status_bar_target,
            "client_limit_boundary_semantics": client_limit_boundary_semantics,
            "note": annotate_note(if preliminary {
                if status_bar_correlated {
                    "Это уже quality-gated exact same-meter метрика, коррелирующая с VS Code status bar, но выборка пока ещё маленькая."
                } else {
                    "Это уже quality-gated метрика, но выборка пока ещё маленькая."
                }
            } else if below_status_bar_target {
                below_target_note.as_str()
            } else if status_bar_correlated {
                "Это главный честный KPI: exact same-meter, quality-gated, коррелирует с VS Code status bar и показывает реальную экономию токенов модели пользователя."
            } else {
                "Это главный честный KPI: live-only, quality-gated и с учётом recovery."
            }),
        })
    } else if status_bar_correlated {
        json!({
            "metric_code": "exact_same_meter_effective_savings_pct",
            "title": "Реальная экономия по exact same-meter",
            "scope_label": scope_label,
            "status": if below_status_bar_target { "alert" } else { "pass" },
            "preliminary": false,
            "value_percent": same_meter_value_percent.unwrap_or(effective_percent),
            "saved_tokens": same_meter_saved_tokens.unwrap_or(effective_saved_tokens),
            "events_count": events_total,
            "counted_events": counted_events,
            "quality_ok_rate": quality_ok_rate,
            "fallback_rate": fallback_rate,
            "client_meter_status_bar_correlated": true,
            "client_meter_target_percent": target_percent,
            "client_meter_target_met": !below_status_bar_target,
            "client_limit_boundary_semantics": client_limit_boundary_semantics,
            "note": annotate_note(if below_status_bar_target {
                below_target_note.as_str()
            } else {
                "Это exact same-meter метрика, коррелирующая с VS Code status bar. В этом scope truthful client-limit equivalence уже materialized по whole-cycle component semantics, даже если retrieval quality-gated confirmed lane ещё пуст."
            }),
        })
    } else if events_total > 0 {
        json!({
            "metric_code": "effective_savings_pct_preliminary",
            "title": "Реальная экономия пока предварительно",
            "scope_label": scope_label,
            "status": "alert",
            "preliminary": true,
            "value_percent": effective_percent,
            "saved_tokens": effective_saved_tokens,
            "events_count": events_total,
            "counted_events": counted_events,
            "quality_ok_rate": quality_ok_rate,
            "fallback_rate": fallback_rate,
            "client_limit_boundary_semantics": client_limit_boundary_semantics,
            "note": annotate_note(if legacy_unverified_events > 0 {
                "Проверенная выборка ещё не набрана: часть исторических live-событий была записана старым форматом без quality-блока, поэтому пока показывается общая реальная экономия."
            } else {
                "Проверенная выборка ещё не набрана, поэтому временно показывается общая реальная экономия по live-событиям."
            }),
        })
    } else {
        json!({
            "metric_code": "no_live_events",
            "title": "Реальная экономия пока не накоплена",
            "scope_label": scope_label,
            "status": "unknown",
            "preliminary": true,
            "value_percent": 0.0,
            "saved_tokens": 0,
            "events_count": 0,
            "counted_events": 0,
            "quality_ok_rate": 0.0,
            "fallback_rate": 0.0,
            "client_limit_boundary_semantics": client_limit_boundary_semantics,
            "note": annotate_note("Amai ещё не накопил live-события для этой метрики."),
        })
    }
}

fn product_headline_same_meter_exact_pair(summary: &Value) -> Option<(i64, f64)> {
    let alignment = &summary["client_limit_meter_alignment"];
    if alignment["same_meter_as_client_limit"].as_bool() != Some(true) {
        return None;
    }
    let without_amai = alignment["strict_client_meter_slice"]["lower_bound_tokens"]
        .as_u64()
        .or_else(|| {
            alignment["baseline_equivalence"]["measured_baseline_tokens_lower_bound"].as_u64()
        })
        .or_else(|| summary["verified_without_amai_measured_tokens"].as_u64())
        .or_else(|| summary["verified_baseline_tokens"].as_u64())?;
    let with_amai = summary["observed_whole_cycle_with_amai_tokens"]
        .as_u64()
        .or_else(|| summary["verified_observed_whole_cycle_with_amai_tokens"].as_u64())
        .or_else(|| summary["verified_with_amai_measured_tokens"].as_u64())
        .or_else(|| summary["with_amai_measured_tokens"].as_u64())?;
    if without_amai == 0 {
        return None;
    }
    let saved_tokens = without_amai as i64 - with_amai as i64;
    let value_percent = saved_tokens as f64 * 100.0 / without_amai as f64;
    Some((saved_tokens, value_percent))
}

#[cfg(test)]
fn scope_same_meter_exact_pair(scope_summary: &Value) -> Option<(u64, u64, i64, f64)> {
    let alignment = &scope_summary["client_limit_meter_alignment"];
    if alignment["same_meter_as_client_limit"].as_bool() != Some(true) {
        return None;
    }
    let without_amai = alignment["strict_client_meter_slice"]["lower_bound_tokens"]
        .as_u64()
        .or_else(|| {
            alignment["baseline_equivalence"]["measured_baseline_tokens_lower_bound"].as_u64()
        })
        .or_else(|| scope_summary["verified_without_amai_measured_tokens"].as_u64())
        .or_else(|| scope_summary["verified_baseline_tokens"].as_u64())?;
    let with_amai = scope_summary["observed_whole_cycle_with_amai_tokens"]
        .as_u64()
        .or_else(|| scope_summary["verified_observed_whole_cycle_with_amai_tokens"].as_u64())
        .or_else(|| scope_summary["verified_with_amai_measured_tokens"].as_u64())
        .or_else(|| scope_summary["with_amai_measured_tokens"].as_u64())?;
    if without_amai == 0 {
        return None;
    }
    let saved_tokens = without_amai as i64 - with_amai as i64;
    let saved_pct = saved_tokens as f64 * 100.0 / without_amai as f64;
    Some((without_amai, with_amai, saved_tokens, saved_pct))
}

fn current_live_turn_alignment_component<'a>(
    scope_summary: &'a Value,
    code: &str,
) -> Option<&'a Value> {
    scope_summary["client_limit_meter_alignment"]["baseline_equivalence"]["component_semantics"]
        .as_array()
        .into_iter()
        .flatten()
        .find(|item| item["code"].as_str() == Some(code))
}

fn current_live_turn_full_turn_exact_pair(
    scope_summary: &Value,
    observation: &codex_threads::RolloutClientMeterObservation,
) -> Option<(u64, u64, i64, f64)> {
    let with_amai_total_tokens = observation.client_turn_total_tokens;
    if with_amai_total_tokens == 0 {
        return None;
    }

    let retrieval_without_amai_tokens = scope_summary["without_amai_measured_tokens"].as_u64()?;
    let retrieval_with_amai_tokens = scope_summary["with_amai_measured_tokens"].as_u64()?;
    let observed_tool_overhead_tokens = scope_summary["observed_tool_overhead_tokens"]
        .as_u64()
        .unwrap_or(0);
    let observed_continuity_restore_tokens = scope_summary["observed_continuity_restore_tokens"]
        .as_u64()
        .unwrap_or(0);

    if let Some(component) =
        current_live_turn_alignment_component(scope_summary, "tool_overhead_outside_retrieval")
    {
        let target_live_events = component["target_live_events_count"].as_u64().unwrap_or(0);
        if target_live_events > 0
            && component["whole_cycle_observed_complete"].as_bool() != Some(true)
        {
            return None;
        }
    }

    let continuity_without_amai_tokens = if observed_continuity_restore_tokens == 0 {
        0
    } else {
        let component = current_live_turn_alignment_component(
            scope_summary,
            "continuity_restore_outside_retrieval",
        )?;
        if component["whole_cycle_observed_complete"].as_bool() != Some(true) {
            return None;
        }
        component["baseline_measured_tokens"].as_u64()?
    };

    let saved_tokens = retrieval_without_amai_tokens as i64
        - retrieval_with_amai_tokens as i64
        - observed_tool_overhead_tokens as i64
        + continuity_without_amai_tokens as i64
        - observed_continuity_restore_tokens as i64;
    let without_amai_total_tokens = if saved_tokens >= 0 {
        with_amai_total_tokens.saturating_add(saved_tokens as u64)
    } else {
        with_amai_total_tokens.saturating_sub(saved_tokens.unsigned_abs())
    };
    if without_amai_total_tokens == 0 {
        return None;
    }
    let saved_pct = saved_tokens as f64 * 100.0 / without_amai_total_tokens as f64;
    Some((
        without_amai_total_tokens,
        with_amai_total_tokens,
        saved_tokens,
        saved_pct,
    ))
}

fn client_limit_meter_alignment_counts(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
) -> (u64, u64, u64, u64) {
    let events_total = summary["events_total"]
        .as_u64()
        .or_else(|| events.map(|items| items.len() as u64))
        .unwrap_or(0);
    let live_events_count = summary["live_events_count"]
        .as_u64()
        .or_else(|| {
            events.map(|items| {
                items
                    .iter()
                    .filter(|event| event.traffic_class == "live")
                    .count() as u64
            })
        })
        .unwrap_or(0);
    let non_live_events_count = summary["non_live_events_count"]
        .as_u64()
        .or_else(|| events_total.checked_sub(live_events_count))
        .unwrap_or(0);
    let counted_events = summary["meter_counted_events"]
        .as_u64()
        .or_else(|| summary["counted_events"].as_u64())
        .or_else(|| {
            events.map(|items| {
                items
                    .iter()
                    .filter(|event| event.traffic_class == "live" && event.quality_ok)
                    .count() as u64
            })
        })
        .unwrap_or(0);
    (
        events_total,
        live_events_count,
        non_live_events_count,
        counted_events,
    )
}

fn tool_overhead_observed_stats(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> (u64, u64) {
    let Some(events) = events else {
        return (
            summary["observed_tool_overhead_live_events"]
                .as_u64()
                .unwrap_or(0),
            summary["observed_tool_overhead_tokens"]
                .as_u64()
                .unwrap_or(0),
        );
    };
    let target_events = tool_overhead_target_events(events, assistant_scope);
    let observed_live_events = target_events
        .iter()
        .filter(|event| event.tool_overhead_tokens.is_some())
        .count() as u64;
    let observed_tokens = target_events
        .iter()
        .filter_map(|event| event.tool_overhead_tokens)
        .sum::<u64>();
    (observed_live_events, observed_tokens)
}

fn client_limit_component_stats(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> [(&'static str, u64, u64); 4] {
    let (observed_tool_overhead_live_events, observed_tool_overhead_tokens) =
        tool_overhead_observed_stats(summary, events, assistant_scope);
    [
        (
            "client_prompt",
            summary["observed_client_prompt_live_events"]
                .as_u64()
                .unwrap_or(0),
            summary["observed_client_prompt_tokens"]
                .as_u64()
                .unwrap_or(0),
        ),
        (
            "assistant_generation",
            assistant_scope
                .map(|scope| scope.observed_group_count)
                .unwrap_or_else(|| {
                    summary["observed_assistant_generation_live_events"]
                        .as_u64()
                        .unwrap_or(0)
                }),
            assistant_scope
                .map(|scope| scope.observed_tokens)
                .unwrap_or_else(|| {
                    summary["observed_assistant_generation_tokens"]
                        .as_u64()
                        .unwrap_or(0)
                }),
        ),
        (
            "tool_overhead_outside_retrieval",
            observed_tool_overhead_live_events,
            observed_tool_overhead_tokens,
        ),
        (
            "continuity_restore_outside_retrieval",
            summary["observed_continuity_restore_live_events"]
                .as_u64()
                .unwrap_or(0),
            summary["observed_continuity_restore_tokens"]
                .as_u64()
                .unwrap_or(0),
        ),
    ]
}

fn client_limit_component_target_scope_kind(code: &str) -> &'static str {
    match code {
        "client_prompt" => "all_live_scope",
        "assistant_generation" => "assistant_generation_turn_scope",
        "tool_overhead_outside_retrieval" => "retrieval_live_scope",
        "continuity_restore_outside_retrieval" => "continuity_restore_live_scope",
        _ => "all_live_scope",
    }
}

fn is_client_limit_component_target_event(code: &str, event: &TokenBudgetEvent) -> bool {
    if event.traffic_class != "live" {
        return false;
    }
    match code {
        "client_prompt" => true,
        "assistant_generation" | "tool_overhead_outside_retrieval" => {
            event.measurement_scope == "retrieval_lower_bound"
        }
        "continuity_restore_outside_retrieval" => {
            event.measurement_scope == "whole_cycle_observed_lower_bound"
                && (event.query_type == "continuity_restore"
                    || event.target_kind == "continuity_restore")
        }
        _ => false,
    }
}

fn client_limit_component_target_live_events(
    code: &str,
    events: Option<&[TokenBudgetEvent]>,
    live_events_count: u64,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> u64 {
    if code == "assistant_generation" {
        return assistant_scope
            .map(|scope| scope.target_group_count)
            .unwrap_or_else(|| {
                events
                    .map(|items| {
                        items
                            .iter()
                            .filter(|event| is_client_limit_component_target_event(code, event))
                            .count() as u64
                    })
                    .unwrap_or(live_events_count)
            });
    }
    events
        .map(|items| {
            items
                .iter()
                .filter(|event| {
                    if !is_client_limit_component_target_event(code, event) {
                        return false;
                    }
                    if code != "tool_overhead_outside_retrieval" {
                        return true;
                    }
                    if is_legacy_continuity_bootstrap_context_pack(event) {
                        return false;
                    }
                    let Some(scope) = assistant_scope else {
                        return true;
                    };
                    let Some(context_pack_id) = event_context_pack_id(event) else {
                        return true;
                    };
                    !(scope
                        .helper_only_non_model_visible_context_pack_ids
                        .contains(&context_pack_id)
                        && !event_has_model_visible_with_amai_tokens(event))
                })
                .count() as u64
        })
        .unwrap_or(live_events_count)
}

fn tool_overhead_target_events<'a>(
    events: &'a [TokenBudgetEvent],
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Vec<&'a TokenBudgetEvent> {
    events
        .iter()
        .filter(|event| {
            if !is_client_limit_component_target_event("tool_overhead_outside_retrieval", event) {
                return false;
            }
            if is_legacy_continuity_bootstrap_context_pack(event) {
                return false;
            }
            let Some(scope) = assistant_scope else {
                return true;
            };
            let Some(context_pack_id) = event_context_pack_id(event) else {
                return true;
            };
            !(scope
                .helper_only_non_model_visible_context_pack_ids
                .contains(&context_pack_id)
                && !event_has_model_visible_with_amai_tokens(event))
        })
        .collect()
}

fn tool_overhead_observation_source_status(
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    let Some(events) = events else {
        return json!({
            "source_kind": "context_pack_payload_attach_v1",
            "state": "tool_overhead_scope_unavailable",
            "target_live_events": 0,
            "observed_live_events": 0,
            "missing_live_events": 0,
            "missing_class_sample": [],
            "missing_context_pack_id_sample": [],
            "note": "Без live events этот слой не может показать, какие retrieval context packs ещё не получили tool_overhead whole-cycle attach."
        });
    };
    let target_events = tool_overhead_target_events(events, assistant_scope);
    let observed_live_events = target_events
        .iter()
        .filter(|event| event.tool_overhead_tokens.is_some())
        .count() as u64;
    let missing_events = target_events
        .iter()
        .filter(|event| event.tool_overhead_tokens.is_none())
        .copied()
        .collect::<Vec<_>>();
    let mut missing_source_states = BTreeMap::<String, u64>::new();
    let mut missing_classes = BTreeMap::<(String, String, String, String), u64>::new();
    for event in &missing_events {
        let key = (
            event.source_kind.clone(),
            event.namespace.clone(),
            event.query_type.clone(),
            event.target_kind.clone(),
        );
        *missing_classes.entry(key).or_default() += 1;
        let state = event
            .tool_overhead_source
            .as_ref()
            .and_then(|value| value["state"].as_str())
            .unwrap_or("source_state_unknown")
            .to_string();
        *missing_source_states.entry(state).or_default() += 1;
    }
    let mut missing_class_sample = missing_classes
        .into_iter()
        .map(
            |((source_kind, namespace, query_type, target_kind), count)| {
                json!({
                    "source_kind": source_kind,
                    "namespace": namespace,
                    "query_type": query_type,
                    "target_kind": target_kind,
                    "count": count,
                })
            },
        )
        .collect::<Vec<_>>();
    missing_class_sample.sort_by(|left, right| {
        right["count"]
            .as_u64()
            .cmp(&left["count"].as_u64())
            .then_with(|| {
                left["source_kind"]
                    .as_str()
                    .cmp(&right["source_kind"].as_str())
            })
            .then_with(|| left["namespace"].as_str().cmp(&right["namespace"].as_str()))
            .then_with(|| {
                left["query_type"]
                    .as_str()
                    .cmp(&right["query_type"].as_str())
            })
            .then_with(|| {
                left["target_kind"]
                    .as_str()
                    .cmp(&right["target_kind"].as_str())
            })
    });
    let mut missing_source_state_sample = missing_source_states
        .into_iter()
        .map(|(state, count)| {
            json!({
                "state": state,
                "count": count,
            })
        })
        .collect::<Vec<_>>();
    missing_source_state_sample.sort_by(|left, right| {
        right["count"]
            .as_u64()
            .cmp(&left["count"].as_u64())
            .then_with(|| left["state"].as_str().cmp(&right["state"].as_str()))
    });
    let irrecoverable_missing_live_events = missing_events
        .iter()
        .filter(|event| {
            event
                .tool_overhead_source
                .as_ref()
                .and_then(|value| value["state"].as_str())
                .is_some_and(is_irrecoverable_tool_overhead_source_state)
        })
        .count() as u64;
    let recoverable_missing_live_events =
        (missing_events.len() as u64).saturating_sub(irrecoverable_missing_live_events);
    let recoverability_state = if missing_events.is_empty() {
        "not_applicable"
    } else if irrecoverable_missing_live_events == 0 {
        "missing_scope_recoverability_unknown"
    } else if irrecoverable_missing_live_events == missing_events.len() as u64 {
        "source_loss_irrecoverable"
    } else {
        "mixed_recoverable_and_irrecoverable"
    };
    let gap_semantics = if target_events.is_empty() {
        "not_applicable"
    } else if missing_events.is_empty() {
        "fully_materialized"
    } else if irrecoverable_missing_live_events == 0 {
        "recoverable_measurement_lag_only"
    } else if recoverable_missing_live_events == 0 {
        "irrecoverable_historical_debt_only"
    } else {
        "mixed_measurement_lag_and_irrecoverable_debt"
    };

    json!({
        "source_kind": "context_pack_payload_attach_v1",
        "state": if target_events.is_empty() {
            "no_tool_overhead_target_scope"
        } else if missing_events.is_empty() {
            "tool_overhead_source_covers_missing_scope"
        } else if irrecoverable_missing_live_events == missing_events.len() as u64 {
            "tool_overhead_irrecoverable_debt_only"
        } else {
            "tool_overhead_source_partial_scope_overlap"
        },
        "target_live_events": target_events.len(),
        "observed_live_events": observed_live_events,
        "missing_live_events": missing_events.len(),
        "recoverability_state": recoverability_state,
        "gap_semantics": gap_semantics,
        "irrecoverable_missing_live_events": irrecoverable_missing_live_events,
        "recoverable_missing_live_events": recoverable_missing_live_events,
        "missing_source_state_sample": missing_source_state_sample.into_iter().take(8).collect::<Vec<_>>(),
        "missing_class_sample": missing_class_sample.into_iter().take(8).collect::<Vec<_>>(),
        "missing_context_pack_id_sample": missing_events
            .iter()
            .filter_map(|event| event_context_pack_id(event))
            .take(8)
            .collect::<Vec<_>>(),
        "note": "Этот слой показывает, какие retrieval live events ещё не получили whole-cycle tool_overhead attach после payload-based sync, как они сгруппированы по классам, и есть ли среди них irrecoverable source-loss без stored context pack payload."
    })
}

fn client_limit_component_event_coverage(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    live_events_count: u64,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Vec<Value> {
    client_limit_component_stats(summary, events, assistant_scope)
        .into_iter()
        .map(|(code, observed_live_events, observed_tokens)| {
            let target_live_events_count = client_limit_component_target_live_events(
                code,
                events,
                live_events_count,
                assistant_scope,
            );
            json!({
                "code": code,
                "observed_live_events": observed_live_events,
                "live_events_count": live_events_count,
                "target_live_events_count": target_live_events_count,
                "target_scope_kind": client_limit_component_target_scope_kind(code),
                "target_scope_applicable": target_live_events_count > 0,
                "event_coverage_pct": percent_share(observed_live_events, target_live_events_count),
                "observed_tokens": observed_tokens,
            })
        })
        .collect()
}

fn client_limit_meter_alignment_blocking_reasons(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Vec<String> {
    let mut reasons = Vec::new();
    let (events_total, live_events_count, non_live_events_count, counted_events) =
        client_limit_meter_alignment_counts(summary, events);
    for (code, observed_live_events, _observed_tokens) in
        client_limit_component_stats(summary, events, assistant_scope)
    {
        let target_live_events = client_limit_component_target_live_events(
            code,
            events,
            live_events_count,
            assistant_scope,
        );
        if target_live_events == 0 {
            continue;
        }
        if observed_live_events == 0 {
            reasons.push(format!("{code}_unmeasured"));
        } else if observed_live_events < target_live_events {
            reasons.push(format!("{code}_partially_measured"));
        }
    }

    if events_total == 0 {
        reasons.push("no_usage_observed_in_scope".to_string());
    } else {
        if live_events_count == 0 {
            reasons.push("no_live_usage_in_scope".to_string());
        }
        if non_live_events_count > 0 {
            reasons.push("non_live_events_present_in_scope".to_string());
        }
        if live_events_count > 0 && counted_events == 0 {
            reasons.push("no_confirmed_live_usage_in_scope".to_string());
        }
    }
    reasons
}

fn client_limit_meter_alignment_state(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
    baseline_equivalence: &Value,
    same_meter_as_client_limit: bool,
) -> &'static str {
    let (events_total, live_events_count, _non_live_events_count, counted_events) =
        client_limit_meter_alignment_counts(summary, events);
    let component_stats = client_limit_component_stats(summary, events, assistant_scope);
    let any_component_applicable =
        component_stats
            .iter()
            .any(|(code, _observed_live_events, _observed_tokens)| {
                client_limit_component_target_live_events(
                    code,
                    events,
                    live_events_count,
                    assistant_scope,
                ) > 0
            });
    let all_components_observed = live_events_count > 0
        && component_stats
            .iter()
            .all(|(code, observed_live_events, _observed_tokens)| {
                let target_live_events = client_limit_component_target_live_events(
                    code,
                    events,
                    live_events_count,
                    assistant_scope,
                );
                target_live_events == 0 || *observed_live_events == target_live_events
            });
    let any_component_observed = component_stats
        .iter()
        .any(|(_code, observed_live_events, _observed_tokens)| *observed_live_events > 0);

    if same_meter_as_client_limit {
        "same_meter_equivalent"
    } else if events_total == 0 {
        "no_usage_observed"
    } else if live_events_count == 0 {
        "only_non_live_scope_activity"
    } else if counted_events == 0 {
        "live_usage_unconfirmed_not_meter_equivalent"
    } else if any_component_applicable && all_components_observed {
        if baseline_equivalence["state"].as_str()
            == Some("baseline_component_semantics_explicit_boundary")
        {
            "whole_cycle_observed_explicit_boundary_not_meter_equivalent"
        } else {
            "whole_cycle_observed_baseline_partial"
        }
    } else if any_component_observed {
        "whole_cycle_partially_observed_not_meter_equivalent"
    } else {
        "partial_lower_bound_not_meter_equivalent"
    }
}

fn assistant_generation_missing_scope_context_pack_ids(
    events: Option<&[TokenBudgetEvent]>,
) -> BTreeSet<String> {
    events
        .into_iter()
        .flatten()
        .filter(|event| {
            event.traffic_class == "live"
                && event.measurement_scope == "retrieval_lower_bound"
                && event_has_model_visible_with_amai_tokens(event)
                && !is_legacy_continuity_bootstrap_context_pack(event)
                && event.assistant_generation_tokens.is_none()
        })
        .filter_map(event_context_pack_id)
        .collect()
}

fn assistant_generation_observation_source_status(
    events: Option<&[TokenBudgetEvent]>,
    rollout_observations: Option<&[codex_threads::RolloutAssistantGenerationObservation]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    let target_ids = assistant_generation_missing_scope_context_pack_ids(events);
    if let Some(scope) = assistant_scope {
        let source_kind = match (
            scope.available_direct_turns > 0,
            scope.available_rollout_turns > 0,
        ) {
            (true, true) => "direct_turn_attach_plus_rollout_turn_timeline_v1",
            (true, false) => "direct_turn_attach_v1",
            (false, true) => "codex_rollout_turn_timeline_v1",
            (false, false) => "assistant_generation_source_unavailable_v1",
        };
        let state = if scope.target_context_pack_ids.is_empty() {
            "no_missing_live_retrieval_events"
        } else if scope.available_turns == 0 {
            "assistant_generation_source_unavailable"
        } else if scope.matched_context_pack_ids.is_empty() {
            "assistant_generation_source_no_scope_overlap"
        } else if !scope.unmatched_context_pack_ids.is_empty() {
            "assistant_generation_source_partial_scope_overlap"
        } else {
            "assistant_generation_source_covers_missing_scope"
        };
        return json!({
            "source_kind": source_kind,
            "state": state,
            "usable_turns": scope.available_turns,
            "usable_direct_turns": scope.available_direct_turns,
            "usable_rollout_turns": scope.available_rollout_turns,
            "matched_turn_ids": scope.matched_turn_ids.len(),
            "matched_direct_turn_ids": scope.matched_direct_turn_ids.len(),
            "matched_rollout_turn_ids": scope.matched_rollout_turn_ids.len(),
            "target_missing_context_pack_ids": scope.target_context_pack_ids.len(),
            "matched_context_pack_ids": scope.matched_context_pack_ids.len(),
            "unmatched_context_pack_ids": scope.unmatched_context_pack_ids.len(),
            "matched_context_pack_id_sample": scope.matched_context_pack_ids.iter().take(8).cloned().collect::<Vec<_>>(),
            "unmatched_context_pack_id_sample": scope.unmatched_context_pack_ids.iter().take(8).cloned().collect::<Vec<_>>(),
            "note": "Этот слой показывает, покрывают ли direct turn attach и rollout turn-timelines именно текущий live retrieval scope и можно ли честно привязать assistant_generation к turn-группам без дублирования токенов по каждому context pack."
        });
    }
    let available_ids = rollout_observations
        .into_iter()
        .flatten()
        .map(|observation| observation.context_pack_id.clone())
        .collect::<BTreeSet<_>>();
    let matched_ids = target_ids
        .intersection(&available_ids)
        .cloned()
        .collect::<Vec<_>>();
    let unmatched_ids = target_ids
        .difference(&available_ids)
        .cloned()
        .collect::<Vec<_>>();
    let state = if target_ids.is_empty() {
        "no_missing_live_retrieval_events"
    } else if available_ids.is_empty() {
        "assistant_generation_source_unavailable"
    } else if matched_ids.is_empty() {
        "assistant_generation_source_no_scope_overlap"
    } else if matched_ids.len() < target_ids.len() {
        "assistant_generation_source_partial_scope_overlap"
    } else {
        "assistant_generation_source_covers_missing_scope"
    };
    json!({
        "source_kind": "codex_rollout_last_token_usage_sum_v1",
        "state": state,
        "usable_rollout_context_pack_ids": available_ids.len(),
        "target_missing_context_pack_ids": target_ids.len(),
        "matched_context_pack_ids": matched_ids.len(),
        "unmatched_context_pack_ids": unmatched_ids.len(),
        "matched_context_pack_id_sample": matched_ids.into_iter().take(8).collect::<Vec<_>>(),
        "unmatched_context_pack_id_sample": unmatched_ids.into_iter().take(8).collect::<Vec<_>>(),
        "note": "Этот слой показывает не общий факт missing assistant_generation, а покрывает ли доступный source именно текущий live retrieval scope."
    })
}

fn client_limit_baseline_component_semantics(
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Vec<Value> {
    let (_events_total, live_events_count, _non_live_events_count, _counted_events) =
        client_limit_meter_alignment_counts(summary, events);
    let continuity_baseline_source = continuity_pre_amai_baseline_source_from_events(events);
    client_limit_component_stats(summary, events, assistant_scope)
        .into_iter()
        .filter_map(|(code, observed_live_events, observed_tokens)| {
            let target_live_events = client_limit_component_target_live_events(
                code,
                events,
                live_events_count,
                assistant_scope,
            );
            if target_live_events == 0 {
                return None;
            }
            let whole_cycle_observed_complete = observed_live_events == target_live_events;
            let (baseline_semantics_state, baseline_measured_tokens, note) =
                if !whole_cycle_observed_complete {
                    (
                        "whole_cycle_component_incomplete",
                        None,
                        "Observed whole-cycle coverage по этому компоненту ещё неполная, поэтому честный baseline-equivalent расчёт пока рано materialize-ить.".to_string(),
                    )
                } else {
                    match code {
                        "client_prompt" => (
                            "observed_tokens_passthrough",
                            Some(observed_tokens),
                            "Для client_prompt baseline-equivalent tokens совпадают с реально observed tokens: исходный пользовательский запрос к клиенту не меняется из-за Amai.".to_string(),
                        ),
                        "assistant_generation" => {
                            if assistant_scope.is_some() {
                                (
                                    "observed_tokens_passthrough",
                                    Some(observed_tokens),
                                    "Для assistant_generation baseline-equivalent tokens совпадают с реально observed turn-group tokens: это тот же самый model-visible output spend, уже собранный по deduplicated turn scope, а не guessed per-context-pack baseline."
                                        .to_string(),
                                )
                            } else {
                                (
                                    "baseline_semantics_unmaterialized",
                                    None,
                                    "Observed assistant_generation tokens уже есть, но без turn-group scope этот слой ещё не может честно доказать deduplicated model-output passthrough и therefore не materialize-ит exact baseline."
                                        .to_string(),
                                )
                            }
                        }
                        "tool_overhead_outside_retrieval" => (
                            "amai_only_zero_baseline",
                            Some(0),
                            "Для tool_overhead_outside_retrieval truthful pre-Amai baseline равен 0: этот model-visible orchestration spend появляется только из-за Amai вне retrieval payload и отсутствует в no-Amai path."
                                .to_string(),
                        ),
                        "continuity_restore_outside_retrieval" => {
                            if let Some((baseline_tokens, source_ref)) =
                                continuity_baseline_source.as_ref()
                            {
                                let source_kind = source_ref["source_kind"]
                                    .as_str()
                                    .unwrap_or(CONTINUITY_PRE_AMAI_BASELINE_STRATEGY);
                                (
                                    "truthful_pre_amai_baseline_source",
                                    Some(*baseline_tokens),
                                    format!(
                                        "Для continuity_restore_outside_retrieval truthful pre-Amai baseline source уже materialized через {source_kind}, поэтому этот компонент теперь можно считать baseline-equivalent без guessed boundary."
                                    ),
                                )
                            } else {
                                (
                                    "baseline_semantics_explicitly_unmodeled",
                                    None,
                                    "Continuity restore payload строится самим Amai continuity contour и сейчас не имеет truthful pre-Amai baseline-equivalent модели; этот gap должен оставаться явной границей, а не guessed baseline.".to_string(),
                                )
                            }
                        }
                        _ => (
                            "baseline_semantics_unmaterialized",
                            None,
                            "Observed tokens уже есть, но baseline-equivalent semantics для этого компонента ещё не materialized.".to_string(),
                        ),
                    }
                };
            Some(json!({
                "code": code,
                "observed_live_events": observed_live_events,
                "target_live_events_count": target_live_events,
                "whole_cycle_observed_complete": whole_cycle_observed_complete,
                "observed_tokens": observed_tokens,
                "baseline_semantics_state": baseline_semantics_state,
                "baseline_measured_tokens": baseline_measured_tokens,
                "note": note,
            }))
        })
        .collect()
}

fn build_client_limit_baseline_equivalence(
    contract: &TokenBudgetContractConfig,
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    let (_events_total, live_events_count, _non_live_events_count, counted_events) =
        client_limit_meter_alignment_counts(summary, events);
    let component_semantics =
        client_limit_baseline_component_semantics(summary, events, assistant_scope);
    let applicable_components = component_semantics
        .iter()
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let fully_observed_components = component_semantics
        .iter()
        .filter(|item| item["whole_cycle_observed_complete"].as_bool() == Some(true))
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let incomplete_components = component_semantics
        .iter()
        .filter(|item| item["whole_cycle_observed_complete"].as_bool() != Some(true))
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let measured_baseline_components = component_semantics
        .iter()
        .filter(|item| item["baseline_measured_tokens"].is_u64())
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let explicitly_unmodeled_baseline_components = component_semantics
        .iter()
        .filter(|item| {
            item["whole_cycle_observed_complete"].as_bool() == Some(true)
                && item["baseline_semantics_state"].as_str()
                    == Some("baseline_semantics_explicitly_unmodeled")
        })
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let missing_baseline_components = component_semantics
        .iter()
        .filter(|item| {
            item["whole_cycle_observed_complete"].as_bool() == Some(true)
                && item["baseline_semantics_state"].as_str()
                    != Some("baseline_semantics_explicitly_unmodeled")
                && !item["baseline_measured_tokens"].is_u64()
        })
        .filter_map(|item| item["code"].as_str().map(str::to_string))
        .collect::<Vec<_>>();
    let measured_baseline_tokens_lower_bound = component_semantics
        .iter()
        .filter_map(|item| item["baseline_measured_tokens"].as_u64())
        .sum::<u64>();
    let whole_cycle_components_fully_observed =
        !applicable_components.is_empty() && incomplete_components.is_empty();
    let same_meter_baseline_materialized = missing_baseline_components.is_empty()
        && explicitly_unmodeled_baseline_components.is_empty()
        && whole_cycle_components_fully_observed
        && measured_baseline_tokens_lower_bound > 0;
    let (state, remaining_gap_reason, note) = if live_events_count == 0 {
        (
            "no_live_scope",
            "no_live_usage_in_scope",
            "В этом scope ещё нет live usage, поэтому baseline-equivalent сравнение с клиентским лимитом пока не на чем строить.",
        )
    } else if !whole_cycle_components_fully_observed {
        (
            "whole_cycle_components_incomplete",
            "whole_cycle_components_incomplete",
            "Whole-cycle observed компоненты ещё покрывают не весь applicable live scope, поэтому baseline-equivalent semantics пока преждевременны.",
        )
    } else if same_meter_baseline_materialized && counted_events == 0 {
        (
            "baseline_semantics_materialized_without_quality_gate",
            "none",
            "Applicable whole-cycle components уже fully observed и baseline-equivalent measured для exact client-limit same-meter slice. Retrieval quality-gated confirmed lane здесь пустой, но truthful meter equivalence уже materialized по whole-cycle component semantics без guessed baseline.",
        )
    } else if same_meter_baseline_materialized {
        (
            "baseline_semantics_materialized",
            "none",
            "Applicable whole-cycle components уже и fully observed, и baseline-equivalent measured в текущем scope.",
        )
    } else if counted_events == 0 {
        (
            "live_scope_unconfirmed",
            "no_confirmed_live_usage_in_scope",
            "Live usage уже был, но confirmed lane ещё не набрался, поэтому baseline-equivalent метр пока нечем честно заякорить.",
        )
    } else if missing_baseline_components.is_empty()
        && !explicitly_unmodeled_baseline_components.is_empty()
    {
        (
            "baseline_component_semantics_explicit_boundary",
            "same_meter_baseline_explicit_boundary",
            "Applicable whole-cycle components уже полностью observed, но часть same-meter baseline contour оставлена как explicit truth-boundary без guessed pre-Amai baseline.",
        )
    } else if measured_baseline_components.is_empty() {
        (
            "baseline_semantics_unmaterialized",
            "same_meter_baseline_unmeasured",
            "Applicable whole-cycle components уже полностью observed, но отдельный baseline-equivalent слой для клиентского spend meter ещё не materialized.",
        )
    } else {
        (
            "baseline_component_semantics_partial",
            "same_meter_baseline_partially_measured",
            "Applicable whole-cycle components уже полностью observed, но baseline-equivalent semantics materialized только для части компонентов.",
        )
    };
    json!({
        "model_version": contract.client_limit_baseline_equivalence_version.clone(),
        "state": state,
        "same_meter_baseline_measured": same_meter_baseline_materialized,
        "baseline_equivalent_to_client_limit": same_meter_baseline_materialized,
        "retrieval_quality_gate_confirmed": counted_events > 0,
        "live_events_count": live_events_count,
        "counted_live_events": counted_events,
        "applicable_component_count": applicable_components.len(),
        "fully_observed_component_count": fully_observed_components.len(),
        "measured_baseline_component_count": measured_baseline_components.len(),
        "explicitly_unmodeled_baseline_component_count": explicitly_unmodeled_baseline_components.len(),
        "missing_baseline_component_count": missing_baseline_components.len(),
        "applicable_components": applicable_components,
        "fully_observed_components": fully_observed_components,
        "incomplete_components": incomplete_components,
        "measured_baseline_components": measured_baseline_components,
        "explicitly_unmodeled_baseline_components": explicitly_unmodeled_baseline_components,
        "missing_baseline_components": missing_baseline_components,
        "measured_baseline_tokens_lower_bound": measured_baseline_tokens_lower_bound,
        "whole_cycle_components_fully_observed": whole_cycle_components_fully_observed,
        "component_semantics": component_semantics,
        "remaining_gap_reason": remaining_gap_reason,
        "note": note,
    })
}

fn build_client_limit_strict_meter_slice(
    contract: &TokenBudgetContractConfig,
    baseline_equivalence: &Value,
) -> Value {
    let measured_components = baseline_equivalence["measured_baseline_components"]
        .as_array()
        .cloned()
        .unwrap_or_default();
    let explicitly_unmodeled_components =
        baseline_equivalence["explicitly_unmodeled_baseline_components"]
            .as_array()
            .cloned()
            .unwrap_or_default();
    let missing_components = baseline_equivalence["missing_baseline_components"]
        .as_array()
        .cloned()
        .unwrap_or_default();
    let lower_bound_tokens = baseline_equivalence["measured_baseline_tokens_lower_bound"]
        .as_u64()
        .unwrap_or(0);
    let state = if measured_components.is_empty() || lower_bound_tokens == 0 {
        "no_strict_slice_measured"
    } else if explicitly_unmodeled_components.is_empty() && missing_components.is_empty() {
        "strict_slice_covers_all_applicable_components"
    } else {
        "strict_slice_partial_lower_bound"
    };
    let note = match state {
        "no_strict_slice_measured" => {
            "В этом scope ещё нет measured strict same-meter lower bound для клиентского лимита."
        }
        "strict_slice_covers_all_applicable_components" => {
            "Applicable whole-cycle components уже дают strict same-meter lower bound без remaining boundary-gap."
        }
        _ => {
            "Часть client-limit meter уже имеет strict same-meter lower bound, но рядом остаётся remaining boundary или unmaterialized contour."
        }
    };
    json!({
        "model_version": contract.client_limit_strict_meter_slice_version.clone(),
        "state": state,
        "same_meter_equivalent_for_slice": !measured_components.is_empty() && lower_bound_tokens > 0,
        "lower_bound_tokens": lower_bound_tokens,
        "component_count": measured_components.len(),
        "components": measured_components,
        "explicit_boundary_component_count": explicitly_unmodeled_components.len(),
        "explicit_boundary_components": explicitly_unmodeled_components,
        "missing_component_count": missing_components.len(),
        "missing_components": missing_components,
        "note": note,
    })
}

fn build_client_limit_explicit_boundary_surface(
    contract: &TokenBudgetContractConfig,
    baseline_equivalence: &Value,
) -> Value {
    let explicit_boundary_components =
        baseline_equivalence["explicitly_unmodeled_baseline_components"]
            .as_array()
            .cloned()
            .unwrap_or_default();
    let measured_components = baseline_equivalence["measured_baseline_components"]
        .as_array()
        .cloned()
        .unwrap_or_default();
    let state = if explicit_boundary_components.is_empty() {
        "no_explicit_boundary"
    } else if explicit_boundary_components
        .iter()
        .all(|item| item.as_str() == Some("continuity_restore_outside_retrieval"))
    {
        "amai_continuity_boundary"
    } else {
        "explicit_boundary_present"
    };
    let (resolution_state, guessed_baseline_prohibited, equivalence_resume_condition) = match state
    {
        "no_explicit_boundary" => ("not_applicable", false, Value::Null),
        "amai_continuity_boundary" => (
            "truthful_pre_amai_baseline_required",
            true,
            json!("truthful_pre_amai_baseline_source"),
        ),
        _ => (
            "truthful_baseline_source_required",
            true,
            json!("truthful_baseline_source"),
        ),
    };
    let note = match state {
        "no_explicit_boundary" => {
            "В этом scope сейчас нет explicit baseline-boundary: remaining gap не упирается в truth-boundary."
        }
        "amai_continuity_boundary" => {
            "Этот boundary оставлен сознательно: Amai-specific continuity restore пока не имеет truthful pre-Amai baseline-equivalent модели и не должен подменяться guessed baseline."
        }
        _ => {
            "В этом scope есть explicit baseline-boundary: часть contour намеренно не выдаётся за same-meter без truthful baseline source."
        }
    };
    json!({
        "model_version": contract.client_limit_explicit_boundary_surface_version.clone(),
        "state": state,
        "blocks_full_same_meter_equivalence": !explicit_boundary_components.is_empty(),
        "component_count": explicit_boundary_components.len(),
        "components": explicit_boundary_components,
        "measured_strict_component_count": measured_components.len(),
        "measured_strict_components": measured_components,
        "resolution_state": resolution_state,
        "guessed_baseline_prohibited": guessed_baseline_prohibited,
        "equivalence_resume_condition": equivalence_resume_condition,
        "note": note,
    })
}

fn build_client_limit_continuity_boundary_rollup(
    contract: &TokenBudgetContractConfig,
    baseline_equivalence: &Value,
    explicit_boundary_surface: &Value,
) -> Value {
    if explicit_boundary_surface["state"].as_str() != Some("amai_continuity_boundary") {
        return json!({
            "model_version": contract.client_limit_continuity_boundary_rollup_version.clone(),
            "state": "no_amai_continuity_boundary",
            "component_count": 0,
            "components": [],
            "observed_tokens": 0,
            "observed_live_events": 0,
            "resolution_state": "not_applicable",
            "guessed_baseline_prohibited": false,
            "equivalence_resume_condition": Value::Null,
            "note": "В этом scope сейчас нет explicit Amai continuity boundary rollup."
        });
    }

    let boundary_components = explicit_boundary_surface["components"]
        .as_array()
        .cloned()
        .unwrap_or_default();
    let mut observed_tokens = 0_u64;
    let mut observed_live_events = 0_u64;
    for item in baseline_equivalence["component_semantics"]
        .as_array()
        .into_iter()
        .flatten()
    {
        let Some(code) = item["code"].as_str() else {
            continue;
        };
        if !boundary_components
            .iter()
            .any(|component| component.as_str() == Some(code))
        {
            continue;
        }
        if item["whole_cycle_observed_complete"].as_bool() != Some(true) {
            continue;
        }
        observed_tokens =
            observed_tokens.saturating_add(item["observed_tokens"].as_u64().unwrap_or(0));
        observed_live_events =
            observed_live_events.saturating_add(item["observed_live_events"].as_u64().unwrap_or(0));
    }

    json!({
        "model_version": contract.client_limit_continuity_boundary_rollup_version.clone(),
        "state": if observed_tokens > 0 {
            "amai_continuity_boundary_observed"
        } else {
            "amai_continuity_boundary_present_without_tokens"
        },
        "component_count": boundary_components.len(),
        "components": boundary_components,
        "observed_tokens": observed_tokens,
        "observed_live_events": observed_live_events,
        "resolution_state": "observed_boundary_only_not_client_meter",
        "guessed_baseline_prohibited": true,
        "equivalence_resume_condition": "truthful_pre_amai_baseline_source",
        "note": "Этот rollup показывает observed token weight для Amai-specific continuity boundary. Он нужен отдельно от strict client-meter slice, потому что continuity restore пока не имеет truthful pre-Amai baseline-equivalent модели."
    })
}

fn continuity_pre_amai_baseline_source_from_events(
    events: Option<&[TokenBudgetEvent]>,
) -> Option<(u64, Value)> {
    let mut total_baseline_tokens = 0_u64;
    let mut current_source_ref = None;
    let mut found = false;

    for event in events.into_iter().flatten() {
        if !is_client_limit_component_target_event("continuity_restore_outside_retrieval", event) {
            continue;
        }
        if event.baseline_strategy != CONTINUITY_PRE_AMAI_BASELINE_STRATEGY
            || event.naive_tokens == 0
        {
            return None;
        }
        total_baseline_tokens = total_baseline_tokens.saturating_add(event.naive_tokens);
        found = true;
        if let Some(source_ref) = event.pre_amai_baseline_source.clone() {
            current_source_ref = Some(source_ref);
        }
    }

    if !found {
        return None;
    }

    Some((
        total_baseline_tokens,
        current_source_ref.unwrap_or_else(|| {
            json!({
                "state": "materialized",
                "source_kind": CONTINUITY_PRE_AMAI_BASELINE_STRATEGY,
                "source_family": "truthful_pre_amai_baseline_source",
            })
        }),
    ))
}

fn build_client_limit_pre_amai_baseline_source_status(
    contract: &TokenBudgetContractConfig,
    events: Option<&[TokenBudgetEvent]>,
    baseline_equivalence: &Value,
    explicit_boundary_surface: &Value,
) -> Value {
    if let Some((_, source_ref)) = continuity_pre_amai_baseline_source_from_events(events) {
        return json!({
            "model_version": contract.client_limit_pre_amai_baseline_source_version.clone(),
            "state": "materialized",
            "required": true,
            "source_family": "truthful_pre_amai_baseline_source",
            "blocking_reason": Value::Null,
            "same_meter_resume_possible": true,
            "current_source_ref": source_ref,
            "note": "Для continuity_restore_outside_retrieval truthful pre-Amai baseline source уже materialized прямо в token ledger events, поэтому explicit boundary больше не нужна."
        });
    }
    let continuity_component_applicable = baseline_equivalence["applicable_components"]
        .as_array()
        .into_iter()
        .flatten()
        .any(|item| item.as_str() == Some("continuity_restore_outside_retrieval"));
    if !continuity_component_applicable {
        return json!({
            "model_version": contract.client_limit_pre_amai_baseline_source_version.clone(),
            "state": "not_required",
            "required": false,
            "source_family": Value::Null,
            "blocking_reason": Value::Null,
            "same_meter_resume_possible": false,
            "current_source_ref": Value::Null,
            "note": "В этом scope truthful pre-Amai baseline source не нужен: continuity_restore_outside_retrieval сейчас не входит в applicable whole-cycle components."
        });
    }
    if explicit_boundary_surface["state"].as_str() != Some("amai_continuity_boundary") {
        return json!({
            "model_version": contract.client_limit_pre_amai_baseline_source_version.clone(),
            "state": "not_required",
            "required": false,
            "source_family": Value::Null,
            "blocking_reason": Value::Null,
            "same_meter_resume_possible": false,
            "current_source_ref": Value::Null,
            "note": "В этом scope truthful pre-Amai baseline source не нужен: explicit Amai continuity boundary сейчас не активен."
        });
    }

    json!({
        "model_version": contract.client_limit_pre_amai_baseline_source_version.clone(),
        "state": "required_not_materialized",
        "required": true,
        "source_family": "truthful_pre_amai_baseline_source",
        "blocking_reason": "missing_truthful_pre_amai_baseline_source",
        "same_meter_resume_possible": false,
        "current_source_ref": Value::Null,
        "note": "Для continuity_restore_outside_retrieval full same-meter equivalence не возобновится, пока не появится отдельный truthful pre-Amai baseline source. До этого boundary должен оставаться explicit."
    })
}

fn baseline_equivalence_component_semantics<'a>(
    baseline_equivalence: &'a Value,
    code: &str,
) -> Option<&'a Value> {
    baseline_equivalence["component_semantics"]
        .as_array()
        .into_iter()
        .flatten()
        .find(|item| item["code"].as_str() == Some(code))
}

fn build_client_limit_exact_pair_status(
    contract: &TokenBudgetContractConfig,
    baseline_equivalence: &Value,
    tool_overhead_observation_source: &Value,
    explicit_boundary_surface: &Value,
    pre_amai_baseline_source_status: &Value,
    blocking_reasons: &[String],
    same_meter_as_client_limit: bool,
) -> Value {
    let mut blockers = Vec::new();
    let mut covered_reasons = BTreeSet::new();
    let incomplete_components = baseline_equivalence["incomplete_components"]
        .as_array()
        .cloned()
        .unwrap_or_default();

    if incomplete_components
        .iter()
        .any(|item| item.as_str() == Some("tool_overhead_outside_retrieval"))
    {
        let observed_live_events = tool_overhead_observation_source["observed_live_events"]
            .as_u64()
            .unwrap_or(0);
        let target_live_events = tool_overhead_observation_source["target_live_events"]
            .as_u64()
            .unwrap_or(0);
        let irrecoverable_missing_live_events =
            tool_overhead_observation_source["irrecoverable_missing_live_events"]
                .as_u64()
                .unwrap_or(0);
        let recoverable_missing_live_events =
            tool_overhead_observation_source["recoverable_missing_live_events"]
                .as_u64()
                .unwrap_or(0);
        let blocking_reason =
            if irrecoverable_missing_live_events > 0 && recoverable_missing_live_events == 0 {
                "tool_overhead_outside_retrieval_irrecoverable_debt"
            } else if observed_live_events > 0 {
                "tool_overhead_outside_retrieval_partially_measured"
            } else {
                "tool_overhead_outside_retrieval_unmeasured"
            };
        covered_reasons.insert(blocking_reason.to_string());
        blockers.push(json!({
            "code": "tool_overhead_outside_retrieval",
            "blocker_kind": "whole_cycle_observation_gap",
            "state": tool_overhead_observation_source["state"].clone(),
            "blocking_reason": blocking_reason,
            "observed_live_events": observed_live_events,
            "target_live_events": target_live_events,
            "missing_live_events": tool_overhead_observation_source["missing_live_events"].clone(),
            "recoverability_state": tool_overhead_observation_source["recoverability_state"].clone(),
            "gap_semantics": tool_overhead_observation_source["gap_semantics"].clone(),
            "irrecoverable_missing_live_events": tool_overhead_observation_source["irrecoverable_missing_live_events"].clone(),
            "recoverable_missing_live_events": tool_overhead_observation_source["recoverable_missing_live_events"].clone(),
            "frozen_gap_candidate": irrecoverable_missing_live_events > 0 && recoverable_missing_live_events == 0,
            "resolution_condition": if irrecoverable_missing_live_events > 0
                && recoverable_missing_live_events == 0
            {
                json!("freeze_irrecoverable_gap_or_keep_exact_pair_unavailable")
            } else if irrecoverable_missing_live_events > 0 {
                json!("recover_historical_tool_overhead_source_or_freeze_irrecoverable_gap")
            } else {
                json!("tool_overhead_source_covers_missing_scope")
            },
            "note": if irrecoverable_missing_live_events > 0 && recoverable_missing_live_events == 0 {
                Value::String("Whole-cycle exact pair по этому компоненту ещё не materialized: recoverable lag уже снят, но остался только irrecoverable historical source-loss без stored context pack payload. Дальше нужен либо explicit frozen gap, либо exact pair честно остаётся unavailable.".to_string())
            } else if irrecoverable_missing_live_events > 0 {
                Value::String("Whole-cycle exact pair по этому компоненту ещё не materialized: часть retrieval live scope уже упирается в irrecoverable source-loss без stored context pack payload, поэтому дальше нужен либо recovery source, либо explicit frozen gap.".to_string())
            } else {
                Value::String("Whole-cycle exact pair по этому компоненту ещё не materialized: retrieval live scope имеет missing tool_overhead attach и пока даёт только partial same-meter coverage.".to_string())
            }
        }));
    }

    if let Some(component) =
        baseline_equivalence_component_semantics(baseline_equivalence, "assistant_generation")
    {
        let semantics_state = component["baseline_semantics_state"]
            .as_str()
            .unwrap_or_default();
        if component["whole_cycle_observed_complete"].as_bool() == Some(true)
            && !component["baseline_measured_tokens"].is_u64()
            && semantics_state == "baseline_semantics_unmaterialized"
        {
            let blocking_reason = "assistant_generation_baseline_semantics_unmaterialized";
            covered_reasons.insert(blocking_reason.to_string());
            blockers.push(json!({
                "code": "assistant_generation",
                "blocker_kind": "baseline_semantics_gap",
                "state": semantics_state,
                "blocking_reason": blocking_reason,
                "observed_live_events": component["observed_live_events"].clone(),
                "target_live_events": component["target_live_events_count"].clone(),
                "observed_tokens": component["observed_tokens"].clone(),
                "resolution_condition": "assistant_generation_baseline_semantics_materialized",
                "note": component["note"].clone(),
            }));
        }
    }

    if explicit_boundary_surface["state"].as_str() == Some("amai_continuity_boundary")
        && pre_amai_baseline_source_status["state"].as_str() == Some("required_not_materialized")
    {
        let blocking_reason = pre_amai_baseline_source_status["blocking_reason"]
            .as_str()
            .unwrap_or("missing_truthful_pre_amai_baseline_source");
        covered_reasons.insert(blocking_reason.to_string());
        covered_reasons.insert("same_meter_baseline_explicit_boundary".to_string());
        blockers.push(json!({
            "code": "continuity_restore_outside_retrieval",
            "blocker_kind": "explicit_truth_boundary",
            "state": pre_amai_baseline_source_status["state"].clone(),
            "blocking_reason": blocking_reason,
            "resolution_condition": explicit_boundary_surface["equivalence_resume_condition"].clone(),
            "resolution_state": explicit_boundary_surface["resolution_state"].clone(),
            "guessed_baseline_prohibited": explicit_boundary_surface["guessed_baseline_prohibited"].clone(),
            "note": pre_amai_baseline_source_status["note"].clone(),
        }));
    }

    for reason in blocking_reasons {
        if covered_reasons.contains(reason) {
            continue;
        }
        blockers.push(json!({
            "code": Value::Null,
            "blocker_kind": "generic_alignment_gap",
            "state": "reported_by_alignment_blocking_reasons",
            "blocking_reason": reason,
            "resolution_condition": Value::Null,
            "note": "Этот blocker уже surfaced top-level alignment blocking_reasons и остаётся общим exact-pair gap без отдельного per-component explainer."
        }));
    }

    let (state, primary_blocking_reason, note) = if same_meter_as_client_limit {
        (
            "exact_pair_materialized",
            Value::Null,
            "В этом scope exact same-meter pair уже materialized: процент model-token savings можно читать как точный client-limit correlation.",
        )
    } else if blockers.is_empty() {
        (
            "exact_pair_blocked_unknown",
            Value::Null,
            "Exact same-meter pair ещё не materialized, но отдельный blocker surface пока не смог разложить причину детальнее текущего alignment state.",
        )
    } else {
        (
            "exact_pair_blocked",
            blockers[0]["blocking_reason"].clone(),
            "Exact same-meter pair ещё не materialized: этот surface перечисляет именно те truth-gaps, которые сейчас держат scope вне точной correlation с client-limit meter.",
        )
    };

    json!({
        "model_version": contract.client_limit_meter_alignment_version.clone(),
        "state": state,
        "exact_pair_available": same_meter_as_client_limit,
        "blocking_reason_count": blockers.len(),
        "primary_blocking_reason": primary_blocking_reason,
        "blockers": blockers,
        "note": note,
    })
}

fn build_client_limit_frozen_gap_review_surface(
    contract: &TokenBudgetContractConfig,
    exact_pair_status: &Value,
) -> Value {
    let exact_pair_available = exact_pair_status["exact_pair_available"].as_bool() == Some(true);
    let blocker = exact_pair_status["blockers"]
        .as_array()
        .and_then(|items| items.first());
    let review_required =
        blocker.and_then(|value| value["frozen_gap_candidate"].as_bool()) == Some(true);
    let state = if exact_pair_available {
        "not_applicable_exact_pair_materialized"
    } else if review_required {
        "review_required"
    } else if exact_pair_status["state"].as_str() == Some("exact_pair_blocked") {
        "not_applicable_without_frozen_gap_candidate"
    } else {
        "not_applicable"
    };
    let allowed_paths = if review_required {
        json!([
            "keep_exact_pair_unavailable",
            "formalize_reviewed_frozen_debt_export"
        ])
    } else {
        json!([])
    };
    let forbidden_paths = if review_required {
        json!(["claim_raw_exact_history"])
    } else {
        json!([])
    };
    let note = match state {
        "review_required" => {
            "Этот surface формализует product decision point для irrecoverable historical debt: raw exact history уже недоступна, поэтому дальше допустимы только keep-exact-unavailable или отдельный reviewed frozen-debt export без притворства raw exact history."
        }
        "not_applicable_exact_pair_materialized" => {
            "Exact same-meter pair уже materialized, поэтому отдельный frozen-gap review не нужен."
        }
        "not_applicable_without_frozen_gap_candidate" => {
            "Exact pair ещё blocked, но текущий blocker пока не классифицирован как irrecoverable frozen debt candidate."
        }
        _ => "Frozen-gap review surface здесь не требуется.",
    };
    json!({
        "model_version": contract.client_limit_frozen_gap_review_surface_version.clone(),
        "state": state,
        "review_required": review_required,
        "raw_exact_history_available": exact_pair_available,
        "blocking_component": blocker.and_then(|value| value["code"].as_str()).map(|value| value.to_string()),
        "missing_live_events": blocker.and_then(|value| value["missing_live_events"].as_u64()),
        "irrecoverable_missing_live_events": blocker.and_then(|value| value["irrecoverable_missing_live_events"].as_u64()),
        "recoverable_missing_live_events": blocker.and_then(|value| value["recoverable_missing_live_events"].as_u64()),
        "resolution_condition": blocker.and_then(|value| value["resolution_condition"].as_str()).map(|value| value.to_string()),
        "allowed_paths": allowed_paths,
        "forbidden_paths": forbidden_paths,
        "note": note,
    })
}

fn build_reviewed_frozen_debt_export_surface(
    contract: &TokenBudgetContractConfig,
    client_limit_boundary_semantics: &Value,
    scope_code: Option<&str>,
) -> Value {
    let exact_pair_status = &client_limit_boundary_semantics["exact_pair_status"];
    let frozen_gap_review_surface = &client_limit_boundary_semantics["frozen_gap_review_surface"];
    let review_required = frozen_gap_review_surface["review_required"].as_bool() == Some(true)
        || frozen_gap_review_surface["state"].as_str() == Some("review_required");
    let exact_pair_available = exact_pair_status["exact_pair_available"].as_bool() == Some(true)
        || client_limit_boundary_semantics["same_meter_as_client_limit"].as_bool() == Some(true);
    let export_ready_report_only = review_required && !exact_pair_available;
    let state = if export_ready_report_only {
        "reviewed_frozen_debt_export_ready_report_only"
    } else if exact_pair_available {
        "not_applicable_exact_pair_materialized"
    } else if review_required {
        "review_required_but_export_not_ready"
    } else if exact_pair_status["state"].as_str() == Some("exact_pair_blocked") {
        "not_applicable_without_frozen_gap_candidate"
    } else {
        "not_applicable"
    };
    let allowed_claims = if export_ready_report_only {
        json!([
            "reviewed_frozen_debt_report_only",
            "historical_source_loss_disclosed_non_exact",
            "raw_exact_history_unavailable"
        ])
    } else {
        json!([])
    };
    let forbidden_claims = if review_required {
        json!([
            "claim_raw_exact_history",
            "claim_exact_same_meter_pair_materialized"
        ])
    } else {
        json!([])
    };
    let required_disclosures = if export_ready_report_only {
        json!([
            "irrecoverable_historical_debt_present",
            "raw_exact_history_unavailable",
            "review_only_non_exact_surface"
        ])
    } else {
        json!([])
    };
    let propagated_surfaces = if export_ready_report_only {
        json!([
            "contractual_statement_summary",
            "statement_export_preview",
            "settlement_report_preview",
            "contractual_evidence_pack"
        ])
    } else {
        json!([])
    };
    let review_bundle_command = if export_ready_report_only {
        scope_code.map(|scope_code| {
            format!("./scripts/amai_exec.sh observe token-statement-export --scope {scope_code}")
        })
    } else {
        None
    };
    let evidence_pack_command = if export_ready_report_only {
        scope_code.map(|scope_code| {
            format!("./scripts/amai_exec.sh observe token-evidence-pack --scope {scope_code}")
        })
    } else {
        None
    };
    let note = match state {
        "reviewed_frozen_debt_export_ready_report_only" => {
            "Этот surface materialize-ит отдельный reviewed frozen-debt export: historical source-loss можно показывать только как report-only review contour с явным раскрытием debt и без притворства raw exact history."
        }
        "not_applicable_exact_pair_materialized" => {
            "Exact same-meter pair уже materialized, поэтому отдельный reviewed frozen-debt export не нужен."
        }
        "review_required_but_export_not_ready" => {
            "Frozen-gap review уже требуется, но report-only export contour ещё не готов к честной публикации."
        }
        "not_applicable_without_frozen_gap_candidate" => {
            "Exact pair ещё blocked, но blocker пока не классифицирован как irrecoverable frozen debt candidate."
        }
        _ => "Reviewed frozen-debt export surface здесь не требуется.",
    };
    json!({
        "model_version": contract
            .client_limit_reviewed_frozen_debt_export_surface_version
            .clone(),
        "state": state,
        "review_required": review_required,
        "export_ready_report_only": export_ready_report_only,
        "surface_kind": if export_ready_report_only {
            json!("reviewed_frozen_debt_report_only")
        } else {
            Value::Null
        },
        "exact_pair_available": exact_pair_available,
        "raw_exact_history_available": exact_pair_available,
        "blocking_component": frozen_gap_review_surface["blocking_component"].clone(),
        "missing_live_events": frozen_gap_review_surface["missing_live_events"].clone(),
        "irrecoverable_missing_live_events": frozen_gap_review_surface
            ["irrecoverable_missing_live_events"]
            .clone(),
        "recoverable_missing_live_events": frozen_gap_review_surface
            ["recoverable_missing_live_events"]
            .clone(),
        "resolution_condition": frozen_gap_review_surface["resolution_condition"].clone(),
        "allowed_claims": allowed_claims,
        "forbidden_claims": forbidden_claims,
        "required_disclosures": required_disclosures,
        "propagated_surfaces": propagated_surfaces,
        "review_bundle_command": review_bundle_command,
        "evidence_pack_command": evidence_pack_command,
        "note": note,
    })
}

fn build_client_limit_meter_alignment(
    contract: &TokenBudgetContractConfig,
    surface_kind: &str,
    summary: &Value,
    events: Option<&[TokenBudgetEvent]>,
    rollout_observations: Option<&[codex_threads::RolloutAssistantGenerationObservation]>,
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    let (events_total, live_events_count, non_live_events_count, counted_events) =
        client_limit_meter_alignment_counts(summary, events);
    let component_coverage =
        client_limit_component_event_coverage(summary, events, live_events_count, assistant_scope);
    let component_stats = client_limit_component_stats(summary, events, assistant_scope);
    let mut measured_components = vec![
        "retrieval_payload".to_string(),
        "followup_recovery".to_string(),
    ];
    let mut not_applicable_components = Vec::new();
    let mut partially_measured_components = Vec::new();
    let mut missing_components = Vec::new();
    for (code, observed_live_events, _observed_tokens) in component_stats {
        let target_live_events = client_limit_component_target_live_events(
            code,
            events,
            live_events_count,
            assistant_scope,
        );
        if target_live_events == 0 {
            not_applicable_components.push(code.to_string());
        } else if observed_live_events == target_live_events {
            measured_components.push(code.to_string());
        } else {
            missing_components.push(code.to_string());
            if observed_live_events > 0 {
                partially_measured_components.push(code.to_string());
            }
        }
    }
    let assistant_generation_observation_source = assistant_generation_observation_source_status(
        events,
        rollout_observations,
        assistant_scope,
    );
    let tool_overhead_observation_source =
        tool_overhead_observation_source_status(events, assistant_scope);
    let baseline_equivalence =
        build_client_limit_baseline_equivalence(contract, summary, events, assistant_scope);
    let strict_client_meter_slice =
        build_client_limit_strict_meter_slice(contract, &baseline_equivalence);
    let explicit_boundary_surface =
        build_client_limit_explicit_boundary_surface(contract, &baseline_equivalence);
    let continuity_boundary_rollup = build_client_limit_continuity_boundary_rollup(
        contract,
        &baseline_equivalence,
        &explicit_boundary_surface,
    );
    let pre_amai_baseline_source_status = build_client_limit_pre_amai_baseline_source_status(
        contract,
        events,
        &baseline_equivalence,
        &explicit_boundary_surface,
    );
    let mut blocking_reasons =
        client_limit_meter_alignment_blocking_reasons(summary, events, assistant_scope);
    if baseline_equivalence["baseline_equivalent_to_client_limit"].as_bool() == Some(true) {
        blocking_reasons.retain(|reason| reason != "no_confirmed_live_usage_in_scope");
    }
    match assistant_generation_observation_source["state"]
        .as_str()
        .unwrap_or_default()
    {
        "assistant_generation_source_unavailable" => {
            blocking_reasons.push("assistant_generation_source_unavailable".to_string());
        }
        "assistant_generation_source_no_scope_overlap" => {
            blocking_reasons.push("assistant_generation_source_no_scope_overlap".to_string());
        }
        "assistant_generation_source_partial_scope_overlap" => {
            blocking_reasons.push("assistant_generation_source_partial_scope_overlap".to_string());
        }
        _ => {}
    }
    match baseline_equivalence["state"].as_str().unwrap_or_default() {
        "baseline_semantics_unmaterialized" => {
            blocking_reasons.push("same_meter_baseline_unmeasured".to_string());
        }
        "baseline_component_semantics_explicit_boundary" => {
            blocking_reasons.push("same_meter_baseline_explicit_boundary".to_string());
        }
        "baseline_component_semantics_partial" => {
            blocking_reasons.push("same_meter_baseline_partially_measured".to_string());
        }
        _ => {}
    }
    let same_meter_as_client_limit = blocking_reasons.is_empty()
        && baseline_equivalence["baseline_equivalent_to_client_limit"].as_bool() == Some(true);
    let exact_pair_status = build_client_limit_exact_pair_status(
        contract,
        &baseline_equivalence,
        &tool_overhead_observation_source,
        &explicit_boundary_surface,
        &pre_amai_baseline_source_status,
        &blocking_reasons,
        same_meter_as_client_limit,
    );
    let frozen_gap_review_surface =
        build_client_limit_frozen_gap_review_surface(contract, &exact_pair_status);
    json!({
        "model_version": contract.client_limit_meter_alignment_version.clone(),
        "surface_kind": surface_kind,
        "alignment_state": client_limit_meter_alignment_state(
            summary,
            events,
            assistant_scope,
            &baseline_equivalence,
            same_meter_as_client_limit,
        ),
        "same_meter_as_client_limit": same_meter_as_client_limit,
        "events_total": events_total,
        "live_events_count": live_events_count,
        "non_live_events_count": non_live_events_count,
        "counted_live_events": counted_events,
        "measured_components": measured_components,
        "not_applicable_components": not_applicable_components,
        "partially_measured_components": partially_measured_components,
        "missing_components": missing_components,
        "component_event_coverage": component_coverage,
        "blocking_reasons": blocking_reasons,
        "assistant_generation_observation_source": assistant_generation_observation_source,
        "tool_overhead_observation_source": tool_overhead_observation_source,
        "baseline_equivalence": baseline_equivalence,
        "strict_client_meter_slice": strict_client_meter_slice,
        "explicit_boundary_surface": explicit_boundary_surface,
        "continuity_boundary_rollup": continuity_boundary_rollup,
        "pre_amai_baseline_source_status": pre_amai_baseline_source_status,
        "exact_pair_status": exact_pair_status,
        "frozen_gap_review_surface": frozen_gap_review_surface,
        "note": "Этот слой честно показывает, что текущие savings пока считаются как lower-bound части агентного цикла. Whole-cycle observed components могут постепенно materialize-иться, но same meter с клиентским лимитом нельзя объявлять раньше, чем появится и полное observed покрытие, и baseline-equivalent semantics."
    })
}

fn build_agent_cycle_economics(
    measurement: &MeasurementConfig,
    contract: &TokenBudgetContractConfig,
    now_epoch_ms: i64,
    current_session_events: &[TokenBudgetEvent],
    rolling_window_events: Option<&[TokenBudgetEvent]>,
    lifetime_events: &[TokenBudgetEvent],
    rolling_window_label: &str,
    rollout_observations: &[codex_threads::RolloutAssistantGenerationObservation],
    current_session_assistant_scope: &AssistantGenerationScopeObservation,
    rolling_window_assistant_scope: Option<&AssistantGenerationScopeObservation>,
    lifetime_assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    json!({
        "model_version": contract.agent_cycle_model_version.clone(),
        "status": "partial_lower_bound",
        "contract": {
            "scope": "lower_bound_whole_agent_cycle",
            "status": "partial_lower_bound",
            "billing_mode": contract.billing_mode.clone(),
            "billing_policy_version": contract.billing_policy_version.clone(),
            "client_limit_meter_alignment": {
                "model_version": contract.client_limit_meter_alignment_version.clone(),
                "baseline_equivalence_model_version": contract
                    .client_limit_baseline_equivalence_version
                    .clone(),
                "strict_meter_slice_model_version": contract
                    .client_limit_strict_meter_slice_version
                    .clone(),
                "explicit_boundary_surface_model_version": contract
                    .client_limit_explicit_boundary_surface_version
                    .clone(),
                "continuity_boundary_rollup_model_version": contract
                    .client_limit_continuity_boundary_rollup_version
                    .clone(),
                "pre_amai_baseline_source_model_version": contract
                    .client_limit_pre_amai_baseline_source_version
                    .clone(),
                "frozen_gap_review_surface_model_version": contract
                    .client_limit_frozen_gap_review_surface_version
                    .clone(),
                "alignment_state": "partial_lower_bound_not_meter_equivalent",
                "same_meter_as_client_limit": false,
                "measured_components": [
                    "retrieval_payload",
                    "followup_recovery"
                ],
                "partially_measured_components": [],
                "observable_components": [
                    "client_prompt",
                    "assistant_generation",
                    "tool_overhead_outside_retrieval",
                    "continuity_restore_outside_retrieval"
                ],
                "missing_components": [
                    "client_prompt",
                    "assistant_generation",
                    "tool_overhead_outside_retrieval",
                    "continuity_restore_outside_retrieval"
                ],
                "blocking_reasons": [
                    "client_prompt_unmeasured",
                    "assistant_generation_unmeasured",
                    "tool_overhead_outside_retrieval_unmeasured",
                    "continuity_restore_outside_retrieval_unmeasured"
                ],
                "note": "Даже при высокой measured lower bound current meter ещё не эквивалентен полному клиентскому лимиту сессии. Whole-cycle observed components можно materialize-ить по мере появления event-level evidence, но same-meter claim запрещён раньше baseline-equivalent semantics."
            },
            "rate_card_version": contract.rate_card_version.clone(),
            "currency_profile": contract.currency_profile.clone(),
            "settlement_status": contract.settlement_status.clone(),
            "summary": "Это не весь токеновый бюджет клиента, а подтверждённая нижняя граница полного агентного цикла.",
            "measured_components": [
                {
                    "code": "retrieval_payload",
                    "label": "Контекст, который Amai реально вернул"
                },
                {
                    "code": "followup_recovery",
                    "label": "Доуточнения после неполного ответа, которые уже видно в ledger"
                }
            ],
            "missing_components": [
                {
                    "code": "client_prompt",
                    "label": "Токены исходного запроса клиента"
                },
                {
                    "code": "assistant_generation",
                    "label": "Токены генерации итогового ответа"
                },
                {
                    "code": "tool_overhead_outside_retrieval",
                    "label": "Tool-step и orchestration вне retrieval-контура"
                },
                {
                    "code": "continuity_restore_outside_retrieval",
                    "label": "Восстановление continuity, если оно прошло вне token-ledger retrieval-событий"
                }
            ],
            "reporting_layers": {
                "billable": {
                    "status": "disabled_report_only",
                    "note": "Пока billing policy работает только в report-only режиме, подтверждённая нижняя граница не используется как money-facing начисление."
                },
                "measured_non_billable": {
                    "status": "active",
                    "note": "Подтверждённые live lower-bound измерения уже видны и пригодны для анализа, но ещё не являются contractual billing amount."
                },
                "unmeasured": {
                    "status": "active",
                    "note": "Полный agent-cycle ещё не покрыт: missing components перечислены отдельно и не маскируются под измеренную экономию."
                }
            },
            "note": "Линия 'без Amai' здесь пока означает измеренный baseline retrieval-части цикла, а линия 'с Amai' — retrieval плюс уже зафиксированные доуточнения. Это честная нижняя граница, а не полная стоимость всей агентной сессии."
        },
        "chart_contract": {
            "timeline_type": "event_cumulative",
            "x_axis": "timestamp_epoch_ms",
            "y_axes": [
                "without_amai_measured_tokens",
                "with_amai_measured_tokens",
                "measured_saved_tokens"
            ],
            "series": [
                "all_live_timeline",
                "verified_live_timeline"
            ],
            "point_limit": AGENT_CYCLE_TIMELINE_MAX_POINTS
        },
        "current_session": build_agent_cycle_scope(
            measurement,
            contract,
            now_epoch_ms,
            "current_session",
            "текущая сессия",
            current_session_events,
            AGENT_CYCLE_TIMELINE_MAX_POINTS / 2,
            rollout_observations,
            materialized_assistant_scope(current_session_assistant_scope),
        ),
        "rolling_window": rolling_window_events
            .map(|events| {
                build_agent_cycle_scope(
                    measurement,
                    contract,
                    now_epoch_ms,
                    "rolling_window",
                    &format!("окно {}", rolling_window_label),
                    events,
                    AGENT_CYCLE_TIMELINE_MAX_POINTS,
                    rollout_observations,
                    rolling_window_assistant_scope,
                )
            })
            .unwrap_or(Value::Null),
        "lifetime": build_agent_cycle_scope(
            measurement,
            contract,
            now_epoch_ms,
            "lifetime",
            "всё время записи",
            lifetime_events,
            AGENT_CYCLE_TIMELINE_MAX_POINTS,
            rollout_observations,
            lifetime_assistant_scope,
        ),
    })
}

fn build_agent_cycle_scope(
    measurement: &MeasurementConfig,
    contract: &TokenBudgetContractConfig,
    now_epoch_ms: i64,
    scope_code: &str,
    scope_label: &str,
    events: &[TokenBudgetEvent],
    max_points: usize,
    rollout_observations: &[codex_threads::RolloutAssistantGenerationObservation],
    assistant_scope: Option<&AssistantGenerationScopeObservation>,
) -> Value {
    let live_events = events
        .iter()
        .filter(|event| event.traffic_class == "live")
        .cloned()
        .collect::<Vec<_>>();
    let summary = summarize_events(&live_events, now_epoch_ms, measurement, contract);
    let with_amai_measured_tokens = summary["total_context_tokens"]
        .as_u64()
        .unwrap_or(0)
        .saturating_add(summary["total_recovery_tokens"].as_u64().unwrap_or(0));
    let verified_with_amai_measured_tokens = summary["verified_delivered_tokens"]
        .as_u64()
        .unwrap_or(0)
        .saturating_add(summary["verified_recovery_tokens"].as_u64().unwrap_or(0));
    let observed_whole_cycle_with_amai_tokens =
        observed_whole_cycle_with_assistant_scope_tokens(&summary, assistant_scope)
            .unwrap_or(with_amai_measured_tokens);
    let verified_observed_whole_cycle_with_amai_tokens =
        verified_observed_whole_cycle_with_assistant_scope_tokens(&summary, assistant_scope)
            .unwrap_or(verified_with_amai_measured_tokens);
    let verified_share_pct = percent_share(
        summary["counted_events"].as_u64().unwrap_or(0),
        summary["events_total"].as_u64().unwrap_or(0),
    );
    json!({
        "scope_code": scope_code,
        "scope_label": scope_label,
        "status": "partial_lower_bound",
        "events_total": summary["events_total"].as_u64().unwrap_or(0),
        "counted_events": summary["counted_events"].as_u64().unwrap_or(0),
        "excluded_events_count": summary["excluded_events_count"].as_u64().unwrap_or(0),
        "coverage": summary["coverage"].clone(),
        "excluded_breakdown": summary["excluded_breakdown"].clone(),
        "client_limit_meter_alignment": build_client_limit_meter_alignment(
            contract,
            "agent_cycle_scope",
            &summary,
            Some(&live_events),
            Some(rollout_observations),
            assistant_scope,
        ),
        "observed_client_prompt_tokens": summary["observed_client_prompt_tokens"].clone(),
        "observed_assistant_generation_tokens": Value::from(
            assistant_scope
                .map(|scope| scope.observed_tokens)
                .unwrap_or_else(|| summary["observed_assistant_generation_tokens"].as_u64().unwrap_or(0))
        ),
        "observed_tool_overhead_tokens": summary["observed_tool_overhead_tokens"].clone(),
        "observed_continuity_restore_tokens": summary["observed_continuity_restore_tokens"].clone(),
        "verified_share_pct": verified_share_pct,
        "without_amai_measured_tokens": summary["total_naive_tokens"].as_u64().unwrap_or(0),
        "with_amai_measured_tokens": with_amai_measured_tokens,
        "observed_whole_cycle_with_amai_tokens": observed_whole_cycle_with_amai_tokens,
        "measured_saved_tokens": summary["total_effective_saved_tokens"].as_i64().unwrap_or(0),
        "measured_saved_pct": summary["effective_savings_pct"].as_f64().unwrap_or(0.0),
        "verified_without_amai_measured_tokens": summary["verified_baseline_tokens"].as_u64().unwrap_or(0),
        "verified_with_amai_measured_tokens": verified_with_amai_measured_tokens,
        "verified_observed_whole_cycle_with_amai_tokens": verified_observed_whole_cycle_with_amai_tokens,
        "verified_measured_saved_tokens": summary["verified_effective_saved_tokens"].as_i64().unwrap_or(0),
        "verified_measured_saved_pct": summary["verified_effective_savings_pct"].as_f64().unwrap_or(0.0),
        "answer_like_counted_events": summary["answer_like_counted_events"].as_u64().unwrap_or(0),
        "answer_like_rate": summary["answer_like_rate"].as_f64().unwrap_or(0.0),
        "started_at_epoch_ms": summary["started_at_epoch_ms"].clone(),
        "ended_at_epoch_ms": summary["ended_at_epoch_ms"].clone(),
        "all_live_timeline": build_agent_cycle_timeline(&live_events, false, max_points),
        "verified_live_timeline": build_agent_cycle_timeline(&live_events, true, max_points),
    })
}

fn build_agent_cycle_timeline(
    events: &[TokenBudgetEvent],
    verified_only: bool,
    max_points: usize,
) -> Value {
    let filtered = events
        .iter()
        .filter(|event| !verified_only || event.quality_ok)
        .collect::<Vec<_>>();
    if filtered.is_empty() {
        return Value::Array(Vec::new());
    }

    let mut without_amai_cumulative = 0_u64;
    let mut with_amai_cumulative = 0_u64;
    let mut points = Vec::with_capacity(filtered.len());
    for (index, event) in filtered.into_iter().enumerate() {
        without_amai_cumulative = without_amai_cumulative.saturating_add(event.naive_tokens);
        with_amai_cumulative = with_amai_cumulative
            .saturating_add(event.context_tokens)
            .saturating_add(event.recovery_tokens);
        let measured_saved_tokens = without_amai_cumulative as i64 - with_amai_cumulative as i64;
        points.push(json!({
            "point_index": index + 1,
            "timestamp_epoch_ms": event.created_at_epoch_ms,
            "event_id": event.event_id,
            "query_type": event.query_type,
            "cold_warm_state": event.cold_warm_state,
            "answer_like": is_answer_like_event(event),
            "without_amai_measured_tokens": without_amai_cumulative,
            "with_amai_measured_tokens": with_amai_cumulative,
            "measured_saved_tokens": measured_saved_tokens,
            "measured_saved_pct": percent_from_signed(measured_saved_tokens, without_amai_cumulative),
        }));
    }
    downsample_timeline(points, max_points)
}

fn downsample_timeline(points: Vec<Value>, max_points: usize) -> Value {
    if points.len() <= max_points || max_points < 2 {
        return Value::Array(points);
    }

    let last_index = points.len() - 1;
    let step = last_index as f64 / (max_points - 1) as f64;
    let mut sampled = Vec::with_capacity(max_points);
    let mut last_taken = None::<usize>;
    for bucket in 0..max_points {
        let index = if bucket == max_points - 1 {
            last_index
        } else {
            (bucket as f64 * step).round() as usize
        }
        .min(last_index);
        if last_taken == Some(index) {
            continue;
        }
        sampled.push(points[index].clone());
        last_taken = Some(index);
    }
    if last_taken != Some(last_index) {
        sampled.push(points[last_index].clone());
    }
    Value::Array(sampled)
}

fn percent_share(part: u64, total: u64) -> f64 {
    if total == 0 {
        0.0
    } else {
        part as f64 * 100.0 / total as f64
    }
}

fn source_breakdown(
    events: &[TokenBudgetEvent],
    measurement: &MeasurementConfig,
    contract: &TokenBudgetContractConfig,
) -> Value {
    let mut grouped = BTreeMap::<String, Vec<TokenBudgetEvent>>::new();
    for event in events {
        grouped
            .entry(event.source_kind.clone())
            .or_default()
            .push(event.clone());
    }
    Value::Array(
        grouped
            .into_iter()
            .map(|(source_kind, items)| {
                json!({
                    "source_kind": source_kind,
                    "summary": summarize_events(
                        &items,
                        items.last()
                            .map(|item| item.created_at_epoch_ms)
                            .unwrap_or_default(),
                        measurement,
                        contract,
                    ),
                })
            })
            .collect(),
    )
}

