fn continuity_snapshot_semantic_epoch_ms(snapshot: &ObservabilitySnapshotRecord) -> i64 {
    snapshot.payload["_observability"]["captured_at_epoch_ms"]
        .as_i64()
        .or_else(|| snapshot.payload["continuity_import"]["imported_at_epoch_ms"].as_i64())
        .or_else(|| snapshot.payload["continuity_handoff"]["captured_at_epoch_ms"].as_i64())
        .unwrap_or(snapshot.created_at_epoch_ms)
}

fn continuity_snapshot_matches_scope(
    snapshot: &ObservabilitySnapshotRecord,
    snapshot_kind: &str,
    project_code: &str,
    namespace_code: &str,
) -> bool {
    let root = match snapshot_kind {
        "continuity_import" => &snapshot.payload["continuity_import"],
        "continuity_handoff" => &snapshot.payload["continuity_handoff"],
        _ => return false,
    };
    root["project"]["code"].as_str() == Some(project_code)
        && root["namespace"]["code"].as_str() == Some(namespace_code)
}

fn latest_scoped_continuity_snapshot_before<'a>(
    snapshots: &'a [ObservabilitySnapshotRecord],
    snapshot_kind: &str,
    project_code: &str,
    namespace_code: &str,
    cutoff_epoch_ms: i64,
) -> Option<&'a ObservabilitySnapshotRecord> {
    snapshots
        .iter()
        .filter(|snapshot| snapshot.snapshot_kind == snapshot_kind)
        .filter(|snapshot| {
            continuity_snapshot_matches_scope(snapshot, snapshot_kind, project_code, namespace_code)
        })
        .filter(|snapshot| continuity_snapshot_semantic_epoch_ms(snapshot) <= cutoff_epoch_ms)
        .max_by_key(|snapshot| {
            (
                continuity_snapshot_semantic_epoch_ms(snapshot),
                snapshot.created_at_epoch_ms,
            )
        })
}

fn render_continuity_pre_amai_baseline_text(
    project_code: &str,
    namespace_code: &str,
    continuity_import_snapshot: Option<&ObservabilitySnapshotRecord>,
    continuity_handoff_snapshot: Option<&ObservabilitySnapshotRecord>,
) -> Option<(String, Vec<String>, Value)> {
    if continuity_import_snapshot.is_none() && continuity_handoff_snapshot.is_none() {
        return None;
    }

    let mut lines = vec![
        "PRE_AMAI_CONTINUITY_BASELINE".to_string(),
        format!("Project: {project_code}"),
        format!("Namespace: {namespace_code}"),
    ];
    let mut source_entries = Vec::new();

    let continuity_import_ref = continuity_import_snapshot.map(|snapshot| {
        let node = &snapshot.payload["continuity_import"];
        let imported_at_epoch_ms = continuity_snapshot_semantic_epoch_ms(snapshot);
        lines.push(String::new());
        lines.push("## Continuity Import".to_string());
        lines.push(format!("- imported_at_epoch_ms: {imported_at_epoch_ms}"));
        if let Some(value) = node["documents_imported"].as_u64() {
            lines.push(format!("- documents_imported: {value}"));
        }
        if let Some(value) = node["session_memory_files"].as_u64() {
            lines.push(format!("- session_memory_files: {value}"));
        }
        if let Some(value) = node["rendered_transcript_files"].as_u64() {
            lines.push(format!("- rendered_transcript_files: {value}"));
        }
        if let Some(value) = node["bootstrap_summary"]["details"]["thread_count"].as_u64() {
            lines.push(format!("- bootstrap_thread_count: {value}"));
        }
        if let Some(value) = node["bootstrap_summary"]["details"]["latest_rendered_transcript"]
            .as_str()
            .filter(|value| !value.is_empty())
        {
            lines.push(format!("- latest_rendered_transcript: {value}"));
        }
        if let Some(value) = node["active_workline_summary"]["details"]["headline"]
            .as_str()
            .filter(|value| !value.is_empty())
        {
            lines.push(format!("- active_workline_headline: {value}"));
        }
        if let Some(value) = node["active_workline_summary"]["details"]["next_step"]
            .as_str()
            .filter(|value| !value.is_empty())
        {
            lines.push(format!("- active_workline_next_step: {value}"));
        }
        source_entries.push(format!("continuity_import:{}", snapshot.snapshot_id));
        json!({
            "snapshot_id": snapshot.snapshot_id.to_string(),
            "semantic_epoch_ms": imported_at_epoch_ms,
        })
    });

    let continuity_handoff_ref = continuity_handoff_snapshot.map(|snapshot| {
        let node = &snapshot.payload["continuity_handoff"];
        let captured_at_epoch_ms = continuity_snapshot_semantic_epoch_ms(snapshot);
        lines.push(String::new());
        lines.push("## Continuity Handoff".to_string());
        lines.push(format!("- captured_at_epoch_ms: {captured_at_epoch_ms}"));
        if let Some(value) = node["headline"].as_str().filter(|value| !value.is_empty()) {
            lines.push(format!("- headline: {value}"));
        }
        if let Some(value) = node["next_step"].as_str().filter(|value| !value.is_empty()) {
            lines.push(format!("- next_step: {value}"));
        }
        if let Some(value) = node["details"]
            .as_str()
            .filter(|value| !value.trim().is_empty())
        {
            lines.push(String::new());
            lines.push("### Handoff Details".to_string());
            lines.push(value.trim().to_string());
        }
        source_entries.push(format!("continuity_handoff:{}", snapshot.snapshot_id));
        json!({
            "snapshot_id": snapshot.snapshot_id.to_string(),
            "semantic_epoch_ms": captured_at_epoch_ms,
        })
    });

    Some((
        lines.join("\n"),
        source_entries,
        json!({
            "state": "materialized",
            "source_kind": CONTINUITY_PRE_AMAI_BASELINE_STRATEGY,
            "source_family": "truthful_pre_amai_baseline_source",
            "source_scope": "continuity_observability_snapshots",
            "continuity_import": continuity_import_ref.unwrap_or(Value::Null),
            "continuity_handoff": continuity_handoff_ref.unwrap_or(Value::Null),
        }),
    ))
}

fn continuity_pre_amai_baseline_materialization(
    tokenizer: &CoreBPE,
    project_code: &str,
    namespace_code: &str,
    continuity_import_snapshot: Option<&ObservabilitySnapshotRecord>,
    continuity_handoff_snapshot: Option<&ObservabilitySnapshotRecord>,
) -> Option<ContinuityPreAmaiBaselineMaterialization> {
    let (baseline_text, source_entries, mut source_ref) = render_continuity_pre_amai_baseline_text(
        project_code,
        namespace_code,
        continuity_import_snapshot,
        continuity_handoff_snapshot,
    )?;
    let baseline_tokens = tokenizer.encode_with_special_tokens(&baseline_text).len() as u64;
    let baseline_sha256 = hex_sha256(baseline_text.as_bytes());
    if let Some(object) = source_ref.as_object_mut() {
        object.insert(
            "baseline_sha256".to_string(),
            Value::String(baseline_sha256),
        );
        object.insert(
            "source_entries".to_string(),
            Value::Array(
                source_entries
                    .iter()
                    .cloned()
                    .map(Value::String)
                    .collect::<Vec<_>>(),
            ),
        );
    }
    Some(ContinuityPreAmaiBaselineMaterialization {
        baseline_tokens,
        baseline_bytes: baseline_text.len(),
        source_entries,
        source_ref,
    })
}

fn apply_continuity_pre_amai_baseline(
    payload: &mut Value,
    materialization: &ContinuityPreAmaiBaselineMaterialization,
) -> Result<bool> {
    let node = payload["token_budget_event"]
        .as_object_mut()
        .ok_or_else(|| anyhow!("token budget payload missing token_budget_event"))?;
    let continuity_tokens = node["whole_cycle_observed"]["continuity_restore_tokens"]
        .as_u64()
        .unwrap_or(0);
    if continuity_tokens == 0 {
        return Ok(false);
    }

    let effective_saved_tokens = materialization.baseline_tokens as i64 - continuity_tokens as i64;
    let saved_tokens = materialization
        .baseline_tokens
        .saturating_sub(continuity_tokens);
    let savings_factor = if continuity_tokens == 0 {
        materialization.baseline_tokens as f64
    } else {
        materialization.baseline_tokens as f64 / continuity_tokens as f64
    };
    let savings_percent = if materialization.baseline_tokens == 0 {
        0.0
    } else {
        saved_tokens as f64 * 100.0 / materialization.baseline_tokens as f64
    };
    let effective_savings_percent =
        percent_from_signed(effective_saved_tokens, materialization.baseline_tokens);

    let already_materialized = node["baseline_strategy"].as_str()
        == Some(CONTINUITY_PRE_AMAI_BASELINE_STRATEGY)
        && node["baseline_tokens"].as_u64() == Some(materialization.baseline_tokens)
        && node["pre_amai_baseline_source"] == materialization.source_ref;
    if already_materialized {
        return Ok(false);
    }

    node.insert("baseline_hit_target".to_string(), Value::Bool(true));
    node.insert(
        "cold_warm_state".to_string(),
        json!("pre_amai_baseline_materialized"),
    );
    node.insert(
        "baseline_strategy".to_string(),
        json!(CONTINUITY_PRE_AMAI_BASELINE_STRATEGY),
    );
    node.insert(
        "baseline_tokens".to_string(),
        Value::from(materialization.baseline_tokens),
    );
    node.insert(
        "naive_tokens".to_string(),
        Value::from(materialization.baseline_tokens),
    );
    node.insert(
        "pre_amai_baseline_source".to_string(),
        materialization.source_ref.clone(),
    );

    let naive_scope = ensure_nested_object(node, "naive_scope")?;
    naive_scope.insert(
        "files_considered".to_string(),
        Value::from(materialization.source_entries.len() as u64),
    );
    naive_scope.insert(
        "files".to_string(),
        Value::Array(
            materialization
                .source_entries
                .iter()
                .cloned()
                .map(Value::String)
                .collect::<Vec<_>>(),
        ),
    );
    naive_scope.insert(
        "rendered_bytes".to_string(),
        Value::from(materialization.baseline_bytes as u64),
    );
    naive_scope.insert(
        "tokens".to_string(),
        Value::from(materialization.baseline_tokens),
    );

    let savings = ensure_nested_object(node, "savings")?;
    savings.insert("saved_tokens".to_string(), Value::from(saved_tokens));
    savings.insert(
        "effective_saved_tokens".to_string(),
        Value::from(effective_saved_tokens),
    );
    savings.insert("savings_factor".to_string(), Value::from(savings_factor));
    savings.insert("savings_percent".to_string(), Value::from(savings_percent));
    savings.insert(
        "effective_savings_percent".to_string(),
        Value::from(effective_savings_percent),
    );
    node.insert("saved_tokens".to_string(), Value::from(saved_tokens));
    node.insert(
        "effective_saved_tokens".to_string(),
        Value::from(effective_saved_tokens),
    );
    node.insert("savings_factor".to_string(), Value::from(savings_factor));
    node.insert("savings_percent".to_string(), Value::from(savings_percent));
    node.insert(
        "gross_savings_pct".to_string(),
        Value::from(savings_percent),
    );
    node.insert(
        "effective_savings_percent".to_string(),
        Value::from(effective_savings_percent),
    );
    Ok(true)
}

pub(crate) fn derive_traffic_class(source_kind: &str) -> String {
    if source_kind.starts_with("live_") {
        "live".to_string()
    } else if source_kind.starts_with("verify_") {
        "verify".to_string()
    } else if source_kind.starts_with("proof_") {
        "proof".to_string()
    } else if source_kind.starts_with("benchmark_") {
        "benchmark".to_string()
    } else {
        "unknown".to_string()
    }
}

fn include_traffic_class_in_report(traffic_class: &str, include_verify_events: bool) -> bool {
    include_verify_events || traffic_class == "live"
}

pub(crate) fn derive_baseline_strategy(query_type: &str) -> &'static str {
    match query_type {
        "onboarding_query" => "legacy_pre_amai",
        "config_lookup" | "symbol_lookup" | "code_lookup" => "ide_search_top_files",
        "docs_lookup" | "cross_file_trace" => "grep_top_files",
        "architecture_question" | "bugfix_context" => "semantic_top_k",
        _ => "naive_top_files",
    }
}

pub(crate) fn derive_query_type(query: &str) -> &'static str {
    let lowered = query.to_lowercase();

    if [
        "onboarding",
        "getting started",
        "setup",
        "install",
        "как подключ",
        "как установить",
        "как запустить",
        "как начать",
    ]
    .iter()
    .any(|needle| lowered.contains(needle))
    {
        "onboarding_query"
    } else if [
        "config",
        "конфиг",
        "настрой",
        ".env",
        "yaml",
        "toml",
        "json",
    ]
    .iter()
    .any(|needle| lowered.contains(needle))
    {
        "config_lookup"
    } else if [
        "bug",
        "fix",
        "ошиб",
        "не работает",
        "падает",
        "сломал",
        "почин",
    ]
    .iter()
    .any(|needle| lowered.contains(needle))
    {
        "bugfix_context"
    } else if ["архитект", "architecture", "контур", "как устроен", "зачем"]
        .iter()
        .any(|needle| lowered.contains(needle))
    {
        "architecture_question"
    } else if [
        "trace",
        "call stack",
        "flow",
        "цепоч",
        "где вызыва",
        "откуда приходит",
    ]
    .iter()
    .any(|needle| lowered.contains(needle))
    {
        "cross_file_trace"
    } else if [
        "symbol",
        "struct",
        "enum",
        "trait",
        "type",
        "тип",
        "функц",
        "method",
        "класс",
    ]
    .iter()
    .any(|needle| lowered.contains(needle))
    {
        "symbol_lookup"
    } else if ["docs", "readme", "guide", "док", "документац"]
        .iter()
        .any(|needle| lowered.contains(needle))
    {
        "docs_lookup"
    } else {
        "code_lookup"
    }
}

fn derive_quality_verdict(
    payload: &Value,
    query_type: &str,
    naive_scope: &NaiveScope,
) -> QualityVerdict {
    let exact_hits = payload["retrieval"]["exact_documents"]
        .as_array()
        .map_or(0, Vec::len);
    let symbol_hits = payload["retrieval"]["symbol_hits"]
        .as_array()
        .map_or(0, Vec::len);
    let lexical_hits = payload["retrieval"]["lexical_chunks"]
        .as_array()
        .map_or(0, Vec::len);
    let semantic_hits = payload["retrieval"]["semantic_chunks"]
        .as_array()
        .map_or(0, Vec::len);
    let semantic_guard_abstained = payload["quality"]["semantic_guard"]["abstained"]
        .as_bool()
        .unwrap_or(false);
    let total_hits = exact_hits + symbol_hits + lexical_hits + semantic_hits;
    let query_terms = extract_query_terms(payload["query"].as_str().unwrap_or_default());
    let target_kind = match query_type {
        "onboarding_query" | "docs_lookup" => "document",
        "config_lookup" | "code_lookup" => "file",
        "symbol_lookup" => "symbol",
        "cross_file_trace" => "cross_file_trace",
        "architecture_question" | "bugfix_context" => "evidence_bundle",
        _ => "file",
    };
    let baseline_hit_target = !naive_scope.files.is_empty();
    let amai_hit_target = match target_kind {
        "document" => exact_hits > 0 || lexical_hits > 0,
        "file" => exact_hits > 0 || lexical_hits > 0 || symbol_hits > 0,
        "symbol" => symbol_hits > 0,
        "cross_file_trace" => {
            (symbol_hits > 0 && lexical_hits > 0)
                || (symbol_hits + lexical_hits + semantic_hits >= 2)
        }
        "evidence_bundle" => total_hits >= 2,
        _ => total_hits > 0,
    };
    let head_hit_target = top_hit_matches_task(payload, target_kind, &query_terms);
    let quality_ok = baseline_hit_target && amai_hit_target && !semantic_guard_abstained;
    let task_success_proxy = quality_ok
        && match target_kind {
            "document" | "file" | "symbol" => head_hit_target,
            "cross_file_trace" => head_hit_target && total_hits >= 2,
            "evidence_bundle" => head_hit_target && total_hits >= 3,
            _ => head_hit_target,
        };
    let answer_like_proxy = answer_like_from_counts(
        target_kind,
        head_hit_target,
        exact_hits,
        symbol_hits,
        lexical_hits,
        semantic_hits,
    ) && task_success_proxy;
    let quality_score = match target_kind {
        "cross_file_trace" => {
            if answer_like_proxy {
                1.0
            } else if task_success_proxy {
                0.92
            } else if quality_ok {
                0.85
            } else if total_hits > 0 && !semantic_guard_abstained {
                0.5
            } else {
                0.0
            }
        }
        "evidence_bundle" => {
            if answer_like_proxy {
                1.0
            } else if task_success_proxy {
                0.94
            } else if quality_ok {
                0.9
            } else if total_hits > 0 && !semantic_guard_abstained {
                0.6
            } else {
                0.0
            }
        }
        _ => {
            if answer_like_proxy {
                1.0
            } else if task_success_proxy {
                0.9
            } else if quality_ok {
                0.8
            } else if total_hits > 0 && !semantic_guard_abstained {
                0.4
            } else {
                0.0
            }
        }
    };
    let (quality_method, quality_tier) = if answer_like_proxy {
        ("hybrid_answer_proxy", "answer_proxy")
    } else if task_success_proxy {
        ("hybrid_task_proxy", "task_proxy")
    } else if quality_ok {
        ("hybrid_retrieval_parity", "retrieval")
    } else if total_hits > 0 && !semantic_guard_abstained {
        ("hybrid_partial_retrieval", "partial")
    } else {
        ("hybrid_retrieval_parity", "retrieval")
    };
    QualityVerdict {
        target_kind,
        baseline_hit_target,
        amai_hit_target,
        quality_ok,
        quality_score,
        quality_method,
        quality_tier,
        head_hit_target,
        needed_followup: !quality_ok,
        followup_count: 0,
    }
}

fn answer_like_from_counts(
    target_kind: &str,
    head_hit_target: bool,
    exact_hits: usize,
    symbol_hits: usize,
    lexical_hits: usize,
    semantic_hits: usize,
) -> bool {
    if !head_hit_target {
        return false;
    }
    let total_hits = exact_hits + symbol_hits + lexical_hits + semantic_hits;
    let nonzero_sections = [exact_hits, symbol_hits, lexical_hits, semantic_hits]
        .into_iter()
        .filter(|count| *count > 0)
        .count();
    match target_kind {
        "document" => exact_hits > 0,
        "file" => exact_hits > 0 || lexical_hits > 0,
        "symbol" => symbol_hits > 0,
        "cross_file_trace" => symbol_hits > 0 && lexical_hits > 0 && total_hits >= 3,
        "evidence_bundle" => total_hits >= 4 && nonzero_sections >= 2,
        _ => total_hits > 0,
    }
}

fn is_answer_like_event(event: &TokenBudgetEvent) -> bool {
    if !event.quality_ok {
        return false;
    }
    if matches!(
        event.quality_tier.as_str(),
        "answer_proxy" | "answer_success_recovered"
    ) {
        return true;
    }
    match event.target_kind.as_str() {
        "document" => event.head_hit_target && event.document_hits > 0,
        "file" => event.head_hit_target && event.file_hits > 0,
        "symbol" => event.head_hit_target && event.symbol_hits_count > 0,
        "cross_file_trace" => {
            event.head_hit_target && event.symbol_hits_count > 0 && event.chunks_count >= 2
        }
        "evidence_bundle" => {
            event.head_hit_target && event.sources_count >= 2 && event.chunks_count >= 3
        }
        _ => event.head_hit_target && event.sources_count > 0,
    }
}

fn top_hit_matches_task(payload: &Value, target_kind: &str, query_terms: &[String]) -> bool {
    let items = top_retrieval_items(payload, 3);
    items
        .into_iter()
        .any(|item| retrieval_item_matches_task(item, target_kind, query_terms))
}

fn top_retrieval_items(payload: &Value, limit: usize) -> Vec<&Value> {
    let retrieval = &payload["retrieval"];
    let mut items = Vec::new();
    for section in [
        "exact_documents",
        "symbol_hits",
        "lexical_chunks",
        "semantic_chunks",
    ] {
        for item in retrieval[section].as_array().into_iter().flatten() {
            items.push(item);
            if items.len() >= limit {
                return items;
            }
        }
    }
    items
}

fn retrieval_item_matches_task(item: &Value, target_kind: &str, query_terms: &[String]) -> bool {
    let kind_matches = match target_kind {
        "document" => {
            item.get("snippet").is_some()
                || item.get("content").is_some()
                || ledger_item_relative_path(item).is_some_and(is_document_like_path)
        }
        "file" => ledger_item_relative_path(item).is_some(),
        "symbol" => item["name"].as_str().is_some(),
        "cross_file_trace" => {
            ledger_item_relative_path(item).is_some() || item["name"].as_str().is_some()
        }
        "evidence_bundle" => {
            ledger_item_relative_path(item).is_some() || item["content"].as_str().is_some()
        }
        _ => true,
    };
    kind_matches && retrieval_item_matches_query(item, query_terms)
}

fn retrieval_item_matches_query(item: &Value, query_terms: &[String]) -> bool {
    if query_terms.is_empty() {
        return false;
    }
    let mut haystacks = Vec::new();
    if let Some(value) = ledger_item_relative_path(item) {
        haystacks.push(value.to_lowercase());
    }
    if let Some(value) = item["name"].as_str() {
        haystacks.push(value.to_lowercase());
    }
    if let Some(value) = item["snippet"].as_str() {
        haystacks.push(value.to_lowercase());
    }
    if let Some(value) = item["content"].as_str() {
        haystacks.push(value.to_lowercase());
    }
    haystacks
        .into_iter()
        .any(|haystack| query_terms.iter().any(|term| haystack.contains(term)))
}

fn is_document_like_path(path: &str) -> bool {
    let lowered = path.to_lowercase();
    lowered.ends_with(".md")
        || lowered.ends_with(".txt")
        || lowered.contains("readme")
        || lowered.contains("docs/")
        || lowered.contains("guide")
}

fn count_lexical_fallback_chunks(payload: &Value) -> usize {
    payload["retrieval"]["semantic_chunks"]
        .as_array()
        .into_iter()
        .flatten()
        .filter(|chunk| chunk["retrieval_strategy"].as_str() == Some("lexical_fallback"))
        .count()
}

fn count_sources(payload: &Value) -> usize {
    let retrieval = &payload["retrieval"];
    retrieval["exact_documents"].as_array().map_or(0, Vec::len)
        + retrieval["symbol_hits"].as_array().map_or(0, Vec::len)
        + retrieval["lexical_chunks"].as_array().map_or(0, Vec::len)
        + retrieval["semantic_chunks"].as_array().map_or(0, Vec::len)
}

fn unique_file_hit_count(payload: &Value) -> usize {
    let mut files = HashSet::new();
    for section in [
        "exact_documents",
        "symbol_hits",
        "lexical_chunks",
        "semantic_chunks",
    ] {
        for item in payload["retrieval"][section]
            .as_array()
            .into_iter()
            .flatten()
        {
            let project_code = item["project_code"]
                .as_str()
                .or_else(|| item["provenance"]["source_project"].as_str())
                .unwrap_or_default();
            let relative_path = item["relative_path"]
                .as_str()
                .or_else(|| item["provenance"]["path"].as_str())
                .unwrap_or_default();
            if !project_code.is_empty() || !relative_path.is_empty() {
                files.insert(format!("{project_code}::{relative_path}"));
            }
        }
    }
    files.len()
}

fn count_chunks(payload: &Value) -> usize {
    let retrieval = &payload["retrieval"];
    retrieval["lexical_chunks"].as_array().map_or(0, Vec::len)
        + retrieval["semantic_chunks"].as_array().map_or(0, Vec::len)
}

fn current_epoch_ms() -> Result<i64> {
    Ok(SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .context("system clock before unix epoch")?
        .as_millis() as i64)
}

fn total_latency_ms(payload: &Value) -> f64 {
    let runtime = &payload["retrieval_runtime"];
    if let Some(value) = runtime["total_ms"].as_f64() {
        return value;
    }
    [
        "resolve_scope_ms",
        "cache_lookup_ms",
        "exact_lookup_ms",
        "symbol_lookup_ms",
        "lexical_lookup_ms",
        "query_embed_ms",
        "semantic_search_ms",
        "semantic_hydrate_ms",
        "serialize_ms",
        "persist_ms",
    ]
    .iter()
    .map(|key| runtime[*key].as_f64().unwrap_or(0.0))
    .sum()
}

fn percent_from_signed(saved_tokens: i64, baseline_tokens: u64) -> f64 {
    if baseline_tokens == 0 {
        0.0
    } else {
        saved_tokens as f64 * 100.0 / baseline_tokens as f64
    }
}

fn hex_sha256(bytes: &[u8]) -> String {
    let mut hasher = Sha256::new();
    hasher.update(bytes);
    hex::encode(hasher.finalize())
}

fn collect_naive_scope(
    payload: &Value,
    limit_files: usize,
    max_bytes_per_file: usize,
    baseline_strategy: &str,
    query: &str,
) -> Result<NaiveScope> {
    let mut files = Vec::new();
    let strategy_files =
        collect_payload_scope_files_by_strategy(payload, baseline_strategy, limit_files)?;
    if !strategy_files.is_empty() {
        for (project_code, repo_root, path) in strategy_files {
            files.push(read_scope_file(
                &project_code,
                &repo_root,
                &path,
                max_bytes_per_file,
            )?);
        }
    } else {
        for project in payload["visible_projects"].as_array().into_iter().flatten() {
            let Some(project_code) = project["project_code"].as_str() else {
                continue;
            };
            let Some(repo_root) = project["repo_root"].as_str() else {
                continue;
            };
            for path in collect_scope_files_by_strategy(
                Path::new(repo_root),
                query,
                baseline_strategy,
                limit_files,
                max_bytes_per_file.min(16 * 1024),
            )? {
                files.push(read_scope_file(
                    project_code,
                    Path::new(repo_root),
                    &path,
                    max_bytes_per_file,
                )?);
            }
        }
    }

    files.sort_by(|left, right| {
        left.project_code
            .cmp(&right.project_code)
            .then_with(|| left.relative_path.cmp(&right.relative_path))
    });
    if limit_files > 0 {
        files.truncate(limit_files);
    }

    let metadata = files
        .iter()
        .map(|file| {
            json!({
                "project_code": file.project_code,
                "relative_path": file.relative_path,
                "original_bytes": file.original_bytes,
                "bytes_used": file.bytes_used,
                "truncated": file.truncated,
            })
        })
        .collect();

    Ok(NaiveScope {
        files: metadata,
        rendered_files: files,
    })
}

fn read_scope_file(
    project_code: &str,
    repo_root: &Path,
    path: &Path,
    max_bytes_per_file: usize,
) -> Result<NaiveScopeFile> {
    let relative_path = path
        .strip_prefix(repo_root)
        .unwrap_or(path)
        .display()
        .to_string();
    let bytes = fs::read(path)
        .with_context(|| format!("failed to read naive scope file {}", path.display()))?;
    let original_bytes = bytes.len();
    let bytes_used = original_bytes.min(max_bytes_per_file);
    let content = safe_lossy_prefix(&bytes, bytes_used);
    Ok(NaiveScopeFile {
        project_code: project_code.to_string(),
        relative_path,
        original_bytes,
        bytes_used: content.len(),
        truncated: original_bytes > content.len(),
        content,
    })
}

fn collect_payload_scope_files_by_strategy(
    payload: &Value,
    baseline_strategy: &str,
    limit_files: usize,
) -> Result<Vec<(String, PathBuf, PathBuf)>> {
    let sections: &[&str] = match baseline_strategy {
        "ide_search_top_files" => &["exact_documents", "symbol_hits", "lexical_chunks"],
        "semantic_top_k" => &["semantic_chunks"],
        _ => return Ok(Vec::new()),
    };
    let repo_roots = payload["visible_projects"]
        .as_array()
        .into_iter()
        .flatten()
        .filter_map(|project| {
            Some((
                project["project_code"].as_str()?.to_string(),
                PathBuf::from(project["repo_root"].as_str()?),
            ))
        })
        .collect::<BTreeMap<_, _>>();
    let mut seen = BTreeSet::new();
    let mut files = Vec::new();
    for section in sections {
        for item in payload["retrieval"][section]
            .as_array()
            .into_iter()
            .flatten()
        {
            let Some(project_code) = ledger_item_project_code(item) else {
                continue;
            };
            let Some(relative_path) = ledger_item_relative_path(item) else {
                continue;
            };
            let Some(repo_root) = repo_roots.get(project_code) else {
                continue;
            };
            let path = repo_root.join(relative_path);
            if !path.is_file() {
                continue;
            }
            if seen.insert(format!("{project_code}::{relative_path}")) {
                files.push((project_code.to_string(), repo_root.clone(), path));
            }
        }
    }
    if limit_files > 0 {
        files.truncate(limit_files);
    }
    Ok(files)
}

fn collect_scope_files_by_strategy(
    root: &Path,
    query: &str,
    baseline_strategy: &str,
    limit_files: usize,
    score_bytes_per_file: usize,
) -> Result<Vec<PathBuf>> {
    match baseline_strategy {
        "grep_top_files" => {
            collect_grep_scope_files(root, query, limit_files, score_bytes_per_file)
        }
        "legacy_pre_amai" => {
            collect_legacy_scope_files(root, query, limit_files, score_bytes_per_file)
        }
        _ => collect_scope_files(root, limit_files),
    }
}

fn collect_scope_files(root: &Path, limit_files: usize) -> Result<Vec<PathBuf>> {
    if !root.exists() {
        bail!("visible project root does not exist: {}", root.display());
    }
    let mut builder = WalkBuilder::new(root);
    builder
        .standard_filters(true)
        .hidden(false)
        .git_ignore(true)
        .git_exclude(true)
        .git_global(true);
    let mut files = builder
        .build()
        .filter_map(Result::ok)
        .filter(|entry| {
            entry
                .file_type()
                .map(|kind| kind.is_file())
                .unwrap_or(false)
        })
        .map(|entry| entry.into_path())
        .filter(|path| language::detect(path).is_some())
        .collect::<Vec<_>>();
    files.sort();
    if limit_files > 0 {
        files.truncate(limit_files);
    }
    Ok(files)
}

fn collect_grep_scope_files(
    root: &Path,
    query: &str,
    limit_files: usize,
    score_bytes_per_file: usize,
) -> Result<Vec<PathBuf>> {
    let files = collect_scope_files(root, 0)?;
    let terms = extract_query_terms(query);
    if terms.is_empty() {
        return collect_scope_files(root, limit_files);
    }

    let mut scored = Vec::new();
    for path in files {
        let relative = path
            .strip_prefix(root)
            .unwrap_or(path.as_path())
            .display()
            .to_string()
            .to_lowercase();
        let mut score = text_match_score(&relative, &terms) * 8;

        let bytes = fs::read(&path)
            .with_context(|| format!("failed to read grep scope file {}", path.display()))?;
        let content = safe_lossy_prefix(&bytes, score_bytes_per_file).to_lowercase();
        score += text_match_score(&content, &terms);

        if score > 0 {
            scored.push((score, path));
        }
    }

    if scored.is_empty() {
        return collect_scope_files(root, limit_files);
    }

    scored.sort_by(|left, right| right.0.cmp(&left.0).then_with(|| left.1.cmp(&right.1)));
    let mut files = scored.into_iter().map(|(_, path)| path).collect::<Vec<_>>();
    if limit_files > 0 {
        files.truncate(limit_files);
    }
    Ok(files)
}

fn collect_legacy_scope_files(
    root: &Path,
    query: &str,
    limit_files: usize,
    score_bytes_per_file: usize,
) -> Result<Vec<PathBuf>> {
    let files = collect_scope_files(root, 0)?;
    let terms = extract_query_terms(query);
    let mut scored = Vec::new();
    for path in files {
        let relative = path
            .strip_prefix(root)
            .unwrap_or(path.as_path())
            .display()
            .to_string()
            .to_lowercase();
        let docs_bias = if relative.contains("readme")
            || relative.contains("docs/")
            || relative.contains("guide")
            || relative.contains("install")
            || relative.contains("setup")
        {
            12
        } else {
            0
        };
        let mut score = docs_bias + text_match_score(&relative, &terms) * 6;
        let bytes = fs::read(&path)
            .with_context(|| format!("failed to read legacy scope file {}", path.display()))?;
        let content = safe_lossy_prefix(&bytes, score_bytes_per_file).to_lowercase();
        score += text_match_score(&content, &terms);
        if score > 0 {
            scored.push((score, path));
        }
    }
    if scored.is_empty() {
        return collect_scope_files(root, limit_files);
    }
    scored.sort_by(|left, right| right.0.cmp(&left.0).then_with(|| left.1.cmp(&right.1)));
    let mut files = scored.into_iter().map(|(_, path)| path).collect::<Vec<_>>();
    if limit_files > 0 {
        files.truncate(limit_files);
    }
    Ok(files)
}

fn ledger_item_project_code(item: &Value) -> Option<&str> {
    item["project_code"]
        .as_str()
        .or_else(|| item["provenance"]["source_project"].as_str())
}

fn ledger_item_relative_path(item: &Value) -> Option<&str> {
    item["relative_path"]
        .as_str()
        .or_else(|| item["provenance"]["path"].as_str())
}

fn extract_query_terms(query: &str) -> Vec<String> {
    let mut terms = query
        .to_lowercase()
        .split(|ch: char| !ch.is_alphanumeric() && ch != '_' && ch != '.')
        .filter(|term| term.len() >= 3)
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    terms.sort();
    terms.dedup();
    terms
}

fn text_match_score(haystack: &str, terms: &[String]) -> usize {
    terms
        .iter()
        .map(|term| haystack.match_indices(term).count())
        .sum()
}

fn safe_lossy_prefix(bytes: &[u8], max_bytes: usize) -> String {
    let slice = &bytes[..bytes.len().min(max_bytes)];
    String::from_utf8_lossy(slice).into_owned()
}

fn render_naive_scope_prompt(payload: &Value, scope: &NaiveScope) -> String {
    let mut prompt = String::new();
    prompt.push_str("NAIVE_SCOPE\n");
    prompt.push_str(
        "This bundle represents the visible project scope without retrieval reduction.\n",
    );
    prompt.push_str("Query: ");
    prompt.push_str(payload["query"].as_str().unwrap_or_default());
    prompt.push_str("\nVisible projects:\n");
    for project in payload["visible_projects"].as_array().into_iter().flatten() {
        prompt.push_str("- ");
        prompt.push_str(project["project_code"].as_str().unwrap_or_default());
        prompt.push_str(" :: ");
        prompt.push_str(project["repo_root"].as_str().unwrap_or_default());
        prompt.push('\n');
    }
    prompt.push('\n');
    for file in &scope.rendered_files {
        prompt.push_str("## PROJECT ");
        prompt.push_str(&file.project_code);
        prompt.push('\n');
        prompt.push_str("### FILE ");
        prompt.push_str(&file.relative_path);
        prompt.push('\n');
        prompt.push_str(&file.content);
        prompt.push_str("\n\n");
    }
    prompt
}

pub(crate) fn render_context_pack_prompt(payload: &Value) -> String {
    if payload["cache_reuse_reference"]["state"].as_str() == Some("same_thread_context_pack_replay")
    {
        return render_same_thread_cache_reuse_prompt(payload);
    }
    let mut excerpt_paths = HashSet::new();
    let mut exact_lines = Vec::new();
    let mut symbol_lines = Vec::new();
    let mut seen_symbols = HashSet::new();
    for item in payload["retrieval"]["symbol_hits"]
        .as_array()
        .into_iter()
        .flatten()
    {
        let line = format!(
            "[{}] {} :: {} :: {}",
            item["provenance"]["source_project"]
                .as_str()
                .unwrap_or_default(),
            item["relative_path"].as_str().unwrap_or_default(),
            item["name"].as_str().unwrap_or_default(),
            item["kind"].as_str().unwrap_or_default(),
        );
        if seen_symbols.insert(line.clone()) {
            symbol_lines.push(line);
        }
    }

    let mut excerpt_lines = Vec::new();
    let mut seen_excerpts = HashSet::new();
    for section in ["lexical_chunks", "semantic_chunks"] {
        for item in payload["retrieval"][section]
            .as_array()
            .into_iter()
            .flatten()
        {
            let line = format!(
                "[{}] {} :: {}",
                item["provenance"]["source_project"]
                    .as_str()
                    .or_else(|| item["project_code"].as_str())
                    .unwrap_or_default(),
                item["relative_path"].as_str().unwrap_or_default(),
                item["content"].as_str().unwrap_or_default(),
            );
            if seen_excerpts.insert(line.clone()) {
                excerpt_lines.push(line);
            }
            excerpt_paths.insert(format!(
                "{}::{}",
                item["provenance"]["source_project"]
                    .as_str()
                    .or_else(|| item["project_code"].as_str())
                    .unwrap_or_default(),
                item["relative_path"].as_str().unwrap_or_default()
            ));
        }
    }

    let mut seen_exact = HashSet::new();
    for item in payload["retrieval"]["exact_documents"]
        .as_array()
        .into_iter()
        .flatten()
    {
        let key = format!(
            "{}::{}",
            item["project_code"].as_str().unwrap_or_default(),
            item["relative_path"].as_str().unwrap_or_default()
        );
        if excerpt_paths.contains(&key) {
            continue;
        }
        let line = format!(
            "[{}] {} {}",
            item["project_code"].as_str().unwrap_or_default(),
            item["relative_path"].as_str().unwrap_or_default(),
            item["snippet"].as_str().unwrap_or_default(),
        );
        if seen_exact.insert(line.clone()) {
            exact_lines.push(line);
        }
    }

    let mut prompt = String::new();
    prompt.push_str("Q:");
    prompt.push_str(payload["query"].as_str().unwrap_or_default());
    prompt.push('\n');
    prompt.push_str("M:");
    prompt.push_str(
        payload["effective_retrieval_mode"]
            .as_str()
            .unwrap_or_default(),
    );
    prompt.push('\n');
    prompt.push_str("P\n");
    for project in payload["visible_projects"].as_array().into_iter().flatten() {
        prompt.push('[');
        prompt.push_str(project["project_code"].as_str().unwrap_or_default());
        prompt.push_str("] ");
        prompt.push_str(project["repo_root"].as_str().unwrap_or_default());
        prompt.push('\n');
    }
    prompt.push('\n');
    push_compact_lines(&mut prompt, "D", &exact_lines);
    push_compact_lines(&mut prompt, "S", &symbol_lines);
    push_compact_lines(&mut prompt, "E", &excerpt_lines);
    prompt
}

fn render_same_thread_cache_reuse_prompt(payload: &Value) -> String {
    let mut prompt = String::new();
    let mut reuse_lines = Vec::new();
    if let Some(context_pack_id) = payload["cache_reuse_reference"]["source_context_pack_id"]
        .as_str()
        .filter(|value| !value.is_empty())
    {
        reuse_lines.push(format!("ctx={context_pack_id}"));
    }
    let counts = &payload["cache_reuse_reference"]["retrieval_counts"];
    reuse_lines.push(format!(
        "counts docs={} symbols={} lexical={} semantic={}",
        counts["exact_documents"].as_u64().unwrap_or(0),
        counts["symbol_hits"].as_u64().unwrap_or(0),
        counts["lexical_chunks"].as_u64().unwrap_or(0),
        counts["semantic_chunks"].as_u64().unwrap_or(0),
    ));
    for path in payload["cache_reuse_reference"]["active_files"]
        .as_array()
        .into_iter()
        .flatten()
        .filter_map(|value| value.as_str())
        .take(6)
    {
        reuse_lines.push(format!("file={path}"));
    }
    reuse_lines.push("reuse=prior_full_payload_same_thread".to_string());
    push_compact_lines(&mut prompt, "R", &reuse_lines);
    prompt
}

fn push_compact_lines(prompt: &mut String, title: &str, lines: &[String]) {
    prompt.push_str(title);
    prompt.push('\n');
    for line in lines {
        prompt.push_str(line);
        prompt.push('\n');
    }
    prompt.push('\n');
}

fn build_tokenizer(name: &str) -> Result<CoreBPE> {
    match name {
        "o200k_base" => o200k_base().context("failed to initialize o200k_base tokenizer"),
        "cl100k_base" => cl100k_base().context("failed to initialize cl100k_base tokenizer"),
        other => Err(anyhow!("unsupported tokenizer: {other}")),
    }
}

